-- Poems batch 233
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('1174b2c4-0e80-44ab-acf7-3d5c3e42efc0','偈頌一百二十三首  其二一','釋普度','宋','宋诗','song-poetry','','[]','千說萬說，不如親見。',47,'全唐诗/poet.song.213000.json','["千說萬說，不如親見。", "有時怒濤衮底，有時水清月現。", "風颼颼冷啾啾，雖然舊閣閑田地，一度贏來方始休。"]'),
('645b57f1-f220-4a78-9a4b-6299d7801cac','偈頌一百二十三首  其二二','釋普度','宋','宋诗','song-poetry','','[]','月冷天高，風號怒濤。',58,'全唐诗/poet.song.213000.json','["月冷天高，風號怒濤。", "提殺人劍，用活人刀。", "雲淡淡寒江鴈影，山渺渺落日危巢。", "見成題目，眨上眉毛。", "萬機頓罷歸來，也是徒勞。"]'),
('17a806e2-8814-414c-97bb-27c2c71347a3','偈頌一百二十三首  其二三','釋普度','宋','宋诗','song-poetry','','[]','群陰剝盡，一陽來復。',48,'全唐诗/poet.song.213000.json','["群陰剝盡，一陽來復。", "鐵樹花開，清香馥郁。", "眼皮開未開，枝南復枝北。", "凹凹凸凸破沙盆，何似鎮州大蘿蔔。"]'),
('57082776-a898-4930-8390-30bfccebb8fd','偈頌一百二十三首  其二四','釋普度','宋','宋诗','song-poetry','','[]','清明寒食節，韶光爛漫時。',40,'全唐诗/poet.song.213000.json','["清明寒食節，韶光爛漫時。", "野花迷古逕，回首暮雲低。", "紙錢飛處杜鵑啼，不是苦心人不知。"]'),
('13c93850-f517-42d1-a598-6de74c744c6e','偈頌一百二十三首  其二五','釋普度','宋','宋诗','song-poetry','','[]','說得一丈，不如行得一尺。',36,'全唐诗/poet.song.213000.json','["說得一丈，不如行得一尺。", "行得一尺，不如離却一寸。", "山高分水深，青天分白日。"]'),
('24b89338-fdfc-4dc9-b0ea-6673d8f00f97','偈頌一百二十三首  其二六','釋普度','宋','宋诗','song-poetry','','[]','玉鑑光中，波澄月現。',62,'全唐诗/poet.song.213000.json','["玉鑑光中，波澄月現。", "展屠龍手，提金剛劍。", "栗棘金圈一拶開，從君細嚼渾崙嚥。", "有照有用，有舒有卷。", "楊岐消息未全灰，優曇華笑春風面。"]'),
('2298725a-45a6-437c-ab40-23079aeb4531','偈頌一百二十三首  其二七','釋普度','宋','宋诗','song-poetry','','[]','年年是好年，日日是好日。',61,'全唐诗/poet.song.213000.json','["年年是好年，日日是好日。", "新年人看舊年人，舊年日是新年日。", "潮生漲舊痕，潮落石頭出。", "萬物有遷流，遷流無變易。", "有變易，上上大吉。"]'),
('5c353fb8-a576-469e-ab80-ea1d39a94630','偈頌一百二十三首  其二八','釋普度','宋','宋诗','song-poetry','','[]','釋迦老子弄精魂，死了依前似不曾。',32,'全唐诗/poet.song.213000.json','["釋迦老子弄精魂，死了依前似不曾。", "一樹落花春過後，遠山無限碧層層。"]'),
('65b91b85-221a-4dfa-b440-bf25667b2837','偈頌一百二十三首  其二九','釋普度','宋','宋诗','song-poetry','','[]','圓同太虛，無欠無餘。',20,'全唐诗/poet.song.213000.json','["圓同太虛，無欠無餘。", "良由取捨，所以不如。"]'),
('d96c07a9-50d9-4e08-aabd-581cd5b5d309','偈頌一百二十三首  其三○','釋普度','宋','宋诗','song-poetry','','[]','一夜江風攪玉塵，孤峰不白轉精神。',32,'全唐诗/poet.song.213000.json','["一夜江風攪玉塵，孤峰不白轉精神。", "從空放下從空看，徹骨寒來有幾人。"]'),
('8f31f73f-6f9b-407d-8b6a-2e16380b1ae6','偈頌一百二十三首  其三一','釋普度','宋','宋诗','song-poetry','','[]','南北東西幾路頭，來來同載一扁舟。',32,'全唐诗/poet.song.213000.json','["南北東西幾路頭，來來同載一扁舟。", "月明夜靜滄浪裡，一掣錦鱗隨直鈎。"]'),
('7d9af990-f5a6-4ae5-b1bc-2b47245cc5c8','偈頌一百二十三首  其三二','釋普度','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','智不到處，不妨道著。',80,'全唐诗/poet.song.213000.json','["智不到處，不妨道著。", "吸盡長江，衝開碧落。", "的的金圈栗棘，一一天花乳酪。", "楊岐消息儼然存，大用機前活卓卓。", "山僧合掌有分，諸人如何啗啄。", "玉鑑光中宇宙寬，雙雙放出遼天鶻。"]'),
('0a0af27d-b363-4397-bcfb-d6bba2812e7c','偈頌一百二十三首  其三三','釋普度','宋','宋诗','song-poetry','','[]','山之高，水之深，非古亦非今。',30,'全唐诗/poet.song.213000.json','["山之高，水之深，非古亦非今。", "老胡打失一隻履，葱嶺那邊無處尋。"]'),
('387d78ce-85e6-4b1e-b740-c942db0f20bc','偈頌一百二十三首  其三四','釋普度','宋','宋诗','song-poetry','','[]','風號寒，霜凜冽。',54,'全唐诗/poet.song.213000.json','["風號寒，霜凜冽。", "屋浪崩騰，飛銀撒雪。", "截流過者，未稱全提。", "作死馬醫，暖氣相接。", "倒腹傾腸一線通，月明不借蘆花白。"]'),
('a026f8a3-fb30-465b-a58c-539427ef8fb5','偈頌一百二十三首  其三五','釋普度','宋','宋诗','song-poetry','','[]','長長出不得，短短出不得。',64,'全唐诗/poet.song.213000.json','["長長出不得，短短出不得。", "四大海不寬，藕絲竅不窄。", "非耳目之所到，非心意之所及。", "自西自東，自南自北。", "落霞與孤鶩齊飛，秋水共長天一色。"]'),
('95cf0d03-9053-48dc-9c86-0953ba412d8d','偈頌一百二十三首  其三六','釋普度','宋','宋诗','song-poetry','','[]','烹佛煉祖，鍛聖鎔凡。',28,'全唐诗/poet.song.213000.json','["烹佛煉祖，鍛聖鎔凡。", "殺活在手，寶劍光寒。", "意在星兮不在盤。"]'),
('116fd954-7659-4402-9b23-4919aca534d7','偈頌一百二十三首  其三七','釋普度','宋','宋诗','song-poetry','','[]','古鏡無光，當臺自照。',76,'全唐诗/poet.song.213000.json','["古鏡無光，當臺自照。", "森羅絕影，覿面難逃。", "行不言之令，坐致太平。", "贊無爲之化，六國晏清。", "天高地厚，水綠山青。", "山青青，水泠泠。", "湘西古渡夕陽明，岳足當簷開畫屏。"]'),
('4bdaa632-37ac-4466-b917-41d681361889','偈頌一百二十三首  其三八','釋普度','宋','宋诗','song-poetry','','[]','李白桃紅，桃紅李白。',20,'全唐诗/poet.song.213000.json','["李白桃紅，桃紅李白。", "或雨或晴，或寒或熱。"]'),
('51a476a8-b61b-4746-9957-2d5006aed915','偈頌一百二十三首  其三九','釋普度','宋','宋诗','song-poetry','','[]','白雲高，灘水急。',18,'全唐诗/poet.song.213000.json','["白雲高，灘水急。", "不動脚頭，全身直入。"]'),
('5a0fae8b-c5e3-49e7-a8e2-c5ba927b5e47','偈頌一百二十三首  其四○','釋普度','宋','宋诗','song-poetry','','[]','花簇簇，錦簇簇。',24,'全唐诗/poet.song.213000.json','["花簇簇，錦簇簇。", "吟不足，詠不足。", "的的無絃琴上曲。"]'),
('e8ce8b7f-7280-43f4-bcf1-3123f06afcaa','偈頌一百二十三首  其四一','釋普度','宋','宋诗','song-poetry','','[]','大機圓應，大智無方。',92,'全唐诗/poet.song.213000.json','["大機圓應，大智無方。", "右左逢原，七穿八穴。", "萬疊雲山一抹過，十八灘頭聲浩浩。", "遇貴即貴，遇賤即賤。", "法隨法行，法幢隨處建立。", "要津把斷，縱奪臨時。", "風細細，日遲遲。", "四海浪平龍睡穩，九天雲浄鶴高飛。"]'),
('0840bc55-c990-4748-bb47-5efe04c7cf2d','偈頌一百二十三首  其四二','釋普度','宋','宋诗','song-poetry','','[]','春風卷春雨，春樹生春烟。',48,'全唐诗/poet.song.213000.json','["春風卷春雨，春樹生春烟。", "作家相見不談禪。", "天寒燒榾柮，雲外煮清泉。", "更有一般風味在，從來附子出西川。"]'),
('53c30aaf-6561-4245-8914-0d0004cfae14','偈頌一百二十三首  其四三','釋普度','宋','宋诗','song-poetry','','[]','西風蕭蕭急未急，塞鴈聲聲寒未寒。',32,'全唐诗/poet.song.213000.json','["西風蕭蕭急未急，塞鴈聲聲寒未寒。", "欲對黄花問時節，有誰同倚玉欄干。"]'),
('236a954e-9c13-4a9c-9ab0-35c40b7bad3e','偈頌一百二十三首  其四四','釋普度','宋','宋诗','song-poetry','','[]','階前黄葉兩三片，門外白雲千萬重。',32,'全唐诗/poet.song.213000.json','["階前黄葉兩三片，門外白雲千萬重。", "寄語善財休斫額，德雲不在妙高峰。"]'),
('7706e515-a86d-495a-b62f-8db0537f886f','偈頌一百二十三首  其四五','釋普度','宋','宋诗','song-poetry','','[]','麻三斤，乾屎橛。',20,'全唐诗/poet.song.213000.json','["麻三斤，乾屎橛。", "不是五逆漢，此話憑誰說。"]'),
('52a561da-2aea-42e6-b15f-e9ead77b244c','偈頌一百二十三首  其四六','釋普度','宋','宋诗','song-poetry','','[]','開口即錯，閉口即啞。',28,'全唐诗/poet.song.213000.json','["開口即錯，閉口即啞。", "釘嘴鐵舌，一時列下。", "碧玉盤，無縫罅。"]'),
('9d903de9-467f-40dc-9ef7-b7e315acdc39','偈頌一百二十三首  其四七','釋普度','宋','宋诗','song-poetry','','[]','筆頭有眼主中主，號令無私公至公。',32,'全唐诗/poet.song.213000.json','["筆頭有眼主中主，號令無私公至公。", "妙用當機全殺活，一新佛祖舊家風。"]'),
('fcec0151-1ed3-4970-a544-020c26a758d8','偈頌一百二十三首  其四八','釋普度','宋','宋诗','song-poetry','','[]','來何遲，去何速，十七日緣今已足。',32,'全唐诗/poet.song.213000.json','["來何遲，去何速，十七日緣今已足。", "拄杖橫擔歸去來，一笑出門山水綠。"]'),
('a07bcb9f-3b51-450f-9955-bdf3d3cec8cf','偈頌一百二十三首  其四九','釋普度','宋','宋诗','song-poetry','','[]','樓閣門開，了無回互。',21,'全唐诗/poet.song.213000.json','["樓閣門開，了無回互。", "既是家裡人，便請直入。"]'),
('bd6463b8-9f82-4460-8d47-d5eb9a7a657b','偈頌一百二十三首  其五○','釋普度','宋','宋诗','song-poetry','','[]','面皮上刮得霜，枯骨裡敲出髓。',27,'全唐诗/poet.song.213000.json','["面皮上刮得霜，枯骨裡敲出髓。", "轉得身，吐得氣。", "不是不是。"]'),
('11fa0789-ee25-42f1-b68f-ddd3cb879e74','偈頌一百二十三首  其五一','釋普度','宋','宋诗','song-poetry','','[]','寶塔層層面面開，當機一拶語如雷。',32,'全唐诗/poet.song.213000.json','["寶塔層層面面開，當機一拶語如雷。", "信知恩大難酬處，一段風光遍九垓。"]'),
('f391f8e4-84dc-4ef9-b1cc-e1c18e079b49','偈頌一百二十三首  其五二','釋普度','宋','宋诗','song-poetry','','[]','天書頒自九重來，萬壑煙雲盡豁開。',32,'全唐诗/poet.song.213000.json','["天書頒自九重來，萬壑煙雲盡豁開。", "竺土大仙燈燦爛，融融和氣靄樓臺。"]'),
('a1e0fd16-22a8-4d0a-94d0-ada570108765','偈頌一百二十三首  其五三','釋普度','宋','宋诗','song-poetry','','[]','落葉辭柯滿竹扉。',39,'全唐诗/poet.song.213000.json','["落葉辭柯滿竹扉。", "道道，何處尋。", "今即古，古即今。", "曹溪波浪如相似，無限平人被陸沈。"]'),
('9f617af9-0038-44b2-adb8-0c94709a389d','偈頌一百二十三首  其五四','釋普度','宋','宋诗','song-poetry','','[]','長一線，一線長。',34,'全唐诗/poet.song.213000.json','["長一線，一線長。", "眼聞耳見，不用商量。", "流水斷橋梅破萼，枝南枝北一般春。"]'),
('c3023dce-47d5-4c62-b1b2-2c50804a7534','偈頌一百二十三首  其五五','釋普度','宋','宋诗','song-poetry','','[]','妙德巖中宴坐時，釋梵天王同讚喜。',55,'全唐诗/poet.song.213000.json','["妙德巖中宴坐時，釋梵天王同讚喜。", "地摇六振雨花飛，一聲霹靂清飈起。", "滄海頭，青海尾。", "楊岐毒，種靈苗，殃害兒孫未已。"]'),
('6d26145b-b08c-4e34-b665-02db0226d5bd','偈頌一百二十三首  其五六','釋普度','宋','宋诗','song-poetry','','[]','手指天，脚踏地。',32,'全唐诗/poet.song.213000.json','["手指天，脚踏地。", "目顧四方，真少兒戲。", "自言惟我獨尊，天上人間誹誹。"]'),
('a10138d8-7a17-4474-a9d0-0b8c0cd65f3e','偈頌一百二十三首  其五七','釋普度','宋','宋诗','song-poetry','','[]','正法眼，破沙盆。',32,'全唐诗/poet.song.213000.json','["正法眼，破沙盆。", "零敲碎打，不直分文。", "一一銀山鐵壁，一一電掣雷奔。"]'),
('2a488f58-50c5-43c4-a6fc-a903b71ef341','偈頌一百二十三首  其五八','釋普度','宋','宋诗','song-poetry','','[]','正覺山前，明星皎皎。',47,'全唐诗/poet.song.213000.json','["正覺山前，明星皎皎。", "夜半打失鼻孔，將謂一了便了。", "中竺看來，有些短處，不說也好。", "開得眼來天大嘵。"]'),
('8c04d065-a078-4e2b-8b9f-d262eee54719','偈頌一百二十三首  其五九','釋普度','宋','宋诗','song-poetry','','[]','當初已是錯投胎，鬼面神頭相賺來。',32,'全唐诗/poet.song.213000.json','["當初已是錯投胎，鬼面神頭相賺來。", "裂破虛空無罅縫，龜毛拂子舞三臺。"]'),
('6f4e99d8-5141-4ca2-8395-9eb8c6e0b520','偈頌一百二十三首  其六○','釋普度','宋','宋诗','song-poetry','','[]','垂垂白髮老成魔，異類中行罪過多。',32,'全唐诗/poet.song.213000.json','["垂垂白髮老成魔，異類中行罪過多。", "業債既深償未足，又拖犂杷出煙蘿。"]'),
('826ad183-bebf-49ef-b383-3d7c730795a8','偈頌一百二十三首  其六一','釋普度','宋','宋诗','song-poetry','','[]','德合乾坤御九天，祥光瑞氣靄山川。',32,'全唐诗/poet.song.213000.json','["德合乾坤御九天，祥光瑞氣靄山川。", "當機覿面全提處，一會靈山又儼然。"]'),
('0c637864-c64f-46cf-a82b-25f71025cec1','偈頌一百二十三首  其六二','釋普度','宋','宋诗','song-poetry','','[]','心王不妄動，六國一時通。',24,'全唐诗/poet.song.213000.json','["心王不妄動，六國一時通。", "罷拈三尺劍，休弄一張弓。"]'),
('f8feaef2-f867-4666-8893-a93bea1b9abe','偈頌一百二十三首  其六三','釋普度','宋','宋诗','song-poetry','','[]','虎巖巖下虎，咬人齒不露。',58,'全唐诗/poet.song.213000.json','["虎巖巖下虎，咬人齒不露。", "踞地坐眈眈，南北無行路。", "翻身一擲更無蹤，虛空拍掌須彌舞。", "萬象森羅，一時痛苦。", "石人木人淚如雨。"]'),
('f2a5a1ab-6e05-4484-908c-4337730322e8','偈頌一百二十三首  其六四','釋普度','宋','宋诗','song-poetry','','[]','兔馬有角，牛羊無角。',32,'全唐诗/poet.song.213000.json','["兔馬有角，牛羊無角。", "寸毫尺釐，天地寥廓。", "潘閬倒騎馿，攧殺黄番趠。"]'),
('0e784c41-a894-4eeb-8330-d9992f5b0e5c','偈頌一百二十三首  其六五','釋普度','宋','宋诗','song-poetry','','[]','十五日已前，銀山鐵壁。',44,'全唐诗/poet.song.213000.json','["十五日已前，銀山鐵壁。", "十五日已後，鐵壁銀山。", "正當十五日，一塵不立天地寬，那知更有上頭關。"]'),
('5f22386a-a12a-4a14-9454-72f1117a5b8e','偈頌一百二十三首  其六六','釋普度','宋','宋诗','song-poetry','','[]','祖師門下，討甚巴鼻。',36,'全唐诗/poet.song.213000.json','["祖師門下，討甚巴鼻。", "東行西行，無是不是。", "忽然籬下菊花黄，此時决定是重陽。"]'),
('4a7f12cf-00fb-4caa-a762-6d88ad4939ec','偈頌一百二十三首  其六七','釋普度','宋','宋诗','song-poetry','','[]','布袋頭一結，百城消息絕。',32,'全唐诗/poet.song.213000.json','["布袋頭一結，百城消息絕。", "蠟人冰不冰，萬里一條鐵。", "珊瑚枝枝撐著月。"]'),
('aae64afb-267d-4350-bd23-2db8e1b62db7','偈頌一百二十三首  其六八','釋普度','宋','宋诗','song-poetry','','[]','一期九十日，鐵壁復鐵壁。',40,'全唐诗/poet.song.213000.json','["一期九十日，鐵壁復鐵壁。", "四方八面來，只是跳不出。", "落霞與孤鶩齊飛，秋水共長天一色。"]'),
('71cc6483-d1ea-456d-a4d3-0213366f4f6b','偈頌一百二十三首  其六九','釋普度','宋','宋诗','song-poetry','','[]','短棹輕帆，風恬浪靜。',62,'全唐诗/poet.song.213000.json','["短棹輕帆，風恬浪靜。", "溢目湖光鏡樣平，漁歌未起同誰聽。", "萬壑千巖，高低普應。", "狼藉斷霞殘照中，船頭撥轉都收盡。", "麽朅提國，親行此令。"]'),
('4b66c70f-7142-488f-b7fe-ebbd9078af35','偈頌一百二十三首  其七○','釋普度','宋','宋诗','song-poetry','','[]','八月二十五，洞山離查渡。',40,'全唐诗/poet.song.213000.json','["八月二十五，洞山離查渡。", "咄哉老雲門，多却末後句。", "桃花浪暖禹門高，霹靂一聲燒尾去。"]'),
('95c4af54-ced0-44bb-91ee-028db6a92cd3','偈頌一百二十三首  其七一','釋普度','宋','宋诗','song-poetry','','[]','老瞿曇，眼孔小。',42,'全唐诗/poet.song.213000.json','["老瞿曇，眼孔小。", "一星半星容不得，說迷說悟何時了。", "衲僧分上那有許多般，雪晴海闊千峰曉。"]'),
('2181fa60-0120-4fc6-9b93-bd3617f69800','偈頌一百二十三首  其七二','釋普度','宋','宋诗','song-poetry','','[]','達磨西來，只箇不識。',35,'全唐诗/poet.song.213000.json','["達磨西來，只箇不識。", "鐵壁銀山，挨拶不入。", "因甚分皮分髓，飛來峰高冷泉碧。"]'),
('0304aee0-2650-4189-b8a0-436731bc79c5','偈頌一百二十三首  其七三','釋普度','宋','宋诗','song-poetry','','[]','巍巍獨坐大雄峰，萬水千山列下風。',32,'全唐诗/poet.song.213000.json','["巍巍獨坐大雄峰，萬水千山列下風。", "相見不說奇特事，一聲猿叫翠微中。"]'),
('a1a4e093-5be9-45fb-adc4-0fba36bb0bed','偈頌一百二十三首  其七四','釋普度','宋','宋诗','song-poetry','','[]','不釘桃符，不懸艾虎。',36,'全唐诗/poet.song.213000.json','["不釘桃符，不懸艾虎。", "駕鐵牛機，擊塗毒皷。", "千妖百怪盡潜蹤，靈鷲峰高日卓午。"]'),
('6e1c3661-7f05-4e3a-a553-7ac63e08c8c9','偈頌一百二十三首  其七五','釋普度','宋','宋诗','song-poetry','','[]','大機圓應，大用無方。',42,'全唐诗/poet.song.213000.json','["大機圓應，大用無方。", "撲碎破沙盆，滅却正法眼。", "要津把定，佛祖潜蹤。", "正案傍提，百發百中。"]'),
('c258fca5-0de5-40a4-8e0e-f6e9994f38a8','偈頌一百二十三首  其七六','釋普度','宋','宋诗','song-poetry','','[]','八月九月，不寒不熱。',50,'全唐诗/poet.song.213000.json','["八月九月，不寒不熱。", "盤山擲劍揮空，正是箇般時節。", "無古無今，無間無歇。", "癡雲卷盡雨聲收，千里萬里一條鐵。"]'),
('ec79ded7-1ce1-44b5-a5b5-cbdc3331c9b9','偈頌一百二十三首  其七七','釋普度','宋','宋诗','song-poetry','','[]','露滴滴，風凄凄。',30,'全唐诗/poet.song.213000.json','["露滴滴，風凄凄。", "黄花香滿路，何獨在東籬。", "高低普應，步步相隨。"]'),
('c54c21bc-8a2b-42bf-97d5-ff4c6e9a07ae','偈頌一百二十三首  其七八','釋普度','宋','宋诗','song-poetry','','[]','落葉飄飄，秋江清淺。',28,'全唐诗/poet.song.213000.json','["落葉飄飄，秋江清淺。", "烈士相逢，干戈不展。", "言多去，道轉遠。"]'),
('b907eaaa-86b8-405e-a341-b65b4ea67534','偈頌一百二十三首  其七九','釋普度','宋','宋诗','song-poetry','','[]','普天寒色，大地爲爐。',52,'全唐诗/poet.song.213000.json','["普天寒色，大地爲爐。", "但見清風壁立，不知石爛松枯。", "丹霞燒木佛，因甚院主墮眉鬚。", "若無這些火種，討甚碧眼老胡。"]'),
('1bf76dba-90bc-4165-b749-92d5278ce626','偈頌一百二十三首  其八○','釋普度','宋','宋诗','song-poetry','','[]','海門一夜波濤惡，玉麟攧折黄金角。',41,'全唐诗/poet.song.213000.json','["海門一夜波濤惡，玉麟攧折黄金角。", "魚龍蝦蟹盡潜，大悲千手難摸索。", "木馬悲嘶，石人淚落。"]'),
('4a736c24-ecb7-4693-a37b-b228dad15d60','偈頌一百二十三首  其八一','釋普度','宋','宋诗','song-poetry','','[]','拔地凌霄峰，嵯峨倚寥泬。',46,'全唐诗/poet.song.213000.json','["拔地凌霄峰，嵯峨倚寥泬。", "一夜天風忽吹折，木馬悲嘶，石人哽咽。", "曉來雲散谷風清，千古虛堂照明月。"]'),
('ae8d01b2-f920-4caa-a64e-ed5dca5cf351','偈頌一百二十三首  其八二','釋普度','宋','宋诗','song-poetry','','[]','東湖輥底怒濤，青山參天荆棘。',50,'全唐诗/poet.song.213000.json','["東湖輥底怒濤，青山參天荆棘。", "兩處狹路相逢，拶得渠儂上壁。", "恩難酬，怨難酬，熱煮冷泉流水，濃點淡茶一甌。"]'),
('d8124216-08b0-410b-b9b7-5b049aa9045d','偈頌一百二十三首  其八三','釋普度','宋','宋诗','song-poetry','','[]','有權有實，有照有用，些些鬼眼睛，臨機要活弄。',42,'全唐诗/poet.song.213000.json','["有權有實，有照有用，些些鬼眼睛，臨機要活弄。", "弄得活，沒疏親。", "誰知席帽下，都是舊時人。"]'),
('c20ea659-d89d-41d7-8c5f-f2639c3b5b06','偈頌一百二十三首  其八四','釋普度','宋','宋诗','song-poetry','','[]','聲前一句，斗換星移。',46,'全唐诗/poet.song.213000.json','["聲前一句，斗換星移。", "石火莫及，電光罔追。", "栗棘蓬當面擲，全剛劍信手揮。", "少林消息斷，花綻不萌枝。"]'),
('20b7bf9c-972d-4f29-a30d-af578c18de83','偈頌一百二十三首  其八五','釋普度','宋','宋诗','song-poetry','','[]','一即三，三即一，達磨不曾離少室。',74,'全唐诗/poet.song.213000.json','["一即三，三即一，達磨不曾離少室。", "父子雖親妙不傳，一花五葉成狼藉。", "海風吹起怒濤寒，截流過者脚不濕。", "道在中庸，梅香巖石。", "破沙盆子響玲瓏，要在當人善拋擲。"]'),
('55bf490d-1e69-46d5-b254-367871a59d95','偈頌一百二十三首  其八六','釋普度','宋','宋诗','song-poetry','','[]','文殊雖令善財採藥，佛病祖病，未曾醫著。',37,'全唐诗/poet.song.213000.json','["文殊雖令善財採藥，佛病祖病，未曾醫著。", "靈隠病亦無，藥亦無，趙州東壁掛葫蘆。"]'),
('98c48952-273a-4b5a-9a34-a142500fc479','偈頌一百二十三首  其八七','釋普度','宋','宋诗','song-poetry','','[]','二千年前，毗藍園裏。',50,'全唐诗/poet.song.213000.json','["二千年前，毗藍園裏。", "地動山摇，禍胎忽起。", "雲門瞎棒打不死，後代兒孫空切齒。", "休切齒，杓柄短長，澆潑在你。"]'),
('1e839164-53ef-443e-acd4-f7371c797ba1','偈頌一百二十三首  其八八','釋普度','宋','宋诗','song-poetry','','[]','說禪說道易，成佛作祖難，突出門前大案山。',56,'全唐诗/poet.song.213000.json','["說禪說道易，成佛作祖難，突出門前大案山。", "成佛作祖易，說禪說道難，南海波斯念八還。", "也不難，也不易，衲僧敲處遼天鼻。"]'),
('6d73dd5b-c9f2-4c6c-ae1e-e2dc8e66dc16','偈頌一百二十三首  其八九','釋普度','宋','宋诗','song-poetry','','["\u592a\u6e56"]','昨夜毗嵐撼山岳，七十二峯俱倒卓。',32,'全唐诗/poet.song.213000.json','["昨夜毗嵐撼山岳，七十二峯俱倒卓。", "太湖萬頃涓滴無，黄葉亂飄星斗落。"]'),
('1e1fb93a-5c2b-4e49-be88-82984be5f876','偈頌一百二十三首  其九○','釋普度','宋','宋诗','song-poetry','','[]','開口不是禪，閉口不是道。',48,'全唐诗/poet.song.213000.json','["開口不是禪，閉口不是道。", "只是箇輪槌，拈來用恰好。", "一擊天門開，萬象俱靠倒。", "狹路忽相逢，拍掌呵呵笑。"]'),
('eaf34cc5-b9ea-4b38-8e27-68816b161c5f','偈頌一百二十三首  其九一','釋普度','宋','宋诗','song-poetry','','[]','入荒田，出荒田，信手拈來顆顆圓。',38,'全唐诗/poet.song.213000.json','["入荒田，出荒田，信手拈來顆顆圓。", "橫三千，豎三千。", "雖曰眼底空花，直是明白洞然。"]'),
('f2f29fe6-15f4-49b8-91fb-171ca82f642e','偈頌一百二十三首  其九二','釋普度','宋','宋诗','song-poetry','','[]','巖頭雪嶠與欽山，共轍同途豈等閑。',32,'全唐诗/poet.song.213000.json','["巖頭雪嶠與欽山，共轍同途豈等閑。", "要識南臺真白額，從來虎體一般斑。"]'),
('73ee3715-1599-47f6-a898-e79f80389123','偈頌一百二十三首  其九三','釋普度','宋','宋诗','song-poetry','','[]','妙喜黑竹篦，有背還有觸。',56,'全唐诗/poet.song.213000.json','["妙喜黑竹篦，有背還有觸。", "兒孫用得親，通身是眼目。", "正令全提轉轆轆，花簇簇，錦簇簇。", "直教佛祖亦頭低，宇宙空來更有誰。"]'),
('e2bd1419-da7c-4d57-90c8-4b30700cd57f','偈頌一百二十三首  其九四','釋普度','宋','宋诗','song-poetry','','[]','拘尸那城有生滅，我此世界生滅無。',32,'全唐诗/poet.song.213000.json','["拘尸那城有生滅，我此世界生滅無。", "桃紅李白花時節，是處江山開畫圖。"]'),
('3f94ba19-24f9-41eb-ad37-30d992fe014c','偈頌一百二十三首  其九五','釋普度','宋','宋诗','song-poetry','','[]','用鈯斧子，非重非輕。',20,'全唐诗/poet.song.213000.json','["用鈯斧子，非重非輕。", "拈起放下，肘後符靈。"]'),
('e6fe857f-ad46-499c-abe0-f3e16dcd06b1','偈頌一百二十三首  其九六','釋普度','宋','宋诗','song-poetry','','[]','清明前，寒食後，花雨漫天雲滿岫。',60,'全唐诗/poet.song.213000.json','["清明前，寒食後，花雨漫天雲滿岫。", "誰家小犢力未完，但知逐隊隨群走。", "阿呵呵，索頭只在翁翁手。", "當機一掣掣斷時，野犴便作師子吼。"]'),
('133284cc-5f10-4608-b963-e1af9e1f2709','偈頌一百二十三首  其九七','釋普度','宋','宋诗','song-poetry','','[]','船來也到，陸來也到。',36,'全唐诗/poet.song.213000.json','["船來也到，陸來也到。", "船來陸來，紅日杲杲。", "白雲缺處燒痕青，春在少林元不老。"]'),
('1c4de5bc-85e4-43e8-937a-06d47ae7a206','偈頌一百二十三首  其九八','釋普度','宋','宋诗','song-poetry','','[]','結夏已十日，那事無消息。',36,'全唐诗/poet.song.213000.json','["結夏已十日，那事無消息。", "雲在嶺頭閑，水流何太急。", "法法不隠藏，古今無朕迹。"]'),
('75f3c1e8-0006-4f42-9bc0-ddca71246d78','偈頌一百二十三首  其九九','釋普度','宋','宋诗','song-poetry','','[]','秧入土，麥上場。',69,'全唐诗/poet.song.213000.json','["秧入土，麥上場。", "豐年已兆，比屋盈倉。", "饑來喫飯，熱來乘凉。", "東倒西擂，隨緣遇方。", "更無餘事可商量，夜來却被子規啼斷腸。", "因甚如此，閻羅老子要飯錢。"]'),
('e78cbdc3-91a0-4403-b774-5201965ec8e8','偈頌一百二十三首  其一○○','釋普度','宋','宋诗','song-poetry','','[]','見身無實是佛見，了心如幻是佛了。',50,'全唐诗/poet.song.213000.json','["見身無實是佛見，了心如幻是佛了。", "了得身心本性空，斯人與佛何殊別。", "坐底坐，立底立。", "觸目遇緣，更非他物。"]'),
('2ec1201f-8679-43f8-87aa-b5d350922b6c','偈頌一百二十三首  其一○一','釋普度','宋','宋诗','song-poetry','','[]','一佛出世，祥光布地。',36,'全唐诗/poet.song.213000.json','["一佛出世，祥光布地。", "一念萬年，壽山增翠。", "曉來風起滿庭香，吹綻蟠桃三五蘂。"]'),
('44a5d29e-5309-44e4-ad97-dfe043f83fe1','偈頌一百二十三首  其一○二','釋普度','宋','宋诗','song-poetry','','[]','是法住法位，世間相常住。',36,'全唐诗/poet.song.213000.json','["是法住法位，世間相常住。", "昨日大風潮，吹折山前樹。", "雲自向天飛，水流朝海去。"]'),
('65dba894-110f-4941-9a06-085581d7d002','偈頌一百二十三首  其一○三','釋普度','宋','宋诗','song-poetry','','[]','用文武火，運惡鉗鎚。',60,'全唐诗/poet.song.213000.json','["用文武火，運惡鉗鎚。", "死學者偷心，開人天眼目。", "大用機前轉轆轆，十分慈悲，十分惡毒。", "六踞名藍兮一笑來歸，青燈夜寒兮香風馥馥。"]'),
('143e2f5b-803b-4629-9d04-46aba57b7aba','偈頌一百二十三首  其一○四','釋普度','宋','宋诗','song-poetry','','[]','山前一片閑田地，曠大劫來無界至。',48,'全唐诗/poet.song.213000.json','["山前一片閑田地，曠大劫來無界至。", "今朝恢復又歸來，坐斷脚頭併脚尾。", "東也是，西也是，南北東西無不是。"]'),
('7dbd8f22-99ea-4de3-8c80-d26e175b96cb','偈頌一百二十三首  其一○五','釋普度','宋','宋诗','song-poetry','','[]','屋裡有金，外頭有秤。',34,'全唐诗/poet.song.213000.json','["屋裡有金，外頭有秤。", "鹽鹹醋淡，斤兩自定。", "自然左右逢原，管取拍拍是令。"]'),
('1d30c206-2bb0-4fd7-94b8-447b8b116715','偈頌一百二十三首  其一○六','釋普度','宋','宋诗','song-poetry','','[]','八十翁翁輥繡毬，誰知輥得意休休。',32,'全唐诗/poet.song.213000.json','["八十翁翁輥繡毬，誰知輥得意休休。", "如今逗到凌霄上，雲自高飛水自流。"]'),
('01948a16-a556-46e1-9288-f3995ee47885','偈頌一百二十三首  其一○七','釋普度','宋','宋诗','song-poetry','','[]','雙雙把手上高樓，唱拍相從各應酬。',32,'全唐诗/poet.song.213000.json','["雙雙把手上高樓，唱拍相從各應酬。", "歌皷散時人盡醉，也無歡喜也無愁。"]'),
('3333df0f-d47c-4331-8344-034bab55a34d','偈頌一百二十三首  其一○八','釋普度','宋','宋诗','song-poetry','','[]','今朝七月十五，衲僧拄杖起舞。',46,'全唐诗/poet.song.213000.json','["今朝七月十五，衲僧拄杖起舞。", "頭頂西天，脚踏東土。", "遊歷百城，不移寸步。", "阿呵呵，白雲綻處青山露。"]'),
('f846e657-5902-4351-b210-4eb872d4e6fb','偈頌一百二十三首  其一○九','釋普度','宋','宋诗','song-poetry','','[]','二大老，一人船行，一人步到。',24,'全唐诗/poet.song.213000.json','["二大老，一人船行，一人步到。", "狹路相逢，掀眉一笑。"]'),
('a4082315-7e60-4d04-9adc-0645c55ef42f','偈頌一百二十三首  其一一○','釋普度','宋','宋诗','song-poetry','','[]','天無四壁，大地爲爐。',38,'全唐诗/poet.song.213000.json','["天無四壁，大地爲爐。", "籬頭吹觱栗，寒鴈一聲孤。", "老胡若不渡江去，至今火種一星無。"]'),
('9f5345e1-6f7e-4d3a-b8a3-7d01ef603065','偈頌一百二十三首  其一一一','釋普度','宋','宋诗','song-poetry','','["\u592a\u6e56"]','鄔那青青處，山高雲半垂。',52,'全唐诗/poet.song.213000.json','["鄔那青青處，山高雲半垂。", "面面栽荆棘，遊人到者稀。", "寥寥五十載，昨是今何非。", "太湖三萬六千頃，月在波心說向誰。"]'),
('8482ffd2-cb02-4fb5-936a-dbf23f2183ea','偈頌一百二十三首  其一一二','釋普度','宋','宋诗','song-poetry','','[]','震法雷，擊法皷。',44,'全唐诗/poet.song.213000.json','["震法雷，擊法皷。", "玉角金鱗，興雲吐霧。", "機前拶倒凌霄峰，大地撮來無寸土。", "殺活全提，平欺佛祖。"]'),
('de2e6671-34df-4e2e-987f-28a6bf1434a0','偈頌一百二十三首  其一一三','釋普度','宋','宋诗','song-poetry','','[]','驕陽正酷火雲飛，一雨霶𩃱徹四維。',32,'全唐诗/poet.song.213000.json','["驕陽正酷火雲飛，一雨霶𩃱徹四維。", "䆉稏吹香民已樂，山川草木亦光輝。"]'),
('0ef1a85d-7504-4c1c-8585-6ddfbc89a919','偈頌一百二十三首  其一一四','釋普度','宋','宋诗','song-poetry','','[]','鐵網漫漫面面開，百城幾度去還來。',32,'全唐诗/poet.song.213000.json','["鐵網漫漫面面開，百城幾度去還來。", "二千年結知誰解，又著三文買草鞋。"]'),
('99968163-87c3-4ad7-93e3-5d94124dc223','偈頌一百二十三首  其一一五','釋普度','宋','宋诗','song-poetry','','[]','佛法無人說，雖慧不能了。',24,'全唐诗/poet.song.213000.json','["佛法無人說，雖慧不能了。", "幸然平似鏡，何用曲如鈎。"]'),
('4e10eb33-7840-4019-84a4-66b158a25214','偈頌一百二十三首  其一一六','釋普度','宋','宋诗','song-poetry','','[]','時臨秋九，不寒不熱。',34,'全唐诗/poet.song.213000.json','["時臨秋九，不寒不熱。", "瓦礫鳴秋蛩，茅簷掛殘月。", "各自著便宜，正是好時節。"]'),
('db6aec23-29d4-4022-9b2a-19cd6568b64b','偈頌一百二十三首  其一一七','釋普度','宋','宋诗','song-poetry','','[]','一日三，三日九。',42,'全唐诗/poet.song.213000.json','["一日三，三日九。", "只知暑往寒來，不覺躘蹱老朽。", "退一步，絕離微。", "百花開盡後，黄菊在東籬。"]'),
('43d9b347-072b-4b0d-9473-e431fe9c529f','偈頌一百二十三首  其一一八','釋普度','宋','宋诗','song-poetry','','[]','憶昔當年錯訪尋，被他用盡毒肝心。',80,'全唐诗/poet.song.213000.json','["憶昔當年錯訪尋，被他用盡毒肝心。", "賺來賺到凌霄頂，火冷雲寒恨轉深。", "冤可解，不可結，必竟如今甚時節。", "打拳何似喫拳時，此理明明向誰說。", "旋汲龍淵萬丈深，爛煮春茶飜白雪。"]'),
('122dc492-6a68-4866-8a73-50b99e00b918','偈頌一百二十三首  其一一九','釋普度','宋','宋诗','song-poetry','','[]','徑山一椀上元燈，不是攢花剪簇成。',32,'全唐诗/poet.song.213000.json','["徑山一椀上元燈，不是攢花剪簇成。", "等閑拈起當陽掛，爍破諸方鬼眼睛。"]'),
('3dfcce42-64c5-4572-b3ee-a7e543ba17ac','偈頌一百二十三首  其一二○','釋普度','宋','宋诗','song-poetry','','[]','踏斷洛陽橋，直上妙峰頂。',74,'全唐诗/poet.song.213000.json','["踏斷洛陽橋，直上妙峰頂。", "拈得家傳黑竹篦，攪動龍淵千尺井。", "四五處雷動風行，八九十春花月影。", "爲人端的無情，獨脫單提誰領。", "竹篦雖折典刑存，聞見猶能發深省。"]'),
('1af7f840-ef5e-4275-8c8a-6f445441cb9d','偈頌一百二十三首  其一二一','釋普度','宋','宋诗','song-poetry','','[]','聲前一句，格外一機。',76,'全唐诗/poet.song.213000.json','["聲前一句，格外一機。", "不墮古今，寧存凡聖。", "妙高臺上，玉鑑光中。", "日日安居，時時禁足。", "風恬浪靜，海晏河清。", "長期短期，平等受用。", "闌干同倚不同倚，消得龍王多少風。"]'),
('7a946353-ce0b-4da9-9888-dd81594a35b7','偈頌一百二十三首  其一二二','釋普度','宋','宋诗','song-poetry','','[]','學道先須有悟由，賊無種，相皷儱，還如曾鬭快龍舟，碧眼胡僧笑不休。',94,'全唐诗/poet.song.213000.json','["學道先須有悟由，賊無種，相皷儱，還如曾鬭快龍舟，碧眼胡僧笑不休。", "雖然舊閣閑田地，物見主，眼卓豎。", "一度贏來方始休，綠楊影裏戴嵩牛。", "如是安居，如是禁足。", "知投身於火悉皆成火，似鎔像爲金莫不□□。"]'),
('cc932085-4d67-4817-8a38-3bd9d6ca8b0b','偈頌一百二十三首  其一二三','釋普度','宋','宋诗','song-poetry','','[]','今歲今宵盡，明年明日來。',24,'全唐诗/poet.song.213000.json','["今歲今宵盡，明年明日來。", "寒隨一夜去，春逐五更回。"]'),
('9917ff0c-ce0a-43ea-aea1-d21815d3dab4','悼天童晦巖和尚','釋普度','宋','宋诗','song-poetry','','[]','恩怨重重分未分，再來不見舊時人。',32,'全唐诗/poet.song.213000.json','["恩怨重重分未分，再來不見舊時人。", "娟娟宿鷺亭前月，忍照西風吹白蘋。"]'),
