('617efe7d-093f-45f6-af86-e1e7ce754162','錢清接待','釋普度','宋','宋诗','song-poetry','','[]','短策輕囊稱野情，憧憧何事過錢清。',32,'全唐诗/poet.song.213000.json','["短策輕囊稱野情，憧憧何事過錢清。", "入門喫飯出門去，莫道沃洲山水青。"]'),
('81234704-b1a7-451b-9e6a-808cecd3e07b','贈醫牙道人','釋普度','宋','宋诗','song-poetry','','[]','先生得道醫牙齒，痛令不痛消彈指。',32,'全唐诗/poet.song.213000.json','["先生得道醫牙齒，痛令不痛消彈指。", "飽飯吾今八十年，未嘗咬著一粒米。"]'),
('1fa68968-eeac-49c3-a5fd-454ceeb2b8bc','碑匠','釋普度','宋','宋诗','song-poetry','','[]','點劃縱橫一脫新，之乎者也轉精神。',32,'全唐诗/poet.song.213000.json','["點劃縱橫一脫新，之乎者也轉精神。", "只於黑白分明處，驗盡尋行數墨人。"]'),
('80656834-55c3-4b9b-b7ec-beae4d48a941','浄髮','釋普度','宋','宋诗','song-poetry','','[]','工夫用處沒蹻踦，心手相應合自知。',32,'全唐诗/poet.song.213000.json','["工夫用處沒蹻踦，心手相應合自知。", "毫髮盡時消息盡，不妨眼上又安眉。"]'),
('7c61a611-2606-4b50-b021-00d18b4ad72c','出山相贊','釋普度','宋','宋诗','song-poetry','','[]','萬乘尊榮都棄了，六年雪嶺受饑寒。',32,'全唐诗/poet.song.213000.json','["萬乘尊榮都棄了，六年雪嶺受饑寒。", "明星一見便回首，到底依前被眼瞞。"]'),
('f45aaa74-f198-47b2-bccc-ff87164d9a2b','觀音贊','釋普度','宋','宋诗','song-poetry','','[]','苦海橫身一葉輕，黑風吹墮任縱橫。',32,'全唐诗/poet.song.213000.json','["苦海橫身一葉輕，黑風吹墮任縱橫。", "要令險處人回首，月在補陀天際生。"]'),
('94bc36ef-194a-4fa3-bdbf-5fd610dab698','馬郎婦贊','釋普度','宋','宋诗','song-poetry','','[]','神清風韻高，鬢綠雲鬟小。',40,'全唐诗/poet.song.213000.json','["神清風韻高，鬢綠雲鬟小。", "賺盡好郎君，法華都誦了。", "到頭姻婭不成雙，金沙月影空相照。"]'),
('bf595103-186f-4fbd-8a18-789e50ab64e8','達磨贊二首  其一','釋普度','宋','宋诗','song-poetry','','[]','竺國太平思泛海，中華禍起向東來。',32,'全唐诗/poet.song.213000.json','["竺國太平思泛海，中華禍起向東來。", "當時不遇梁天子，只好深深掘地埋。"]'),
('31b6512d-9c42-4c5f-b16a-8f519f72e570','達磨贊二首  其二','釋普度','宋','宋诗','song-poetry','','[]','梁皇法令豈徒勞，滯貨私通價轉高。',32,'全唐诗/poet.song.213000.json','["梁皇法令豈徒勞，滯貨私通價轉高。", "蘆葦蕭蕭熊耳月，至今大地是波濤。"]'),
('d3418c1a-6c9a-4bb3-b533-b13d34e0b5c0','寶公贊','釋普度','宋','宋诗','song-poetry','','[]','剪刀拂尺，高挂金錫。',57,'全唐诗/poet.song.213000.json','["剪刀拂尺，高挂金錫。", "賣狗懸羊，多虛少實。", "掉發武帝趕達磨過江，五葉一花，從此狼藉。", "稽首十二面觀音，正面有誰識得，㘞。"]'),
('d9b2fe3e-4cf2-4758-a49e-662cdeed03ec','布袋贊','釋普度','宋','宋诗','song-poetry','','[]','兜率內宮不肯住，杖挑布袋紅塵去。',44,'全唐诗/poet.song.213000.json','["兜率內宮不肯住，杖挑布袋紅塵去。", "不知開口笑何人，待你下生人笑你。", "阿呵呵，寬著肚皮等著他。"]'),
('7d25bd30-ef8a-489c-a0bf-ae7797545325','豬頭和尚贊','釋普度','宋','宋诗','song-poetry','','[]','金華聖者無人識，相逢便討豬頭喫。',32,'全唐诗/poet.song.213000.json','["金華聖者無人識，相逢便討豬頭喫。", "回首還從舊路歸，春風一陣香狼藉。"]'),
('6eade0e3-38bb-4fbc-8ae9-c9057f7e535a','蜆子贊','釋普度','宋','宋诗','song-poetry','','[]','不釣鯨鰲只撈蜆，得些滋味興偏佳。',32,'全唐诗/poet.song.213000.json','["不釣鯨鰲只撈蜆，得些滋味興偏佳。", "拈來塞斷娘生口，一段風光屬當家。"]'),
('813c9f60-4beb-4dc7-8aef-d88a314066b1','寒山贊','釋普度','宋','宋诗','song-poetry','','[]','沒伎倆，愛吟詩。',24,'全唐诗/poet.song.213000.json','["沒伎倆，愛吟詩。", "一句子，少人知。", "寥寥靜聽松風吹。"]'),
('84ecb5f9-d889-41b7-a5a7-75ffc35e1587','拾得贊','釋普度','宋','宋诗','song-poetry','','[]','生掃箒，用得親。',24,'全唐诗/poet.song.213000.json','["生掃箒，用得親。", "休指注，枉辛勤。", "本來田地絕纖塵。"]'),
('9d02fd42-50c7-4984-9133-ade130f6e5ee','藥山贊','釋普度','宋','宋诗','song-poetry','','[]','瓶內水，松下經。',26,'全唐诗/poet.song.213000.json','["瓶內水，松下經。", "有人來問，覿面相呈。", "白雲散盡秋天青。"]'),
('fc435be5-4256-4c20-a6e6-76b1d9a3a6ae','懶瓚贊','釋普度','宋','宋诗','song-poetry','','[]','山窈窕，路羊腸。',26,'全唐诗/poet.song.213000.json','["山窈窕，路羊腸。", "紫泥下詔，御墨猶香。", "報道我儂煨芋忙。"]'),
('626a52bc-f1a5-4338-90b9-622631506be1','德山贊','釋普度','宋','宋诗','song-poetry','','[]','擔疏鈔行脚，大負不平氣。',64,'全唐诗/poet.song.213000.json','["擔疏鈔行脚，大負不平氣。", "失脚到龍潭，未愜平生意。", "吹滅紙燈時，拶著娘生鼻。", "便將一炬火，燒却閑故紙。", "從茲憤憤覓冤讎，一條白棒掀天地。"]'),
('852d6cf3-cf7e-4647-a072-f55e9a8dacb2','臨濟贊','釋普度','宋','宋诗','song-poetry','','[]','黄蘗山頭兀坐，開口咬著生鐵。',54,'全唐诗/poet.song.213000.json','["黄蘗山頭兀坐，開口咬著生鐵。", "高安灘上飜身，也似掉棒打月。", "從茲便解，赤手白拈，以楔出楔。", "別別，無位真人乾屎橛。"]'),
('b9147f7f-1875-48e8-9738-0da6670ee8f3','佛光法師贊','釋普度','宋','宋诗','song-poetry','','[]','蕩蕩慈風彌宇宙，滔滔辯瀉四河清。',32,'全唐诗/poet.song.213000.json','["蕩蕩慈風彌宇宙，滔滔辯瀉四河清。", "毗盧海印全身佩，香擁優曇滿帝城。"]'),
('c0bac796-8f11-45de-890c-6304488ff0a6','虛堂和尚贊','釋普度','宋','宋诗','song-poetry','','[]','戲海獰龍，出山猛虎。',64,'全唐诗/poet.song.213000.json','["戲海獰龍，出山猛虎。", "眼蓋乾坤，氣吞佛祖。", "嚴法令則滴水冰生，提向上則超今越古。", "九據名藍，三奉詔旨。", "無愧當年面壁人，只是口門多一齒。"]'),
('dc0a6afd-bd46-4e19-8666-2593f573a2a0','覺城夏大師贊','釋普度','宋','宋诗','song-poetry','','[]','隠峰有女弟，我亦有女弟。',40,'全唐诗/poet.song.213000.json','["隠峰有女弟，我亦有女弟。", "雖然各自行，必竟同時至。", "花開花落覺城東，兒孫代代長相繼。"]'),
('fbb162c3-dde3-4834-a4fa-021fea88a832','自贊','釋普度','宋','宋诗','song-poetry','','[]','畫得十分，且信一半。',48,'全唐诗/poet.song.213000.json','["畫得十分，且信一半。", "脚尾脚頭，渾無畔岸。", "一點鬼眼睛，黑豆終難換。", "徐行緩步五峰頭，一輪明月凌霄漢。"]'),
('be6b8803-2017-43a6-a897-eea4959f7a7c','穹窿森長老請贊','釋普度','宋','宋诗','song-poetry','','[]','渠儂面目，畫則不似。',50,'全唐诗/poet.song.213000.json','["渠儂面目，畫則不似。", "只因伎倆全無，重負楊岐擔子。", "棒喝機前，阿誰敢擬。", "橫拋豎擲破沙盆，通玄峰頂清風起。"]'),
('cc9ffc1a-8291-4d2c-9757-44be5407aad3','日本瓊林侍者請贊','釋普度','宋','宋诗','song-poetry','','[]','百醜千拙，無法可說。',52,'全唐诗/poet.song.213000.json','["百醜千拙，無法可說。", "一箇拳頭，硬如生鐵。", "放開則日耀扶桑，捏聚則乾坤黯黑。", "冤家莫興惡相從，正法眼藏瞎馿滅。"]'),
('6b409eeb-98b0-45ff-9a20-40ad788b035b','小師淳縝請贊','釋普度','宋','宋诗','song-poetry','','[]','工夫縝密，描畫不及。',35,'全唐诗/poet.song.213000.json','["工夫縝密，描畫不及。", "正令全提，佛也不識。", "十分惡毒得人憎，付與破家五逆。"]'),
('e56651e8-c54e-4d75-9939-5a53dd5d98cd','小師淳元請贊','釋普度','宋','宋诗','song-poetry','','[]','據坐胡床，風生萬壑。',36,'全唐诗/poet.song.213000.json','["據坐胡床，風生萬壑。", "無說而說，無作而作。", "聲前的的有來源，必竟不留元字脚。"]'),
('92e0f49a-cf43-4120-8fb0-c991ba625173','小師淳密請贊','釋普度','宋','宋诗','song-poetry','','[]','頭白眉鬚白，胸中無點墨。',42,'全唐诗/poet.song.213000.json','["頭白眉鬚白，胸中無點墨。", "說禪不入時樣，一味點胸點肋。", "密意分明生汝邊，何待當來問彌勒。"]'),
('cf343a5f-a8ad-4e2b-8e6f-cb802de3ea8c','郁維那請贊','釋普度','宋','宋诗','song-poetry','','[]','這漢酷毒，元無面目。',48,'全唐诗/poet.song.213000.json','["這漢酷毒，元無面目。", "描畫難成，下筆則觸。", "瞎衲僧正眼，滅老胡種族。", "殃害叢林卒未休，一時付與清江郁。"]'),
('3a0b65e2-dc3b-4d63-8e73-133bcf324c67','益侍者請贊','釋普度','宋','宋诗','song-poetry','','[]','面目可憎，胸中條直。',36,'全唐诗/poet.song.213000.json','["面目可憎，胸中條直。", "勿彼勿此，何損何益。", "不將佛法當人情，一任破沙盆狼藉。"]'),
('546793cf-1818-4190-909b-ae93815db0b4','寮前老郎請贊','釋普度','宋','宋诗','song-poetry','','[]','心直如絃，性急似箭。',39,'全唐诗/poet.song.213000.json','["心直如絃，性急似箭。", "翻手覆手，日面月面。", "零敲碎打破沙盆，我見人見衆生見壽者見。"]'),
('46411224-92a1-4a91-844e-dc656df0dc08','辭世頌','釋普度','宋','宋诗','song-poetry','','[]','八十二年，駕無底船。',20,'全唐诗/poet.song.213000.json','["八十二年，駕無底船。", "踏翻歸去，明月一天。"]'),
('28e4c16d-5209-44be-886a-099be3b70fe6','頌古一首','釋普度','宋','宋诗','song-poetry','','[]','雙林樹下手摩胸，說有談無恣脫空。',32,'全唐诗/poet.song.213000.json','["雙林樹下手摩胸，說有談無恣脫空。", "若謂瞿曇曾入滅，錯教啼鳥笑春風。"]'),
('8c03ba46-1e57-4978-b2b5-6b3b678ec49d','和靜照詩韻  其一','釋普度','宋','宋诗','song-poetry','','[]','汲來崖瀑煮新茶，紫玉甌中現瑞霞。',32,'全唐诗/poet.song.213000.json','["汲來崖瀑煮新茶，紫玉甌中現瑞霞。", "到此豁然如夢覺，一天疏雨濕秋花。"]'),
('63703a0c-3674-43ea-9685-fae2e9e6c551','和靜照詩韻  其二','釋普度','宋','宋诗','song-poetry','','[]','磵邊雲泠裛蒼苔，木杪金燈午夜開。',32,'全唐诗/poet.song.213000.json','["磵邊雲泠裛蒼苔，木杪金燈午夜開。", "更問曇猷在何許，分明猶隔海門來。"]'),
('2ad1a387-0a55-4fc2-bf11-42808f0b4b0b','偈頌一百六十九首  其一','釋智朋','宋','宋诗','song-poetry','','[]','不立孤危，了無藏覆。',20,'全唐诗/poet.song.213000.json','["不立孤危，了無藏覆。", "掉臂因行，推門入臼。"]'),
('aa4cf384-5fa9-4fa0-a773-8b1e29d0575c','偈頌一百六十九首  其二','釋智朋','宋','宋诗','song-poetry','','[]','佛身無爲，不墮諸數。',28,'全唐诗/poet.song.213000.json','["佛身無爲，不墮諸數。", "土塊泥團，燈籠露柱。", "鳳棲不在梧桐樹。"]'),
('f83a1b25-e2c4-425f-87f3-258a21a8fea3','偈頌一百六十九首  其三','釋智朋','宋','宋诗','song-poetry','','[]','北鬰單越，西瞿耶尼。',20,'全唐诗/poet.song.213000.json','["北鬰單越，西瞿耶尼。", "有利無利，不離行市。"]'),
('958b09ac-fdf9-4a22-bfc0-78ba021be4c1','偈頌一百六十九首  其四','釋智朋','宋','宋诗','song-poetry','','[]','一燈分燈燈無盡，一處明處處齊透。',44,'全唐诗/poet.song.213000.json','["一燈分燈燈無盡，一處明處處齊透。", "閙浩浩中一法不捨，靜悄悄處一塵不受。", "燈明如來，一場漏逗。"]'),
('8c1c0fd3-34d4-45d9-81da-c3b4617acabd','偈頌一百六十九首  其五','釋智朋','宋','宋诗','song-poetry','','[]','事同一家，萬別千差。',28,'全唐诗/poet.song.213000.json','["事同一家，萬別千差。", "雲門餬餠，趙州喫茶。", "何似南山鱉鼻蛇。"]'),
('b6e7763f-24d7-45ff-b1d4-b146ddc3d580','偈頌一百六十九首  其六','釋智朋','宋','宋诗','song-poetry','','[]','未舉先知，未言先領。',28,'全唐诗/poet.song.213000.json','["未舉先知，未言先領。", "趙州無關，玄沙有嶺。", "萬別千差一印定。"]'),
('b9ea45a1-5dcb-443a-9bd2-623203a3d5d8','偈頌一百六十九首  其七','釋智朋','宋','宋诗','song-poetry','','[]','卒風暴雨，鼓蕩無前。',39,'全唐诗/poet.song.213000.json','["卒風暴雨，鼓蕩無前。", "石裂崖崩，回避不及。", "總教喪盡生涯，方見時清道泰。", "功不浪施。"]'),
('486c04c0-0b2b-4a62-aa58-57dc7b3597e8','偈頌一百六十九首  其八','釋智朋','宋','宋诗','song-poetry','','[]','秋雨凄凄，秋雲黯黯。',26,'全唐诗/poet.song.213000.json','["秋雨凄凄，秋雲黯黯。", "修成八萬四千斧，不比尋常三五圓。"]'),
('df80a464-7a8d-45e8-9b34-35292a87224b','偈頌一百六十九首  其九','釋智朋','宋','宋诗','song-poetry','','[]','日卓午，夜半子。',39,'全唐诗/poet.song.213000.json','["日卓午，夜半子。", "千門萬戶俱開，一聲兩聲砧杵。", "流沙浪闊，葱嶺無路，達磨何曾歸去。"]'),
('a0d17912-aeac-4b3e-a3c2-26aec54ab856','偈頌一百六十九首  其一○','釋智朋','宋','宋诗','song-poetry','','[]','大地皆凍鎖，遍界熱如火。',36,'全唐诗/poet.song.213000.json','["大地皆凍鎖，遍界熱如火。", "時節不放過，衲僧多蹉過。", "不蹉過，深雪之中有一箇。"]'),
('70183421-8436-4653-a6be-a478356768bf','偈頌一百六十九首  其一一','釋智朋','宋','宋诗','song-poetry','','[]','伶利衲僧，動無思算。',35,'全唐诗/poet.song.213000.json','["伶利衲僧，動無思算。", "合水和泥，田頭地畔。", "搆得完全，只得一半，窮坑難滿。"]'),
('c9b2d60d-c23c-4bbf-a6d0-7be99a4fa9f6','偈頌一百六十九首  其一二','釋智朋','宋','宋诗','song-poetry','','[]','楖𣗖木卷而曲，回天關轉地軸。',47,'全唐诗/poet.song.213000.json','["楖𣗖木卷而曲，回天關轉地軸。", "群陰時時剝盡，一陽日日來復。", "爲甚羅漢山中冷門難向，不是苦心人不知。"]'),
('5d9d0909-4a6a-40af-88f9-bbdf17bab840','偈頌一百六十九首  其一三','釋智朋','宋','宋诗','song-poetry','','[]','全身坐在正覺山中，要行便行要用便用。',34,'全唐诗/poet.song.213000.json','["全身坐在正覺山中，要行便行要用便用。", "明星現處路頭通，十倍慈悲成脫空。"]'),
('f41c77d7-d61f-4eda-b89a-5cf978c3d352','偈頌一百六十九首  其一四','釋智朋','宋','宋诗','song-poetry','','[]','舊歲昨宵去，新年今日來。',34,'全唐诗/poet.song.213000.json','["舊歲昨宵去，新年今日來。", "燈籠與露柱，不覺笑咍咍。", "達磨面壁，雲門念七。"]'),
('8cb8c381-c1a8-4309-acb4-8320d0901bb3','偈頌一百六十九首  其一五','釋智朋','宋','宋诗','song-poetry','','[]','黄面老子性命，今日落在朋上座手裏。',27,'全唐诗/poet.song.213000.json','["黄面老子性命，今日落在朋上座手裏。", "扶起放倒，不爲差事。"]'),
('affe1f29-db37-469a-9b8d-684b4d24ee3d','偈頌一百六十九首  其一六','釋智朋','宋','宋诗','song-poetry','','[]','達磨西來，卦文不識。',46,'全唐诗/poet.song.213000.json','["達磨西來，卦文不識。", "胡卜亂卜，傳至今日。", "佛日等是開箇鋪席，敢向朕兆未分已前。", "端平元年正月一。"]'),
('b644ba71-5e5d-454d-b01a-8385798631d3','偈頌一百六十九首  其一七','釋智朋','宋','宋诗','song-poetry','','[]','桃花爛熳紅，靈雲眼中血。',24,'全唐诗/poet.song.213000.json','["桃花爛熳紅，靈雲眼中血。", "不是斷腸人，此恨向誰說。"]'),
('8debf714-fc88-425d-8e85-11096770d058','偈頌一百六十九首  其一八','釋智朋','宋','宋诗','song-poetry','','[]','胞胎才出播殃塵，直至如今毒害人。',32,'全唐诗/poet.song.213000.json','["胞胎才出播殃塵，直至如今毒害人。", "一杓蘭湯無限恨，腕頭何止重千斤。"]'),
('df9e1717-a0b7-4dd2-a951-bee2679fcfd4','偈頌一百六十九首  其一九','釋智朋','宋','宋诗','song-poetry','','[]','禁足安居，一句直舉。',20,'全唐诗/poet.song.213000.json','["禁足安居，一句直舉。", "匝地普天，四月十五。"]'),
('76dc747d-3813-437d-9a68-11afdbc6029c','偈頌一百六十九首  其二○','釋智朋','宋','宋诗','song-poetry','','[]','一葉落，天下秋。',36,'全唐诗/poet.song.213000.json','["一葉落，天下秋。", "回避不及底眼睛突出，窺覷無門底南州北州。", "有來由處沒來由。"]'),
('9362771c-a89e-4b31-acba-6b77b00f9aba','偈頌一百六十九首  其二一','釋智朋','宋','宋诗','song-poetry','','[]','冬不寒，臘後看。',38,'全唐诗/poet.song.213000.json','["冬不寒，臘後看。", "酸風刮地，凍破泥團。", "毗盧樓閣前，少林深雪裏，誰知猶隔萬重關。"]'),
('84e0d3a0-6072-4aa9-9274-e6b0da1d1376','偈頌一百六十九首  其二二','釋智朋','宋','宋诗','song-poetry','','[]','滯貨無價，爛錢無索。',29,'全唐诗/poet.song.213000.json','["滯貨無價，爛錢無索。", "咬定牙關，將錯就錯。", "天將以夫子爲木鐸。"]'),
('2e0fb54e-5ecf-4d8d-804d-d527cc8fcd74','偈頌一百六十九首  其二三','釋智朋','宋','宋诗','song-poetry','','[]','提折脚鐺，各出隻手。',42,'全唐诗/poet.song.213000.json','["提折脚鐺，各出隻手。", "釋迦不先，彌勒不後。", "妙用臨機，如盤珠走。", "鼓腹笑復歌，面南看北斗。"]'),
('17715521-77c7-42af-87ac-cbfd19c2a026','偈頌一百六十九首  其二四','釋智朋','宋','宋诗','song-poetry','','[]','六載將身草裏埋，當時有眼幾曾開。',32,'全唐诗/poet.song.213000.json','["六載將身草裏埋，當時有眼幾曾開。", "果然見得明星現，未到門庭冷似灰。"]'),
('692ad558-3e60-4f51-a6a3-fade085d6a37','偈頌一百六十九首  其二五','釋智朋','宋','宋诗','song-poetry','','[]','坐底坐殺，立底立殺。',26,'全唐诗/poet.song.213000.json','["坐底坐殺，立底立殺。", "不知誰是赤鬚胡，轉身句子活鱍鱍。"]'),
('68f6dd47-efe1-4caa-8090-7996aa6b4b1c','偈頌一百六十九首  其二六','釋智朋','宋','宋诗','song-poetry','','[]','節屆元宵氣象新，笙歌競奏漢宮春。',32,'全唐诗/poet.song.213000.json','["節屆元宵氣象新，笙歌競奏漢宮春。", "滿城燈火暄和氣，車馬往來人看人。"]'),
('04f87d96-2007-47d8-a091-3e0031267a9b','偈頌一百六十九首  其二七','釋智朋','宋','宋诗','song-poetry','','[]','四十九年蹲坐處，無明荒草幾多愁。',32,'全唐诗/poet.song.213000.json','["四十九年蹲坐處，無明荒草幾多愁。", "一朝得意春風裏，活却從前死路頭。"]'),
('48d41983-ffd3-43ca-aaa8-46a4ec240358','偈頌一百六十九首  其二八','釋智朋','宋','宋诗','song-poetry','','[]','黄檗棒頭，馬祖喝下。',26,'全唐诗/poet.song.213000.json','["黄檗棒頭，馬祖喝下。", "家家春風二三月，處處綠楊堪繫馬。"]'),
('9ed96e6a-f1f4-4ef8-9b38-54f53da83912','偈頌一百六十九首  其二九','釋智朋','宋','宋诗','song-poetry','','[]','諸佛出世，標拍荒郊，達磨西來，塚添新土。',44,'全唐诗/poet.song.213000.json','["諸佛出世，標拍荒郊，達磨西來，塚添新土。", "保福今日，向拜掃無門處打開一路，冬至寒食一百五。"]'),
('d935bf2b-a43b-4119-8fec-3cc96c638847','偈頌一百六十九首  其三○','釋智朋','宋','宋诗','song-poetry','','[]','暮春初，修禊事。',50,'全唐诗/poet.song.213000.json','["暮春初，修禊事。", "少長咸集，群賢畢至。", "數樹松花，一溪流水。", "知慚愧底足以暢敘幽情，無摸索底正好頓張意氣。"]'),
('2060b798-fa41-4e3b-843a-54f87207bb3a','偈頌一百六十九首  其三一','釋智朋','宋','宋诗','song-poetry','','[]','不捨諸道法，而現凡夫事。',48,'全唐诗/poet.song.213000.json','["不捨諸道法，而現凡夫事。", "萬人遊仰處高掛錦標，千波競起時要須好手。", "還如曾鬭快龍舟，一度贏來方始休。"]'),
('6dcb8501-8297-4fec-bd8c-018f95a0b345','偈頌一百六十九首  其三二','釋智朋','宋','宋诗','song-poetry','','[]','動絃別曲，落葉知秋。',20,'全唐诗/poet.song.213000.json','["動絃別曲，落葉知秋。", "普天匝地，騎牛覓牛。"]'),
('8d382133-3e7d-4e8f-8d08-40321f5eaeea','偈頌一百六十九首  其三三','釋智朋','宋','宋诗','song-poetry','','[]','心月孤圓，光吞萬像，起模畫樣。',35,'全唐诗/poet.song.213000.json','["心月孤圓，光吞萬像，起模畫樣。", "光非照境，境亦非存，收拾不上，光境俱亡。"]'),
('5db6e1bc-a181-4412-a933-80e30309f9cd','偈頌一百六十九首  其三四','釋智朋','宋','宋诗','song-poetry','','[]','得力句子，全身擔荷。',40,'全唐诗/poet.song.213000.json','["得力句子，全身擔荷。", "水長船高，泥多佛大。", "西風鴈字新，東籬菊花老，四十九年談不到。"]'),
('8ae375f3-fbee-4dc0-9e87-5972b10ef6c6','偈頌一百六十九首  其三五','釋智朋','宋','宋诗','song-poetry','','[]','行路難，有何難。',36,'全唐诗/poet.song.213000.json','["行路難，有何難。", "不見陶淵明，採菊東籬下，悠然見南山。", "彼此丈夫，莫受人瞞。"]'),
('e47b3834-5d3c-45a6-bebd-61f79d130e3e','偈頌一百六十九首  其三六','釋智朋','宋','宋诗','song-poetry','','[]','多言喪道，多歧亡羊。',36,'全唐诗/poet.song.213000.json','["多言喪道，多歧亡羊。", "渾無顆粒，別甑炊香。", "驚起暮天沙上雁，海門斜去兩三行。"]'),
('4c1c4927-ac4b-478c-9165-3e71b202fc9b','偈頌一百六十九首  其三七','釋智朋','宋','宋诗','song-poetry','','[]','一國之中，聖主最尊。',45,'全唐诗/poet.song.213000.json','["一國之中，聖主最尊。", "四民之中，君恩最重。", "衲僧居四民之外，正當今日如何報恩。", "萬年松頂拂雲高。"]'),
('b7a47e3a-181c-4d07-ac8f-306f25424cbb','偈頌一百六十九首  其三八','釋智朋','宋','宋诗','song-poetry','','[]','錯步入雪山，茫茫謾尋討。',46,'全唐诗/poet.song.213000.json','["錯步入雪山，茫茫謾尋討。", "鬼眼忽撐開，草窠裏蹲坐。", "見底是明星，悟底是什麽。", "瞿曇瞿曇，未敢相保。"]'),
('2a783cfd-a220-46e7-bed4-4fd3964fe8b8','偈頌一百六十九首  其三九','釋智朋','宋','宋诗','song-poetry','','[]','天寒人，寒徹骨，迥無依倚。',45,'全唐诗/poet.song.213000.json','["天寒人，寒徹骨，迥無依倚。", "拳到踢到當機，貴得崢嶸。", "眼裏無筋，韓獹逐塊，皮下有血，杓卜虛聲。"]'),
('1ee04d9c-65a5-4c63-8d22-ffc4c2b59372','偈頌一百六十九首  其四○','釋智朋','宋','宋诗','song-poetry','','[]','凍雲垂野，掠地衝風。',36,'全唐诗/poet.song.213000.json','["凍雲垂野，掠地衝風。", "乾坤把定，凡聖潜蹤。", "堪笑神光曾斷臂，至今埋在雪堆中。"]'),
('a644af8d-924e-4388-8f51-fd18aed94259','偈頌一百六十九首  其四一','釋智朋','宋','宋诗','song-poetry','','[]','向上機，活人句。',26,'全唐诗/poet.song.213000.json','["向上機，活人句。", "石火電光，葛藤露布。", "靈蹤更在猿啼處。"]'),
('6fc5ea14-2f3b-4056-af56-1d0195b0047a','偈頌一百六十九首  其四二','釋智朋','宋','宋诗','song-poetry','','[]','塵劫事，只如今。',39,'全唐诗/poet.song.213000.json','["塵劫事，只如今。", "向這裏瓦解冰銷，如水入水，似金博金。", "未知年窮歲盡在，三年一閏。"]'),
('f28b1b19-dcc4-410c-a6d6-b83a9b99b012','偈頌一百六十九首  其四三','釋智朋','宋','宋诗','song-poetry','','[]','大無外，細無內。',38,'全唐诗/poet.song.213000.json','["大無外，細無內。", "斗換星移，明珠絕纇。", "權實不到處，賓主歷然時，佛祖無門著眼窺。"]'),
('39e2cbf4-57dc-4a4e-823b-6060467dd2db','偈頌一百六十九首  其四四','釋智朋','宋','宋诗','song-poetry','','[]','塵劫至今，堂堂丈夫。',56,'全唐诗/poet.song.213000.json','["塵劫至今，堂堂丈夫。", "無毫髮許，蓋覆得渠。", "覓之轉失，親之轉疏。", "不論聖凡，說甚賢愚。", "直饒放下屠刀，衲僧門下未敢相許。"]'),
('77cbaafb-8639-460d-a79a-ae02c3425e2c','偈頌一百六十九首  其四五','釋智朋','宋','宋诗','song-poetry','','[]','分明見徹，開口猶難，驀過重關，轉身無路。',48,'全唐诗/poet.song.213000.json','["分明見徹，開口猶難，驀過重關，轉身無路。", "只這拙處，作麽生去。", "不得有語，不得無語，發機須是千鈞弩。"]'),
('17319e90-6266-4ab1-ae58-d3f6076a77b0','偈頌一百六十九首  其四六','釋智朋','宋','宋诗','song-poetry','','[]','履踐平實道路，倚門傍戶。',56,'全唐诗/poet.song.213000.json','["履踐平實道路，倚門傍戶。", "敲磕嶮峻門庭，接響承虛。", "無師智，自然智。", "推倒大梅峰，一舉九萬里。", "保福緩緩向道，伏惟安置。"]'),
('c45aa0c1-3942-4a25-af1d-b3582f526d6d','偈頌一百六十九首  其四七','釋智朋','宋','宋诗','song-poetry','','[]','東開西閉，滯在門庭，左出右入，重添途轍。',36,'全唐诗/poet.song.213000.json','["東開西閉，滯在門庭，左出右入，重添途轍。", "新香山有條活路，與諸人共行去也。"]'),
('85efa6c0-49bd-4422-83a5-20cd4d86106c','偈頌一百六十九首  其四八','釋智朋','宋','宋诗','song-poetry','','[]','禮自己佛，燒自己香。',22,'全唐诗/poet.song.213000.json','["禮自己佛，燒自己香。", "容顔甚奇妙，光明照十方。"]'),
('c1cddaab-b652-4d38-ba46-63f14dfcc3a8','偈頌一百六十九首  其四九','釋智朋','宋','宋诗','song-poetry','','[]','老僧軒前黄菊花，不可勝數如恒沙。',32,'全唐诗/poet.song.213000.json','["老僧軒前黄菊花，不可勝數如恒沙。", "誰在畫樓沽酒處，相邀來喫趙州茶。"]'),
('5d701db3-8a61-41f7-b2ec-172ff0ac84cb','偈頌一百六十九首  其五○','釋智朋','宋','宋诗','song-poetry','','[]','雪山六載自欺瞞，耿耿明星碧漢間。',54,'全唐诗/poet.song.213000.json','["雪山六載自欺瞞，耿耿明星碧漢間。", "開眼更無回避處，普天匝地黑漫漫。", "古今日月，古今星辰。", "若教頻下淚，滄海也須乾。"]'),
('69de2d0f-220a-49b8-a5fc-537c2787cf09','偈頌一百六十九首  其五一','釋智朋','宋','宋诗','song-poetry','','[]','此大樓閣，無住無去。',30,'全唐诗/poet.song.213000.json','["此大樓閣，無住無去。", "此樓閣門，無開無閉。", "作者同歸，不勞彈指。"]'),
('ed55cf75-3345-4fdb-af87-48955fcfe5c0','偈頌一百六十九首  其五二','釋智朋','宋','宋诗','song-poetry','','[]','七佛前引，維摩後隨。',24,'全唐诗/poet.song.213000.json','["七佛前引，維摩後隨。", "但知逐隊隨邪，脚跟何曾點地。"]'),
('24e7a816-17ec-467b-967c-f1d2cbc8b3bf','偈頌一百六十九首  其五三','釋智朋','宋','宋诗','song-poetry','','[]','雪竇與麽說話，要瞞諸人則易，埋沒諸人則難。',33,'全唐诗/poet.song.213000.json','["雪竇與麽說話，要瞞諸人則易，埋沒諸人則難。", "出門見山水，入門見佛殿。"]'),
('ecb652b5-9fae-4c78-9095-a127fbce6852','偈頌一百六十九首  其五四','釋智朋','宋','宋诗','song-poetry','','[]','武帝高懸聖鑑，要見緇素分明。',73,'全唐诗/poet.song.213000.json','["武帝高懸聖鑑，要見緇素分明。", "大士覿面當機，且非索鹽奉馬。", "檢點將來，只知賣貴，不知賣賤，可惜武帝當時放過，隨後好與一拶。", "非僧非道非俗，管取口乾舌大。"]'),
('5a78adf3-f522-4841-818b-55bb41931072','偈頌一百六十九首  其五五','釋智朋','宋','宋诗','song-poetry','','[]','一不得向，二不得討，廊下閑行，堂中打坐。',35,'全唐诗/poet.song.213000.json','["一不得向，二不得討，廊下閑行，堂中打坐。", "眼裏耳裏，觀世音，胡達磨，過。"]'),
('fbf0fa21-b2a5-458d-bb78-c4324ec099a8','偈頌一百六十九首  其五六','釋智朋','宋','宋诗','song-poetry','','[]','握驪頷明珠，秉金剛寶劍，日日禁足安居，箇箇心空及第，猶是衲僧尋常行履。',60,'全唐诗/poet.song.213000.json','["握驪頷明珠，秉金剛寶劍，日日禁足安居，箇箇心空及第，猶是衲僧尋常行履。", "雙林乍入院來，不敢背俗違時，下座且與諸人普同作禮。"]'),
('5702c919-eb25-4917-94c9-291263e750f3','偈頌一百六十九首  其五七','釋智朋','宋','宋诗','song-poetry','','[]','悲願海，四生海。',45,'全唐诗/poet.song.213000.json','["悲願海，四生海。", "出沒卷舒，圓融自在。", "善慧大士來也，石火電光，且過一邊。", "擬欲擡眸，龍華會裏。"]'),
('45b53419-6dc2-4a81-bf79-8fa1334d8b68','偈頌一百六十九首  其五八','釋智朋','宋','宋诗','song-poetry','','[]','半夜三更，天昏地黑。',32,'全唐诗/poet.song.213000.json','["半夜三更，天昏地黑。", "赤肉團邊，捉得箇賊。", "正好朝打三千，暮打八百。"]'),
('767eafe9-7e95-4933-a500-6ea0c8ceef35','偈頌一百六十九首  其五九','釋智朋','宋','宋诗','song-poetry','','[]','天得中，星辰羅。',93,'全唐诗/poet.song.213000.json','["天得中，星辰羅。", "地得中，陰陽和。", "衲僧得中，罷却干戈。", "隨寒逐暑，徒自波波。", "一夏九十日，今日是中夏，諸人未舉先和。", "因甚問著如何是汝心，却又不會，拄杖子到此，也不得無過。", "是汝諸人，還知痛癢麽。"]'),
('a7c3bd66-1c69-44b5-adfa-00eebffb831c','偈頌一百六十九首  其六○','釋智朋','宋','宋诗','song-poetry','','[]','聖制安居處，凡夫路不同。',54,'全唐诗/poet.song.213000.json','["聖制安居處，凡夫路不同。", "過去不可得，現在不可得，未來不可得。", "掀翻毗盧樓閣，只在頃刻。", "天上無彌勒，地下無彌勒。"]'),
('3bade99c-20be-46e7-a96e-e6155385da60','偈頌一百六十九首  其六一','釋智朋','宋','宋诗','song-poetry','','[]','老木成喬林，秋空見明月。',52,'全唐诗/poet.song.213000.json','["老木成喬林，秋空見明月。", "芥子之中入正定，須彌山中從定出。", "過去佛，現在佛，未來佛，無物堪比倫，教我如何說。"]'),
('4b9d5188-968b-4bca-acd0-da555c69ccbf','偈頌一百六十九首  其六二','釋智朋','宋','宋诗','song-poetry','','[]','靈龜未兆之際，黑豆未芽已前，道得一句，蓋地蓋天，猶未是無師句自然句。',50,'全唐诗/poet.song.213000.json','["靈龜未兆之際，黑豆未芽已前，道得一句，蓋地蓋天，猶未是無師句自然句。", "秋風高，秋空闊，雪峰何曾桶底脫。"]'),
('7758fa95-6bb2-4a00-917f-29865f05f5a1','偈頌一百六十九首  其六三','釋智朋','宋','宋诗','song-poetry','','[]','天上星，夜夜現。',26,'全唐诗/poet.song.213000.json','["天上星，夜夜現。", "眼豁開，方始見。", "黄面瞿曇，腦後拔箭。"]'),
('895f5067-730b-428c-b66b-ee24376cfb02','偈頌一百六十九首  其六四','釋智朋','宋','宋诗','song-poetry','','[]','寒時寒殺，熱時熱殺。',44,'全唐诗/poet.song.213000.json','["寒時寒殺，熱時熱殺。", "諸方普請寒暄。", "雙林寒時熱殺，熱時寒殺。", "且非別換條貫，大士從來頭戴冠。"]'),
('ad52c08c-cdb5-4624-afc2-1bd7f5cd0ba0','偈頌一百六十九首  其六五','釋智朋','宋','宋诗','song-poetry','','[]','三界無安，猶如火宅。',86,'全唐诗/poet.song.213000.json','["三界無安，猶如火宅。", "良醫之門，愈多病人。", "傅大士打失鼻孔眼睛，至今尋討不見。", "胡相公偏要向高高峰頂起殿，不管鹽貴米賤。", "春風一陣來，花開三五片。", "達磨大師挨拶不入，忽携隻履返西天。"]'),
('ffd40cde-24e6-42b5-a884-4bf7d0efb4a2','偈頌一百六十九首  其六六','釋智朋','宋','宋诗','song-poetry','','[]','一處通，千處萬處絕羅籠。',52,'全唐诗/poet.song.213000.json','["一處通，千處萬處絕羅籠。", "青山常在，知識難逢。", "威音王已前，猶是坐家致仕。", "衲僧氣宇如王，溈山笠子，誌公拄杖。"]'),
('d4490c6c-e296-4e25-9a8b-5c91d2b08b1c','偈頌一百六十九首  其六七','釋智朋','宋','宋诗','song-poetry','','[]','大海一漚，未發已前。',28,'全唐诗/poet.song.213000.json','["大海一漚，未發已前。", "坤六段，乾三連。", "擬欲眨眼，馿年馿年。"]'),
('da8b1f89-9de7-4909-aa35-fc79878a88a6','偈頌一百六十九首  其六八','釋智朋','宋','宋诗','song-poetry','','[]','雙林樹下生，雙林樹下滅。',24,'全唐诗/poet.song.213000.json','["雙林樹下生，雙林樹下滅。", "生死不相關，彼此是途轍。"]'),
('0fac9bb4-84f8-48fb-8c04-f4ea34c7cbd5','偈頌一百六十九首  其六九','釋智朋','宋','宋诗','song-poetry','','[]','正旦令晨，物物咸新。',40,'全唐诗/poet.song.213000.json','["正旦令晨，物物咸新。", "衲僧應時納祐，不是和光同塵。", "柏樹子，麻三斤，死柴頭上放陽春。"]'),
('a3274a25-6e2d-470e-97ae-0f1c92b9ccca','偈頌一百六十九首  其七○','釋智朋','宋','宋诗','song-poetry','','[]','一冬晴暖，梅花盡開。',43,'全唐诗/poet.song.213000.json','["一冬晴暖，梅花盡開。", "林下道人，折得一蓓兩蓓。", "但見清香可愛，不知結調羹子未得，猶有雪在。"]'),
('3db40bb3-02cf-4d80-a6f9-207879e04836','偈頌一百六十九首  其七一','釋智朋','宋','宋诗','song-poetry','','[]','寂然不動，感而遂通，癩馬繫枯樁。',53,'全唐诗/poet.song.213000.json','["寂然不動，感而遂通，癩馬繫枯樁。", "寂而常動，不感而通，四方八面絕羅籠。", "不下禪床，一喝耳聾，不妨游戲人事海中。"]'),
('0b8e5999-98ee-497a-bcf0-930fee85aaa2','偈頌一百六十九首  其七二','釋智朋','宋','宋诗','song-poetry','','[]','一切聲是佛聲，一切色是佛色。',52,'全唐诗/poet.song.213000.json','["一切聲是佛聲，一切色是佛色。", "三分光陰二早過，普天匝地逐春忙。", "辜負春光，腸斷春光。", "杏園啼百舌，誰醉在花傍。"]'),
('658647d1-893d-4092-8db9-5499678466d7','偈頌一百六十九首  其七三','釋智朋','宋','宋诗','song-poetry','','[]','是藥非藥，信手拈來。',35,'全唐诗/poet.song.213000.json','["是藥非藥，信手拈來。", "殺人活人，風生八極。", "任是文殊維摩，也少這一服不得。"]'),
('8a5741e8-beaa-452c-831a-f44803be8bae','偈頌一百六十九首  其七四','釋智朋','宋','宋诗','song-poetry','','[]','兜率宮中把不定，松山山裏借場開。',32,'全唐诗/poet.song.213000.json','["兜率宮中把不定，松山山裏借場開。", "普天匝地皆泥水，那更當生補處來。"]'),
('5e6dbec1-9a37-49b8-a15e-ab4271508f0f','偈頌一百六十九首  其七五','釋智朋','宋','宋诗','song-poetry','','[]','頭頂天，脚踏地。',80,'全唐诗/poet.song.213000.json','["頭頂天，脚踏地。", "聞鼓聲上來，減多少意氣。", "他殺不如自殺，參他不如參己。", "森羅萬像，是汝諸人知識。", "森羅萬像，是汝諸人自己。", "堪笑嵩山破竈墮，既是泥土合成，又要破也墮也。"]'),
('d8af45b9-84d6-444a-b031-076a09781c05','偈頌一百六十九首  其七六','釋智朋','宋','宋诗','song-poetry','','[]','金圈栗蓬，爐鞴鎔鎔。',28,'全唐诗/poet.song.213000.json','["金圈栗蓬，爐鞴鎔鎔。", "吞得透得，鈍鐵頑銅，百丈徒誇三日聾。"]'),
('e29f80d5-9647-4b76-841e-1cd4557a9c48','偈頌一百六十九首  其七七','釋智朋','宋','宋诗','song-poetry','','[]','分皮分髓誑盲聾，污却嵩山熊耳峰。',32,'全唐诗/poet.song.213000.json','["分皮分髓誑盲聾，污却嵩山熊耳峰。", "隻履携歸葱嶺去，賊身何處不相逢。"]'),
('0ce9f4b7-0205-4ae6-b35f-91390a91aa09','偈頌一百六十九首  其七八','釋智朋','宋','宋诗','song-poetry','','[]','透脫言詮，鐵山橫卧。',28,'全唐诗/poet.song.213000.json','["透脫言詮，鐵山橫卧。", "截斷言詮，通塗荒草。", "自小持齋今已老。"]'),
('8e178942-3bdf-459d-9fb4-f221d9c95b22','偈頌一百六十九首  其七九','釋智朋','宋','宋诗','song-poetry','','[]','鶯老花殘，春事已過。',60,'全唐诗/poet.song.213000.json','["鶯老花殘，春事已過。", "明眼衲僧，多是蹉過。", "楝花信風，不肯放過。", "萬戶千門，一時俱過。", "築著磕著，是誰之過。", "轉換不得，也要驗過。"]'),
('824ede82-f2f3-4a17-91b3-1be6aa58bae7','偈頌一百六十九首  其八○','釋智朋','宋','宋诗','song-poetry','','[]','杓柄人人入手來，莫隨顛倒自沉埋。',32,'全唐诗/poet.song.213000.json','["杓柄人人入手來，莫隨顛倒自沉埋。", "普天匝地無回互，黄面瞿曇出母胎。"]'),
('9aa4d160-b6cb-4720-b117-74cb886b0937','偈頌一百六十九首  其八一','釋智朋','宋','宋诗','song-poetry','','[]','九日無白醪，飽餐黄栗糕。',40,'全唐诗/poet.song.213000.json','["九日無白醪，飽餐黄栗糕。", "孤峰絕頂，兩眼彌高。", "不覺不知，忽然帽落。", "秋風惡，秋風惡。"]'),
('9d89c5bb-12b4-429c-8e52-acc7b3188d6d','偈頌一百六十九首  其八二','釋智朋','宋','宋诗','song-poetry','','[]','碌碌復碌碌，良馬白日足。',44,'全唐诗/poet.song.213000.json','["碌碌復碌碌，良馬白日足。", "咬定牙關，掀翻地軸。", "神不敢呵，鬼不敢哭。", "世尊入地獄，調達出地獄。"]'),
('670e693e-4c8e-49f4-bdf8-2e5ed241e72c','偈頌一百六十九首  其八三','釋智朋','宋','宋诗','song-poetry','','[]','入無窮，出無盡。',18,'全唐诗/poet.song.213000.json','["入無窮，出無盡。", "把定要津，頭正尾正。"]'),
('d579706f-1f1d-4af9-b3ba-e25c963ece30','偈頌一百六十九首  其八四','釋智朋','宋','宋诗','song-poetry','','[]','收則大地全收，展則大千俱覆。',24,'全唐诗/poet.song.213000.json','["收則大地全收，展則大千俱覆。", "黄面瞿曇，隠身無路。"]'),
('9fdf9cf6-c4b6-4cc4-b67a-978253e320be','偈頌一百六十九首  其八五','釋智朋','宋','宋诗','song-poetry','','[]','千聖頂𩕳打開，三塗地底把住。',33,'全唐诗/poet.song.213000.json','["千聖頂𩕳打開，三塗地底把住。", "是汝諸人鼻孔，總在山僧手裏，一時穿却。"]'),
('8e8c09ac-d88b-4e17-ba6e-acf5d8d8c778','偈頌一百六十九首  其八六','釋智朋','宋','宋诗','song-poetry','','[]','金剛圈，栗棘蓬。',22,'全唐诗/poet.song.213000.json','["金剛圈，栗棘蓬。", "識得衲僧公驗，便是造化爐中。"]'),
('9ca0bda0-f665-4f07-a268-abd3696cf3bb','偈頌一百六十九首  其八七','釋智朋','宋','宋诗','song-poetry','','[]','前峨嵋峰，後碧玉盤。',25,'全唐诗/poet.song.213000.json','["前峨嵋峰，後碧玉盤。", "一字字，一句句，且非草本相瞞。"]'),
('3be2f9a0-174e-4d38-b4f5-bdecaebf9628','偈頌一百六十九首  其八八','釋智朋','宋','宋诗','song-poetry','','[]','坐斷毗盧頂，不稟釋迦文，且在下風。',17,'全唐诗/poet.song.213000.json','["坐斷毗盧頂，不稟釋迦文，且在下風。"]'),
('a114734e-0a1a-484c-91b1-fd3bd3a03954','偈頌一百六十九首  其八九','釋智朋','宋','宋诗','song-poetry','','[]','雪竇頭上錐，脚下劄。',22,'全唐诗/poet.song.213000.json','["雪竇頭上錐，脚下劄。", "拍拍是令，成就一切世界。"]'),
('dbdfc6db-1562-4e96-8eca-a897be291f9e','偈頌一百六十九首  其九○','釋智朋','宋','宋诗','song-poetry','','[]','興化打克賓，種穀不生豆。',24,'全唐诗/poet.song.213000.json','["興化打克賓，種穀不生豆。", "雖然費栽培，也要人知有。"]'),
('dc9840a7-933d-433c-99c8-f8b5f153396c','偈頌一百六十九首  其九一','釋智朋','宋','宋诗','song-poetry','','[]','懸崖撒手，藉草眠雲，四方八面，移南作北。',49,'全唐诗/poet.song.213000.json','["懸崖撒手，藉草眠雲，四方八面，移南作北。", "佛祖不歷處，古今不到處，如何行履。", "三九二十七，籬頭吹觱栗。"]'),
('4761f1e8-8218-48dd-a9a9-835b404769d8','偈頌一百六十九首  其九二','釋智朋','宋','宋诗','song-poetry','','[]','旃檀林，獅子窟。',46,'全唐诗/poet.song.213000.json','["旃檀林，獅子窟。", "蹲坐不得處，正好翻身，片片煙消時，方堪拈出。", "不是心，不是佛，明眼衲僧莫輕忽。"]'),
('820e0858-1d01-4d6b-a998-7596ef877b4e','偈頌一百六十九首  其九三','釋智朋','宋','宋诗','song-poetry','','[]','吳宮煙冷水迢迢，當日齊腰雪未消。',32,'全唐诗/poet.song.213000.json','["吳宮煙冷水迢迢，當日齊腰雪未消。", "臘月今朝二十五，今朝未是拜年朝。"]'),
('1d3f2eb1-d882-470b-957f-57aafe093782','偈頌一百六十九首  其九四','釋智朋','宋','宋诗','song-poetry','','[]','歲之元，月之元，日之元。',59,'全唐诗/poet.song.213000.json','["歲之元，月之元，日之元。", "元正啟祚，萬彙發生。", "達磨西來，直指人心，見性成佛。", "一花開五葉，結果自然成。", "兩段不同，收歸上科。"]'),
('067f3bb9-4083-4898-a18c-4cb6e6471832','偈頌一百六十九首  其九五','釋智朋','宋','宋诗','song-poetry','','[]','坐一走七，橫三豎四。',30,'全唐诗/poet.song.213000.json','["坐一走七，橫三豎四。", "大力量人，全身擔負。", "普化鈴鐸，楊岐馿子。"]'),
('de21d9e5-1b2b-4ec7-bf50-58034a62562d','偈頌一百六十九首  其九六','釋智朋','宋','宋诗','song-poetry','','[]','自古及今，燈燈相續。',32,'全唐诗/poet.song.213000.json','["自古及今，燈燈相續。", "匝地普天，燈燈無間。", "助發實相義，今朝正月半。"]'),
('fca4735f-4447-40a3-8ef4-89307f33b13e','偈頌一百六十九首  其九七','釋智朋','宋','宋诗','song-poetry','','[]','當年一曲脫空歌，急水灘頭鳥作窠。',32,'全唐诗/poet.song.213000.json','["當年一曲脫空歌，急水灘頭鳥作窠。", "知是翻謄經幾手，沒誵訛處有誵訛。"]'),
('8ae9e387-3da9-46a0-a4be-bf075435b8e1','偈頌一百六十九首  其九八','釋智朋','宋','宋诗','song-poetry','','[]','寒則普天寒，熱則普天熱。',24,'全唐诗/poet.song.213000.json','["寒則普天寒，熱則普天熱。", "透出寒暑關，何曾離窠窟。"]'),
('bded7015-fe82-43bc-a429-7c30a6360a1e','偈頌一百六十九首  其九九','釋智朋','宋','宋诗','song-poetry','','[]','木落千巖，秋空如洗。',68,'全唐诗/poet.song.213000.json','["木落千巖，秋空如洗。", "向這裏轉得身去，可以移星換斗，轉位回機。", "百尺竿頭，纖塵不立。", "向這裏進得一步，殺活縱擒，縱橫自在。", "須彌無頂，滄海無底。"]'),
('13f1b2dc-d208-499d-860f-8379f49a7ce2','偈頌一百六十九首  其一○○','釋智朋','宋','宋诗','song-poetry','','[]','迦葉三昧，阿難不知。',36,'全唐诗/poet.song.213000.json','["迦葉三昧，阿難不知。", "聞名見面，劍去久矣。", "拽杷拖犂較後先，楊岐鼻孔沒半邊。"]'),
('7ccf6fa5-31ca-4964-b92a-fbc08e6dd6e6','偈頌一百六十九首  其一○一','釋智朋','宋','宋诗','song-poetry','','[]','人人自有光明在，看時不見暗昏昏。',31,'全唐诗/poet.song.213000.json','["人人自有光明在，看時不見暗昏昏。", "這箇豈不是光明，一一聞見分明。"]'),
('7a8fd569-6b92-48fa-a0a6-a4ca317a6b9a','偈頌一百六十九首  其一○二','釋智朋','宋','宋诗','song-poetry','','[]','天地發祥，聖人誕降。',66,'全唐诗/poet.song.213000.json','["天地發祥，聖人誕降。", "恩霑四海，德被萬邦。", "林下道人，坐則禪板蒲團，用則拄杖拂子，無非仰答聖恩。", "今日讚祝一句，又作麽生，此心心外更無心。"]'),
('72e9d33c-0d36-45d6-94ed-76a5df4a7c6f','偈頌一百六十九首  其一○三','釋智朋','宋','宋诗','song-poetry','','[]','田庫兒，甚奇怪。',74,'全唐诗/poet.song.213000.json','["田庫兒，甚奇怪。", "一下鋤頭，打破土塊。", "盡大地老和尚，髑髏粉碎，坐一走七，圓融內外。", "青松下，明窗內，玉殿瓊樓未爲最。", "分毫定斤兩。", "涓滴見滄海，拄杖子話在。"]'),
('dcb54621-bc8b-43fd-9e74-6b2f816ce918','偈頌一百六十九首  其一○四','釋智朋','宋','宋诗','song-poetry','','[]','三轉法輪於大千，其輪本來常清浄。',45,'全唐诗/poet.song.213000.json','["三轉法輪於大千，其輪本來常清浄。", "平江出燈道地，諸人盡知燈明。", "如來在諸人眼裏耳裏，轉如是輪。"]'),
('00af270e-c340-4ce5-912d-0db5a69f590a','偈頌一百六十九首  其一○五','釋智朋','宋','宋诗','song-poetry','','[]','虛空迸綻，山嶽起舞。',20,'全唐诗/poet.song.213000.json','["虛空迸綻，山嶽起舞。", "拔舌犂耕，罪惡俱露。"]'),
('82bd6b10-f1c8-4f20-afd6-bb4583271df3','偈頌一百六十九首  其一○六','釋智朋','宋','宋诗','song-poetry','','[]','真靈無功，功超造化。',55,'全唐诗/poet.song.213000.json','["真靈無功，功超造化。", "真聖無相，相包虛空。", "從權攝化，正按旁提。", "風行草偃，玉轉珠回。", "使人人向這裏飽食味法味，慚愧。"]'),
('29faef49-f7a1-46cc-98fe-51829caba2d5','偈頌一百六十九首  其一○七','釋智朋','宋','宋诗','song-poetry','','[]','看樓打樓，東湧西沒。',48,'全唐诗/poet.song.213000.json','["看樓打樓，東湧西沒。", "入水入泥，穿皮透骨，十字街頭石敢當。", "忽會轉身句，便笑遼天鶻，達磨大師眼睛突。"]'),
('b0f4d957-4196-4678-a901-82b9519ff953','偈頌一百六十九首  其一○八','釋智朋','宋','宋诗','song-poetry','','[]','無用之用，其用甚大。',40,'全唐诗/poet.song.213000.json','["無用之用，其用甚大。", "無功之功，其功甚博。", "自然如龍得水，似虎靠山，壺中春色異人間。"]'),
('50c4ec2f-c9af-4c89-a9da-f2c9f532a65f','偈頌一百六十九首  其一○九','釋智朋','宋','宋诗','song-poetry','','[]','爰從耳門，圓照三昧。',54,'全唐诗/poet.song.213000.json','["爰從耳門，圓照三昧。", "緣心自在，東倒西攂。", "異中現同，小中現大。", "只如不涉眼色耳聲，甚處與他相見，婺機羅，川紙會。"]'),
('adf31919-fb7b-4675-8148-b0568d109559','偈頌一百六十九首  其一一○','釋智朋','宋','宋诗','song-poetry','','[]','伶俐衲僧，討甚巴鼻。',41,'全唐诗/poet.song.213000.json','["伶俐衲僧，討甚巴鼻。", "著脚處寸草不生，著眼時佛祖掃地。", "且道以何爲據，不愛南山愛鱉鼻。"]'),
('9b433fc4-717f-48fa-b1fd-c80850b17dcd','偈頌一百六十九首  其一一一','釋智朋','宋','宋诗','song-poetry','','[]','毗藍園裏，活中覓死不可得。',36,'全唐诗/poet.song.213000.json','["毗藍園裏，活中覓死不可得。", "雙林樹下，死中覓活不可得。", "腦後一錐，是活是死。"]'),
('2281f17f-e0e6-4ea6-a048-e141b9cea3e3','偈頌一百六十九首  其一一二','釋智朋','宋','宋诗','song-poetry','','[]','南州北州，萬緒千頭。',74,'全唐诗/poet.song.213000.json','["南州北州，萬緒千頭。", "釣絲絞水，紙撚無油。", "鶴神飛上天，土宿騎黄牛。", "大海有十件奇特事，未曾說著。", "海底蓬塵起，千江水逆流。", "維摩丈室，有三萬二千獅子座，收。"]'),
('66d1c2ab-0921-41d1-b2fe-22c765c96519','偈頌一百六十九首  其一一三','釋智朋','宋','宋诗','song-poetry','','[]','放下身心，仁義禮智。',38,'全唐诗/poet.song.213000.json','["放下身心，仁義禮智。", "黄面瞿曇，撈天摸地。", "四月十五，喚作結制，東行不見西行利。"]'),
('98a2ec55-a8f0-4a25-9f58-d4383a8c9a2c','偈頌一百六十九首  其一一四','釋智朋','宋','宋诗','song-poetry','','[]','正不立玄，偏無所附。',42,'全唐诗/poet.song.213000.json','["正不立玄，偏無所附。", "三十年異類中行，末後句月圓古渡。", "夜船撥轉琉璃殿，白鳥飛宿無影樹。"]'),
('9f3f9109-69a3-4265-973e-07e1bd835f92','偈頌一百六十九首  其一一五','釋智朋','宋','宋诗','song-poetry','','[]','膚寸生層雲，已具瀰漫勢。',47,'全唐诗/poet.song.213000.json','["膚寸生層雲，已具瀰漫勢。", "盡矚晴空目，且非煙霧比。", "首座行脚，首座來也，落在第二。", "看看，雲行雨至。"]'),
('63985d93-73fb-4b4b-a2f7-a4bd7bf3e077','偈頌一百六十九首  其一一六','釋智朋','宋','宋诗','song-poetry','','[]','孤峰頂上無出身路，十字街頭亦無向背。',40,'全唐诗/poet.song.213000.json','["孤峰頂上無出身路，十字街頭亦無向背。", "臨濟老瞎禿，明州憨布袋。", "正令不行，東倒西攂。"]'),
('00c95903-81fc-4866-8583-cc794d4f8d14','偈頌一百六十九首  其一一七','釋智朋','宋','宋诗','song-poetry','','[]','平地起堆從古有，青天霹靂避猶難。',32,'全唐诗/poet.song.213000.json','["平地起堆從古有，青天霹靂避猶難。", "杖頭自有通方眼，風月一天非等閑。"]'),
('80b38b5d-4f36-4325-b87d-60d92a29ce1c','偈頌一百六十九首  其一一八','釋智朋','宋','宋诗','song-poetry','','[]','木骨金粧，似則也似。',20,'全唐诗/poet.song.213000.json','["木骨金粧，似則也似。", "瞬目揚眉，西天此土。"]'),
('3906fcea-5b56-4a8e-97e0-45ee328a545f','偈頌一百六十九首  其一一九','釋智朋','宋','宋诗','song-poetry','','[]','倒卓須彌，揭翻大海。',27,'全唐诗/poet.song.213000.json','["倒卓須彌，揭翻大海。", "魚龍變化，禽鳥懽呼。", "且放佛祖出頭。"]'),
('45072a0d-24d3-44fb-8150-3a76c7dd2970','偈頌一百六十九首  其一二○','釋智朋','宋','宋诗','song-poetry','','[]','象王行處，狐兔絕蹤。',20,'全唐诗/poet.song.213000.json','["象王行處，狐兔絕蹤。", "水月現時，風雲自異。"]'),
('9fb37af0-4311-4417-86f8-73104a957fc5','偈頌一百六十九首  其一二一','釋智朋','宋','宋诗','song-poetry','','[]','齊進退，正紀綱。',18,'全唐诗/poet.song.213000.json','["齊進退，正紀綱。", "提向上事，建光明幢。"]'),
('9107c07b-b217-4253-940a-279f6329d173','偈頌一百六十九首  其一二二','釋智朋','宋','宋诗','song-poetry','','[]','大方無外，大圓無內。',46,'全唐诗/poet.song.213000.json','["大方無外，大圓無內。", "是凡是聖，同此安居。", "淈淈𣸩𣸩，瞞瞞盰盰，富不足而樂有餘，是馬何曾喚作馿。"]'),
('a5c9551a-573c-40c1-a6d3-4060d051d038','偈頌一百六十九首  其一二三','釋智朋','宋','宋诗','song-poetry','','[]','立中就中，滲漏難盡。',48,'全唐诗/poet.song.213000.json','["立中就中，滲漏難盡。", "不見一法，始是半提。", "向上全提，諸佛諸祖。", "明不出，標不起。", "龍女獻珠，狼藉浄地。"]'),
('0f5b0a3b-20e1-426d-bc7b-c35224ce93d9','偈頌一百六十九首  其一二四','釋智朋','宋','宋诗','song-poetry','','[]','三處度夏，開拓封疆，眉毛在麽，抱贓叫屈。',32,'全唐诗/poet.song.213000.json','["三處度夏，開拓封疆，眉毛在麽，抱贓叫屈。", "柏山今夏，逢人不得錯舉。"]'),
('a494b30e-671e-4fd3-aa22-d0cd5f5c3644','偈頌一百六十九首  其一二五','釋智朋','宋','宋诗','song-poetry','','[]','三回四度，不曾入得徑山門。',33,'全唐诗/poet.song.213000.json','["三回四度，不曾入得徑山門。", "萬恨千愁，今日落在弟子手。", "只得歡喜忍受。"]'),
('34bbe22d-6ffa-4cc1-aa3a-6d873e077161','偈頌一百六十九首  其一二六','釋智朋','宋','宋诗','song-poetry','','[]','旃檀林，無雜樹。',38,'全唐诗/poet.song.213000.json','["旃檀林，無雜樹。", "拈出片片皆香，收來枝枝顯露。", "門頭戶底一等打開時如何，喫茶去。"]'),
('ccad2c2f-e5c3-4bba-8889-648b17d3cd04','偈頌一百六十九首  其一二七','釋智朋','宋','宋诗','song-poetry','','[]','一月普現一切水，一切水月一月攝，從上佛祖不出這影子。',50,'全唐诗/poet.song.213000.json','["一月普現一切水，一切水月一月攝，從上佛祖不出這影子。", "只今雨暗乾坤，月明如晝，衲僧眼目，瞞他一點不得。"]'),
('8906ce53-3453-4b21-be35-786293f91f59','偈頌一百六十九首  其一二八','釋智朋','宋','宋诗','song-poetry','','[]','柏山高，秋風高。',32,'全唐诗/poet.song.213000.json','["柏山高，秋風高。", "打失登山屐，吹落炙脂帽。", "應節應不及，登高登不到。"]'),
('0affd83d-a143-4671-a637-2283cde3baaa','偈頌一百六十九首  其一二九','釋智朋','宋','宋诗','song-poetry','','[]','造化寒暑，有來有往，衲僧火爐，有開有閉。',40,'全唐诗/poet.song.213000.json','["造化寒暑，有來有往，衲僧火爐，有開有閉。", "寒暑往來，火爐開閉。", "非實非虛，非如非異。"]'),
('220c9666-023a-4c08-bf78-f4aa288b75ef','偈頌一百六十九首  其一三○','釋智朋','宋','宋诗','song-poetry','','[]','散爲器者，乃道之漓。',46,'全唐诗/poet.song.213000.json','["散爲器者，乃道之漓。", "適於變者，乃法之弊。", "衲僧家，如何是事事無礙底句。", "濟北老禿兵，明州憨布袋。"]'),
('257ba784-7c47-4f05-8c94-dd5265ef2cf9','偈頌一百六十九首  其一三一','釋智朋','宋','宋诗','song-poetry','','[]','人天眼目，渥洼真産。',50,'全唐诗/poet.song.213000.json','["人天眼目，渥洼真産。", "踏殺天下人，今古何曾間。", "馬師不曾過去，衲僧自生隔遠。", "不隔遠，蜀旱不旱，蜀有彭漢。"]'),
('e94271d4-5ec9-4f8c-89ab-a0cb2a6ad047','偈頌一百六十九首  其一三二','釋智朋','宋','宋诗','song-poetry','','[]','依時及節，歲歲元正啟祚。',32,'全唐诗/poet.song.213000.json','["依時及節，歲歲元正啟祚。", "葭管灰飛，勾芒布令。", "春牛頭黄，歲稔年康。"]'),
('ef5d3bb5-9be3-4005-b876-a34d8eb8bb20','偈頌一百六十九首  其一三三','釋智朋','宋','宋诗','song-poetry','','[]','衲僧相見，或彼或此。',45,'全唐诗/poet.song.213000.json','["衲僧相見，或彼或此。", "水出龍宮，雲生嶽塢。", "壁立千仞放行，合水和泥把住。", "仁義道中是第幾句，舉。"]'),
('60984545-3eff-442c-b883-f576a969f958','偈頌一百六十九首  其一三四','釋智朋','宋','宋诗','song-poetry','','[]','雙林示滅誑何人，無際真空浄法身。',32,'全唐诗/poet.song.213000.json','["雙林示滅誑何人，無際真空浄法身。", "活向春風裏埋了，萬年千載不成塵。"]'),
('12583c0a-423c-44c8-93c9-6601fe5f6518','偈頌一百六十九首  其一三五','釋智朋','宋','宋诗','song-poetry','','[]','愛聖憎凡，蝸牛上壁。',57,'全唐诗/poet.song.213000.json','["愛聖憎凡，蝸牛上壁。", "凡聖情盡，獨鶴下田。", "向外馳求，鄉關轉遠。", "百尺竿頭進得一步，脚跟下正好一錐。", "如是我聞，一時佛在。"]'),
('54e69221-c9cc-4734-b54c-eca5af0ff1ec','偈頌一百六十九首  其一三六','釋智朋','宋','宋诗','song-poetry','','[]','罷拈金錫，七尺軍前。',60,'全唐诗/poet.song.213000.json','["罷拈金錫，七尺軍前。", "今春看又過，何日是歸年，辜負春山啼杜鵑。", "樊將軍向補陀山上禮觀音大士，不知不覺，在五臺峨嵋見文殊普賢。"]'),
('b825afc7-7ca7-4c64-a30c-e4a81e89be88','偈頌一百六十九首  其一三七','釋智朋','宋','宋诗','song-poetry','','[]','柏山小小叢林，安居九十日。',68,'全唐诗/poet.song.213000.json','["柏山小小叢林，安居九十日。", "五日不陞堂，隔日不入室。", "與麽承當去，已是拗曲作直。", "吹糠著米，無贓考賊。", "沛公鬭智，項羽鬭力。", "南無甚深般若波羅蜜。"]'),
('5cfa2ec6-d630-4ddb-b1de-eb5fff3323e7','偈頌一百六十九首  其一三八','釋智朋','宋','宋诗','song-poetry','','[]','護生殺生，遍界刀鎗。',38,'全唐诗/poet.song.213000.json','["護生殺生，遍界刀鎗。", "柏山結也如常，解也如常。", "如常恰似秋風至，無意凉人人自凉。"]'),
('2ca23733-f0c4-454d-985f-318bf8cf2a5b','偈頌一百六十九首  其一三九','釋智朋','宋','宋诗','song-poetry','','[]','草舍家風，少富多貧。',44,'全唐诗/poet.song.213000.json','["草舍家風，少富多貧。", "牙根齧定，七縱八橫。", "有爐無火燒殺人，有火無爐走殺人，說甚楊岐鬼眼睛。"]'),
('0572643e-9f27-4759-afd3-cb91be85237d','偈頌一百六十九首  其一四○','釋智朋','宋','宋诗','song-poetry','','[]','黄檗歸本位坐，陷虎機深。',46,'全唐诗/poet.song.213000.json','["黄檗歸本位坐，陷虎機深。", "保壽打推出僧，釣鰲力巨。", "一舉三山連，未稱全提處。", "把斷要津，輝騰今古。"]'),
('ab2f72a7-d119-4e10-826f-8ca8482cf976','偈頌一百六十九首  其一四一','釋智朋','宋','宋诗','song-poetry','','[]','人情濃厚道情微，道用人情世豈知。',77,'全唐诗/poet.song.213000.json','["人情濃厚道情微，道用人情世豈知。", "鹽鹹醋酸，阿誰不知。", "只要熟處放教生，生處放教熟。", "道用人情日久，自然打成一片。", "猶是蹲坐在浄地上，要得大方獨步，柏山與你草鞋。"]'),
('3150b91e-d213-44bf-8d63-00bf60459acc','偈頌一百六十九首  其一四二','釋智朋','宋','宋诗','song-poetry','','[]','七日來復，宮添一線。',44,'全唐诗/poet.song.213000.json','["七日來復，宮添一線。", "衲僧分上作麽生，石笋抽條，冰河發焰。", "柏山拄杖子，放一頭低，與你相見。"]'),
('12c02384-69f4-41a1-a6ec-07626f74224b','偈頌一百六十九首  其一四三','釋智朋','宋','宋诗','song-poetry','','[]','雪山中，夜半子。',41,'全唐诗/poet.song.213000.json','["雪山中，夜半子。", "眼見星，醜惡露。", "四十九年分疏不去，兒孫千古遭塗污，臘八年年是一度。"]'),
('0d56ab0e-53e6-407e-9207-4dab8eb40746','偈頌一百六十九首  其一四四','釋智朋','宋','宋诗','song-poetry','','[]','一棒一喝，疾雷破山，一提一唱，崩空峭壁。',41,'全唐诗/poet.song.213000.json','["一棒一喝，疾雷破山，一提一唱，崩空峭壁。", "諸佛傍觀有分，諸祖拈掇不出。", "只如入已還閉。"]'),
('38e0e26c-9463-48fb-9870-a3a7501de579','偈頌一百六十九首  其一四五','釋智朋','宋','宋诗','song-poetry','','[]','安居禁足，護生殺生。',28,'全唐诗/poet.song.213000.json','["安居禁足，護生殺生。", "無依倚處，百匝千層。", "柏山手裏有烏藤。"]'),
('233324f1-180e-415f-832b-398f58e2b59b','偈頌一百六十九首  其一四六','釋智朋','宋','宋诗','song-poetry','','[]','不知月之大小，不管歲之餘閏。',55,'全唐诗/poet.song.213000.json','["不知月之大小，不管歲之餘閏。", "黑牛卧死水，癩馬繫枯樁。", "三年一閏，五年載閏。", "衲僧須經得與麽時節過，方可成自己歲功。"]'),
('953605bb-e4d4-4825-b62e-37d9088d29da','偈頌一百六十九首  其一四七','釋智朋','宋','宋诗','song-poetry','','[]','門掩衰頹又暮春，這些病痛與誰陳。',32,'全唐诗/poet.song.213000.json','["門掩衰頹又暮春，這些病痛與誰陳。", "百城若有歸來者，方見文殊一臂伸。"]'),
('421ea58c-bde7-42c2-9b94-d7c265621303','偈頌一百六十九首  其一四八','釋智朋','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','如何望岱嶽，仁心普周被。',24,'全唐诗/poet.song.213000.json','["如何望岱嶽，仁心普周被。", "難與衲僧角，換却鬼眼睛。"]'),
('4dc1c7fc-8b60-4dae-bdbc-f24e7eb68fcc','偈頌一百六十九首  其一四九','釋智朋','宋','宋诗','song-poetry','','[]','歸源性無二，方便有多門。',64,'全唐诗/poet.song.213000.json','["歸源性無二，方便有多門。", "棒如雨點，喝似雷奔。", "衲僧門下，無著這破草鞋處，經律論又向什麽科中收。", "移高就下，有箇商量。", "白晝長，松風凉。"]'),
('7e691a7b-7ecb-42fe-a59d-89d9f37189e1','偈頌一百六十九首  其一五○','釋智朋','宋','宋诗','song-poetry','','[]','火就燥，水流濕。',57,'全唐诗/poet.song.213000.json','["火就燥，水流濕。", "問十答百，問一答十。", "達磨是甚老臊胡，臨濟未是白拈賊。", "今日爲汝一劃劃斷，且道既是冬瓜，爲什么夏裏喫。"]'),
('db8c5119-f924-4ed2-921f-7baa86c45e89','偈頌一百六十九首  其一五一','釋智朋','宋','宋诗','song-poetry','','[]','秋氣澄清，秋空如鏡。',38,'全唐诗/poet.song.213000.json','["秋氣澄清，秋空如鏡。", "萬籟沉寂，明月一輪。", "盡大地人徹曉競觀，不知昧却自己光明。"]'),
('439c9886-4ec0-4db9-a7b0-5164254f2495','偈頌一百六十九首  其一五二','釋智朋','宋','宋诗','song-poetry','','[]','德山棒，臨濟喝，拗曲作直。',44,'全唐诗/poet.song.213000.json','["德山棒，臨濟喝，拗曲作直。", "雲門餠，趙州茶，特地周遮。", "威音那畔，毫髮不差，山中是處有黄花。"]'),
('136268eb-df42-48f7-b084-792cc137ffe0','偈頌一百六十九首  其一五三','釋智朋','宋','宋诗','song-poetry','','[]','至尊至貴，無去無來。',20,'全唐诗/poet.song.213000.json','["至尊至貴，無去無來。", "體若虛空，迥絕安排。"]'),
('b423d0e6-83b6-4a9d-87af-d756778b406d','偈頌一百六十九首  其一五四','釋智朋','宋','宋诗','song-poetry','','[]','即心是佛，非心非佛。',40,'全唐诗/poet.song.213000.json','["即心是佛，非心非佛。", "東湧西沒，穿皮透骨。", "十字街頭，孤峰絕頂，是離窠臼，不離窠臼。"]'),
('af60aa78-59f2-45ea-94d5-3cb8a38c0b32','偈頌一百六十九首  其一五五','釋智朋','宋','宋诗','song-poetry','','[]','叢林聖制，有解有結。',20,'全唐诗/poet.song.213000.json','["叢林聖制，有解有結。", "透脫重關，紅爐點雪。"]'),
('93c206f5-caf7-419f-9e91-9120c7cae0fd','偈頌一百六十九首  其一五六','釋智朋','宋','宋诗','song-poetry','','[]','三脚馿，聖箭子。',44,'全唐诗/poet.song.213000.json','["三脚馿，聖箭子。", "放行則大地全收，收來則千差一舉。", "握土成金，握金成土。", "轉如是輪，不可量數。"]'),
('3dfe392a-91b2-4177-a49c-c28baa0b80a8','偈頌一百六十九首  其一五七','釋智朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','秋雲捲盡見晴空，瘦聳西湖千萬峰。',32,'全唐诗/poet.song.213000.json','["秋雲捲盡見晴空，瘦聳西湖千萬峰。", "水鳥樹林南宕寺，老胡曾未到其中。"]'),
('435acfff-2487-46f8-bf1a-34918f5ae301','偈頌一百六十九首  其一五八','釋智朋','宋','宋诗','song-poetry','','[]','貧到無錐，正好進步。',50,'全唐诗/poet.song.213000.json','["貧到無錐，正好進步。", "王舍城中，有條活路。", "一聲金錫，千門萬戶。", "全放全收，全賓全主。", "多寶如來，何曾過去。"]'),
('f433a266-fc17-48b7-8a86-d397c59e0bb9','偈頌一百六十九首  其一五九','釋智朋','宋','宋诗','song-poetry','','[]','會則一似等閑，不會則千難萬難。',48,'全唐诗/poet.song.213000.json','["會則一似等閑，不會則千難萬難。", "豈不見陶淵明採菊東籬下，悠然見南山。", "到這裏轉身有路，不妨入廛垂手。"]'),
('cfdeeadd-2f9f-48ba-89a9-fabb1a46fcd2','偈頌一百六十九首  其一六○','釋智朋','宋','宋诗','song-poetry','','[]','明頭暗合絕安排，莫厭紅塵撥不開。',32,'全唐诗/poet.song.213000.json','["明頭暗合絕安排，莫厭紅塵撥不開。", "不見當年分庵主，一聲江上侍郎來。"]'),
('3e9e87a6-c851-41bf-b8b8-213bc68d8f6d','偈頌一百六十九首  其一六一','釋智朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','溪山雖異，雲月是同。',28,'全唐诗/poet.song.213000.json','["溪山雖異，雲月是同。", "透脫聲色，任自西東。", "十里西湖九里松。"]'),
('14a3fcd5-3375-46f2-8fdf-ea7e09ddd9e4','偈頌一百六十九首  其一六二','釋智朋','宋','宋诗','song-poetry','','[]','把定乾坤正此時，衲僧猶未副全提。',32,'全唐诗/poet.song.213000.json','["把定乾坤正此時，衲僧猶未副全提。", "普賢不顧彌天罪，甘自渾身陷鐵圍。"]'),
('67417b52-b581-4b54-b47d-1734196e35c6','偈頌一百六十九首  其一六三','釋智朋','宋','宋诗','song-poetry','','[]','言之者失其真，知之者反其愚。',70,'全唐诗/poet.song.213000.json','["言之者失其真，知之者反其愚。", "有之者乖其性，無之者傷其軀。", "俊鷹摩霄，豈重雲能礙。", "六馬奔騰，豈朽索能繫。", "如其不然，轉身吐氣。", "久雨不晴，雲門道劄。"]'),
('04a13775-5714-4ede-b1ba-a508742d942c','偈頌一百六十九首  其一六四','釋智朋','宋','宋诗','song-poetry','','[]','信脚行，信口道，缺齒老胡，不是達磨。',33,'全唐诗/poet.song.213000.json','["信脚行，信口道，缺齒老胡，不是達磨。", "酸風刮地，泥團凍破，有什麽過。"]'),
('d6a7234e-690b-4969-9446-b05b6bdfb25f','偈頌一百六十九首  其一六五','釋智朋','宋','宋诗','song-poetry','','[]','通身是病通身藥，病去依前藥自除。',32,'全唐诗/poet.song.213000.json','["通身是病通身藥，病去依前藥自除。", "木落秋空山骨露，何須一默對文殊。"]'),
('0215c2c0-0d37-4b23-b88f-7492cea208a4','偈頌一百六十九首  其一六六','釋智朋','宋','宋诗','song-poetry','','[]','夜半明星，打失眼睛。',30,'全唐诗/poet.song.213000.json','["夜半明星，打失眼睛。", "胡人多詐，未可全憑。", "遭他冤害，始報不平。"]'),
('cc21d2c1-aef6-4a9c-acec-5c4319c422f4','偈頌一百六十九首  其一六七','釋智朋','宋','宋诗','song-poetry','','[]','西天此土，十萬餘程。',20,'全唐诗/poet.song.213000.json','["西天此土，十萬餘程。", "胡言易會，漢語難明。"]'),
('f0c6001e-990f-46cc-bb6e-721bdabe13a2','偈頌一百六十九首  其一六八','釋智朋','宋','宋诗','song-poetry','','[]','桃花水，榆莢雨。',18,'全唐诗/poet.song.213000.json','["桃花水，榆莢雨。", "一點忽來，千花競吐。"]'),
('85b20899-3b92-4af0-a930-cad35d103c4c','偈頌一百六十九首  其一六九','釋智朋','宋','宋诗','song-poetry','','[]','頭頂天，脚踏地。',57,'全唐诗/poet.song.213000.json','["頭頂天，脚踏地。", "開口喫飯，鼻孔出氣。", "死盡活，活盡死。", "百尺竿頭更進一步，未夢見衲僧巴鼻。", "達磨迢迢西來，葱嶺迢迢歸去。"]'),
('815290e4-865e-454e-974f-54d995f0c5ae','偈頌一百六十九首  其一七○','釋智朋','宋','宋诗','song-poetry','','[]','白首儒生困路歧，殘盃冷炙飽還饑。',32,'全唐诗/poet.song.213000.json','["白首儒生困路歧，殘盃冷炙飽還饑。", "一朝得意春風裏，便把馿兒作馬騎。"]'),
('7ed342c6-032f-4b65-9275-d0aa3febbb18','天衣生緣','釋智朋','宋','宋诗','song-poetry','','[]','烹金爐冷歲華更，此地曾經借路行。',32,'全唐诗/poet.song.213000.json','["烹金爐冷歲華更，此地曾經借路行。", "潮滿沙頭起寒雁，葛藤芽孽又重生。"]'),
('e18deb67-525f-4110-8ccd-4fb15d52ec92','拜明招塔','釋智朋','宋','宋诗','song-poetry','','[]','稍硬風頭早已乖，更歸暖處自沉埋。',32,'全唐诗/poet.song.213000.json','["稍硬風頭早已乖，更歸暖處自沉埋。", "翻令千古成蹤跡，枉喫羅山白飯來。"]'),
('2ea60042-387b-4dc2-9bb4-4598e021749d','水庵生緣','釋智朋','宋','宋诗','song-poetry','','[]','一宿分明不易投，老拳要覓死冤讎。',32,'全唐诗/poet.song.213000.json','["一宿分明不易投，老拳要覓死冤讎。", "不應荒却娘生也，自是無人敢出頭。"]'),
('a074499d-61ac-464b-9a0d-3c0285f9b636','拜明教塔','釋智朋','宋','宋诗','song-poetry','','[]','如說而行炳日星，回瀾一柱屹亭亭。',32,'全唐诗/poet.song.213000.json','["如說而行炳日星，回瀾一柱屹亭亭。", "湖邊安得磨崖石，只刻尊僧篇作銘。"]'),
('1a7fa8ba-d3d9-4169-b4ea-43e5038be35a','蘇谿牧護坐禪巖','釋智朋','宋','宋诗','song-poetry','','[]','當機突出鴨吞螺，奈此懸崖峭壁何。',32,'全唐诗/poet.song.213000.json','["當機突出鴨吞螺，奈此懸崖峭壁何。", "等是蘇谿蹲坐處，且非蒼檜影婆娑。"]'),
('8783628a-57e5-42e8-ae2c-1fd3441f0412','先羅漢塔','釋智朋','宋','宋诗','song-poetry','','[]','風幡影裏眼麻迷，爲是知音却不知。',32,'全唐诗/poet.song.213000.json','["風幡影裏眼麻迷，爲是知音却不知。", "畢竟礙膺除未得，寒松千古替傷悲。"]'),
('c95edb6d-32fa-497a-91fc-1d849a556edb','佛蹟','釋智朋','宋','宋诗','song-poetry','','[]','石火電光中出沒，崖崩石裂尚難酬。',32,'全唐诗/poet.song.213000.json','["石火電光中出沒，崖崩石裂尚難酬。", "放行一步還知不，佛是西天老比丘。"]'),
('33e8d002-8617-4c69-ba7e-283e3c96c47d','布袋脚跡石上現','釋智朋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','名與長江萬古流，當時狼藉若爲收。',32,'全唐诗/poet.song.213000.json','["名與長江萬古流，當時狼藉若爲收。", "脚跟只爲不點地，又涴橋邊塊石頭。"]'),
('9eb54b39-0890-43cd-a88e-a9f113943ce7','韜光庵','釋智朋','宋','宋诗','song-poetry','','[]','唐木猶存腹半空，蒼崖苔是舊時封。',32,'全唐诗/poet.song.213000.json','["唐木猶存腹半空，蒼崖苔是舊時封。", "雲隨十乘歸伊洛，月照年年湖上峯。"]'),
('430a7ee5-19c0-43c0-87ef-d345718d06a3','靈叟歸蜀','釋智朋','宋','宋诗','song-poetry','','[]','半生清苦衲無畦，惟有莎庭積雪知。',32,'全唐诗/poet.song.213000.json','["半生清苦衲無畦，惟有莎庭積雪知。", "眼带東南海色碧，莫和煙雨看峨眉。"]'),
('d27e95bb-9f13-4217-9255-2cdedfb3144f','鄙翁住菁山庵','釋智朋','宋','宋诗','song-poetry','','[]','糞火堆中不善藏，蹲鴟直透九重香。',32,'全唐诗/poet.song.213000.json','["糞火堆中不善藏，蹲鴟直透九重香。", "煙雲深鎖菁山塢，輒莫鐘聲送夕陽。"]'),
('f4276183-a7ce-499d-8c15-3ca5e1047d6e','鰲山接待','釋智朋','宋','宋诗','song-poetry','','[]','到得安眠飽飯中，東西南北路頭通。',32,'全唐诗/poet.song.213000.json','["到得安眠飽飯中，東西南北路頭通。", "三更夜半鬼嫁禍，莫著巖頭與雪峯。"]'),
('0902ffba-e424-4888-b968-3c78b3c2d9d8','題譙菴','釋智朋','宋','宋诗','song-poetry','','[]','歷觀嘉泰與開禧，禪苑宗壇更有誰。',32,'全唐诗/poet.song.213000.json','["歷觀嘉泰與開禧，禪苑宗壇更有誰。", "脩竹蒼松凜寒色，一如問道冷泉時。"]'),
