('cd03262d-48e9-4385-ae68-74772a1247a9','珙上人求','釋智朋','宋','宋诗','song-poetry','','[]','西風吹雨滿吳天，不犯竿絲一釣船。',32,'全唐诗/poet.song.213000.json','["西風吹雨滿吳天，不犯竿絲一釣船。", "寂寞要貪香餌味，江湖浮動幾蓑烟。"]'),
('b18f2894-3fb4-4015-b4e9-ea866b1614a4','了翁','釋智朋','宋','宋诗','song-poetry','','[]','先師公案强名模，不解深藏負累渠。',32,'全唐诗/poet.song.213000.json','["先師公案强名模，不解深藏負累渠。", "是我殺人便償命，如何年老解心孤。"]'),
('be8686e0-7875-4b98-a06a-99e321721eab','古鏡','釋智朋','宋','宋诗','song-poetry','','[]','不知經幾劫塵侵，元本形模莫辨明。',32,'全唐诗/poet.song.213000.json','["不知經幾劫塵侵，元本形模莫辨明。", "一片青銅銷得盡，無揩磨處始光生。"]'),
('3f6a06ff-cbcb-41fc-b708-8bd9a923356c','夢宅','釋智朋','宋','宋诗','song-poetry','','[]','六窗深閉大槐宮，一枕清風瞬息中。',32,'全唐诗/poet.song.213000.json','["六窗深閉大槐宮，一枕清風瞬息中。", "窮劫至今佛與祖，樓頭知是幾聲鐘。"]'),
('25d7f8c2-fee3-4b70-aa25-4d0f2279a6ce','幻菴','釋智朋','宋','宋诗','song-poetry','','[]','虛空迸裂海乾枯，人在漚花影裏居。',32,'全唐诗/poet.song.213000.json','["虛空迸裂海乾枯，人在漚花影裏居。", "合眼黄昏開眼晝，月明何許上珊瑚。"]'),
('3cca68b9-4381-46eb-845b-ac82788ec942','瞎翁','釋智朋','宋','宋诗','song-poetry','','[]','道得更無心外法，首山有眼且無光。',32,'全唐诗/poet.song.213000.json','["道得更無心外法，首山有眼且無光。", "拍盲枷棒揮將去，匝地普天興禍殃。"]'),
('c42e08de-afd0-48f7-9730-b1b86022e63f','古航','釋智朋','宋','宋诗','song-poetry','','[]','片帆不是等閑開，衝破洪波白浪堆。',32,'全唐诗/poet.song.213000.json','["片帆不是等閑開，衝破洪波白浪堆。", "眨上眉毛千萬劫，有誰洗脚上船來。"]'),
('1f7bce60-4fdf-4c61-8cc3-365a1d8c960a','壽秀王八十','釋智朋','宋','宋诗','song-poetry','','[]','道尊宗翰玉亭亭，益固維城重典刑。',32,'全唐诗/poet.song.213000.json','["道尊宗翰玉亭亭，益固維城重典刑。", "八十手扶靈壽杖，咸瞻南極老人星。"]'),
('26bd33df-c6ca-434d-9027-360f7f83cf80','隠室','釋智朋','宋','宋诗','song-poetry','','[]','文殊親到見非親，蹤跡渾無礙塞人。',32,'全唐诗/poet.song.213000.json','["文殊親到見非親，蹤跡渾無礙塞人。", "一丈方方遮障了，如何彈擊現全身。"]'),
('9e56d13b-5be3-4600-9ed0-54d2079d3d2f','出山相贊','釋智朋','宋','宋诗','song-poetry','','[]','子夜逾城，午夜見星。',36,'全唐诗/poet.song.213000.json','["子夜逾城，午夜見星。", "青天白日，大道不行。", "水泥脚下轉深深，究竟何曾得道成。"]'),
('afdb88da-2af1-49c8-85cb-a28beb419718','行道觀音贊','釋智朋','宋','宋诗','song-poetry','','[]','盡聞不住，業識忙忙。',28,'全唐诗/poet.song.213000.json','["盡聞不住，業識忙忙。", "空所空滅，遍界難藏。", "特地經行往那方。"]'),
('93d5dee2-1c9d-4fb7-9fd3-1ce7c1b84ba7','獅子相觀音贊','釋智朋','宋','宋诗','song-poetry','','[]','獅子國中，隨類度生。',34,'全唐诗/poet.song.213000.json','["獅子國中，隨類度生。", "盤石海潮，呵吼不停。", "要見真獅子兒，於斯觀其音聲。"]'),
