('22e92cf9-ee24-4af3-a886-5fbf56786b6a','觀音贊','釋智朋','宋','宋诗','song-poetry','','[]','十方圓明，應現非一。',32,'全唐诗/poet.song.213000.json','["十方圓明，應現非一。", "眼看浄瓶，坐盤陀石。", "楊枝入手時，一滴是一滴。"]'),
('eafef77e-95bc-4980-a2f1-4940202e0f29','踏蓮葉觀音贊','釋智朋','宋','宋诗','song-poetry','','[]','剎海無數，分身遍普。',32,'全唐诗/poet.song.213000.json','["剎海無數，分身遍普。", "蓮華葉上，如日卓午。", "應作如是觀，圓通二十五。"]'),
('44cc509a-9036-454a-ae6b-1fa3d7da7d9f','布袋和尚贊三首  其一','釋智朋','宋','宋诗','song-poetry','','[]','拖布囊，握烏藤。',18,'全唐诗/poet.song.213000.json','["拖布囊，握烏藤。", "街頭市尾，不是閑行。"]'),
('bbbe76e7-de1a-4ba4-9c11-50b3eac21f05','布袋和尚贊三首  其二','釋智朋','宋','宋诗','song-poetry','','[]','靠布袋作夢，有甚惺惺處。',24,'全唐诗/poet.song.213000.json','["靠布袋作夢，有甚惺惺處。", "若遇當行家，喚醒喫茶去。"]'),
('7f469eff-7b3d-4ea3-b87a-c89aba8ab414','布袋和尚贊三首  其三','釋智朋','宋','宋诗','song-poetry','','[]','一肩擔荷非輕，是什麽破落索。',28,'全唐诗/poet.song.213000.json','["一肩擔荷非輕，是什麽破落索。", "雖然顧後瞻前，不知打失樓閣。"]'),
('c1556ffa-e000-4de2-8019-f3698e9e50c7','渡蘆達磨贊二首  其一','釋智朋','宋','宋诗','song-poetry','','[]','江水無極，莖蘆可折。',28,'全唐诗/poet.song.213000.json','["江水無極，莖蘆可折。", "離了梁朝，未到魏闕。", "此恨波心向誰說。"]'),
('1791e254-61f6-4435-a7ba-b751bd91a850','渡蘆達磨贊二首  其二','釋智朋','宋','宋诗','song-poetry','','[]','破六宗邪，開五葉花。',20,'全唐诗/poet.song.213000.json','["破六宗邪，開五葉花。", "西天此土，地無硃砂。"]'),
('5188dd4c-d23b-47f1-b1b0-83e3802ebf00','豐干贊','釋智朋','宋','宋诗','song-poetry','','[]','跨猛虎去來，與寒拾來去。',32,'全唐诗/poet.song.213000.json','["跨猛虎去來，與寒拾來去。", "賊火不勘，自相訐露。", "謂是彌陀，有何憑據。"]'),
('30cdb7b4-9553-47aa-903b-4ee913c75f31','寒山贊','釋智朋','宋','宋诗','song-poetry','','[]','五字忍饑吟，十年忘歸路。',49,'全唐诗/poet.song.213000.json','["五字忍饑吟，十年忘歸路。", "著不著大笑，一場吐不出。", "相似底句，是真文殊。", "無二文殊，蘇盧㗭唎，㗭唎蘇盧。"]'),
('71718f7e-3f13-49d5-b3d0-73b5bdcae6a3','拾得贊','釋智朋','宋','宋诗','song-poetry','','[]','來無地頭，去有蹤跡。',46,'全唐诗/poet.song.213000.json','["來無地頭，去有蹤跡。", "笑不省是什麽意，掃不盡幾多狼藉。", "苦海無邊，行願無邊。", "喚作普賢，即非普賢。"]'),
('79496ba2-8933-4eb3-a61e-78eda01a54f6','寒拾贊','釋智朋','宋','宋诗','song-poetry','','[]','放下苕帚，對坐巖穴。',34,'全唐诗/poet.song.213000.json','["放下苕帚，對坐巖穴。", "眼看不亭，口說不歇。", "想得峨眉五臺，無此一天明月。"]'),
('ffd521df-9ee2-4e0b-8f4d-246cb4c4675c','船子和尚贊','釋智朋','宋','宋诗','song-poetry','','[]','不是輕舟蕩漾戲，一撓未展命如絲。',32,'全唐诗/poet.song.213000.json','["不是輕舟蕩漾戲，一撓未展命如絲。", "雙眸冏冏煙波外，伶利闍梨欲到時。"]'),
('e17327b7-576c-41a9-b5d7-8261e8544750','郁山主贊','釋智朋','宋','宋诗','song-poetry','','[]','拾得明珠笑口開，謂言塵盡轉塵埃。',32,'全唐诗/poet.song.213000.json','["拾得明珠笑口開，謂言塵盡轉塵埃。", "若無直下承當分，孤負馿兒一攧來。"]'),
('f0693fa4-02ac-483d-918f-20d452bfe575','政黄牛贊','釋智朋','宋','宋诗','song-poetry','','[]','江海歸來知幾年，却從牛背看風烟。',32,'全唐诗/poet.song.213000.json','["江海歸來知幾年，却從牛背看風烟。", "十成一轉倒跟語，萬象終難舉得全。"]'),
('d84c86de-f7e2-47f1-86a1-c4fefb92b347','朝陽穿破衲二首  其一','釋智朋','宋','宋诗','song-poetry','','[]','襤襂衣，能多少。',32,'全唐诗/poet.song.213000.json','["襤襂衣，能多少。", "破不盡，補不了。", "新羅夜半日輪紅，線路何曾穿得透。"]'),
('ec017da6-a783-470a-a48c-4e0a5fb6fc64','朝陽穿破衲二首  其二','釋智朋','宋','宋诗','song-poetry','','[]','骨相寒，毳寒衲。',26,'全唐诗/poet.song.213000.json','["骨相寒，毳寒衲。", "不朝陽，難提掇。", "正與麽時，大地火發。"]'),
('8e0f830d-6629-41bf-a6db-73578ed85fce','對月了殘經二首  其一','釋智朋','宋','宋诗','song-poetry','','[]','月在天，字在紙。',32,'全唐诗/poet.song.213000.json','["月在天，字在紙。", "於此經，了也未。", "口如鼻孔眼如眉，依前坐在光影裏。"]'),
('2dd59e6a-b73a-45d8-98c9-4874024567b6','對月了殘經二首  其二','釋智朋','宋','宋诗','song-poetry','','[]','心洞明，眼豁開。',26,'全唐诗/poet.song.213000.json','["心洞明，眼豁開。", "末後句，絕安排。", "未曾展卷，明月自來。"]'),
('228dcfd5-02e2-477e-a19c-ea887b3731ae','無準和尚贊','釋智朋','宋','宋诗','song-poetry','','[]','奮身鐵色，飛崖倒戈，欠蹄少角。',115,'全唐诗/poet.song.213000.json','["奮身鐵色，飛崖倒戈，欠蹄少角。", "得聵翁之聰而震忽雷，乘雲巢之雲而撒巨雹。", "遠若可親，邇而愈邈。", "拈死柴頭，煨文武火，而起龍宮之烈焰。", "以廣長舌，談真聖諦，而被天子之恩渥。", "或謂爲密庵破庵，跳籬驀墉之克家。", "豈知是脩水黄梅，寒霜冷燄之超卓者也。"]'),
('306e44dd-6d89-4485-a54f-39c71faf2677','大歇和尚贊','釋智朋','宋','宋诗','song-poetry','','[]','擔一字板，喪却生涯。',100,'全唐诗/poet.song.213000.json','["擔一字板，喪却生涯。", "見聵翁頂門有竅，識秘魔手裏無叉。", "霹靂震驚，幾蟄龍蛇。", "信手方圓，了無痕瑕。", "回垂天之雲翼，念寶林之故家。", "掃狐兔陸梁之區，輕重輸經界之際。", "俾檮陰永蔚，槁面生霞。", "若非鐵樹生花，安能如是耶。"]'),
('5a61273f-e5ca-4755-a77c-d03baa1d64ed','東坡贊','釋智朋','宋','宋诗','song-poetry','','[]','難將得喪動天常，儋耳安然似玉堂。',32,'全唐诗/poet.song.213000.json','["難將得喪動天常，儋耳安然似玉堂。", "來往借書仍借笠，不知雨步瘴烟鄉。"]'),
('bee4be6f-5d9a-4285-bf3a-70a611e56901','淵明贊','釋智朋','宋','宋诗','song-poetry','','[]','田園稔久已荒蕪，歸去來兮自荷鋤。',32,'全唐诗/poet.song.213000.json','["田園稔久已荒蕪，歸去來兮自荷鋤。", "眼底悠然見無見，黄花歲歲狀難如。"]'),
('c25c7fef-4e81-4b1c-b680-e3f0fdd64f0a','楊知府贊','釋智朋','宋','宋诗','song-poetry','','[]','丹成於太初之先，道濟乎後地之極。',57,'全唐诗/poet.song.213000.json','["丹成於太初之先，道濟乎後地之極。", "負勳名閥閲之寄，忘生長富貴之習。", "時行時止，無固無必。", "操須彌之筆，亦難寫此珪璋之質。"]'),
('a0f3bca7-3559-49e9-8f49-58ef07dbcd31','暮春即事','高斯得','宋','宋诗','song-poetry','','[]','皇天列四運，懿茲暮春熙。',108,'全唐诗/poet.song.213000.json','["皇天列四運，懿茲暮春熙。", "和風著萬物，觀物令心怡。", "如何魏晉後，詞人總淒淒。", "退之頗知道，及此尤傷悲。", "寧非遘淹留，嘆老還嗟卑。", "哀樂緣外感，安能識天時。", "不見魯中狂，陶然浴清沂。", "問渠樂何事，無言對春暉。", "人亡已千年，嘆息將安歸。"]'),
('af8b7a49-a41f-453b-9207-04fd789123a3','次韻王秉純投贈三十韻','高斯得','宋','宋诗','song-poetry','','[]','狂客寫孤憤，危詞戁戁憸。',288,'全唐诗/poet.song.213000.json','["狂客寫孤憤，危詞戁戁憸。", "秋巖露節角，春林掃穠纖。", "長鋏剚橫鰐，寸鐵刳妖蟾。", "赤子臨橫草，蒼生捐蓋苫。", "無衣可自蔽，有突何由黔。", "冽泉浸苞稂，白露摧蒼蒹。", "念此心怛怛，因之淚漸漸。", "誰能坐捫舌，聊欲一奮髯。", "百憂不易窮，千篇猶未饜。", "生氣凜不憊，死灰驚復炎。", "敢云寡鶴唱，尚欲神龍潜。", "拾遺愛薛孟，謫仙重王閻。", "相邀共夜話，快讀臨風簷。", "更闌堲頻折，樂極酒屢拈。", "國家正閑暇，上下方熙恬。", "賈誼枉流慟，桓侯笑鍼砭。", "無庸事吟諷，且復披湘縑。", "緬懷西方美，遐想虞庭僉。", "狂愚易搆禍，譏刺徒招嫌。", "舌出躬是瘁，戲言心如惔。", "且當阮籍醉，莫待申屠箝。", "及今不自悔，明神將汝殲。", "之子七步才，時命三年淹。", "江湖久放浪，虀鹽應饇懕。"]'),
('2fc6f32c-951f-4a27-add0-0f55e02306ac','送徐景說歸三衢','高斯得','宋','宋诗','song-poetry','','[]','秋風吐商氣，庭樹慽以飛。',156,'全唐诗/poet.song.213000.json','["秋風吐商氣，庭樹慽以飛。", "美人悼時節，去意不可鞿。", "朋陰傲排盪，晨光弄熹微。", "靈修豈敢怨，浩蕩終難依。", "岐分蹈一失，决此存亡機。", "僵株擢新稊，倏忽成十圍。", "陽阸人所願，蒼天詎能違。", "蹇予於夫子，亮節深所希。", "取舍既共是，排拫亦同非。", "豈伊桐江上，裴回送將歸。", "時危抱深感，人遠傷遐睎。", "國家福未艾，祖宗臨孔威。", "願子崇明德，桑榆借光輝。"]'),
('4b644358-5230-4ce3-83f0-f13e995044f3','思耕亭','高斯得','宋','宋诗','song-poetry','','[]','莘郊投耒興，六百奠殷祀。',181,'全唐诗/poet.song.213000.json','["莘郊投耒興，六百奠殷祀。", "南陽輟耰出，漢業僨還起。", "聖賢憂世心，秋月照寒水。", "彼哉植杖徒，長往見見何庳。", "我讀逸民傳，初訝子陵志。", "赤符燄方張，注想資共理。", "掉頭歸深山，繆洗巢父耳。", "六經凜刀尺，云乎不斯畏。", "反覆史氏詞，陵去良有以。", "維人驗進德，必於師友試。", "歷試猶夫人，成就安能偉。", "挽士亦既來，舍王寧得已。", "漢道汝不衡，先生可輕議。", "釣臺千萬篇，未有愜予意。", "賦詩題思耕，聊與發斯義。"]'),
('94a6df52-7b9b-454e-a0ae-366995b3ae2c','觴客海棠下以東坡詩紅萼是鄉人之句分韻予得絲字','高斯得','宋','宋诗','song-poetry','','[]','南國候傷早，東皇駕如馳。',120,'全唐诗/poet.song.213000.json','["南國候傷早，東皇駕如馳。", "月正未强半，紅紫皆離披。", "蜀花異凡品，作態能矜持。", "可憐多迫蹵，竟隨羣卉移。", "如彼市門女，狼籍施臙脂。", "又如賤錦工，忙擲梭中絲。", "匆匆不耐看，欲速將何爲。", "碧雞有佳人，睡足晨粧遲。", "含姿自愛惜，肯受春風欺。", "思之不可見，感事腸生悲。"]'),
('c2486fde-7a2e-4dd0-9efe-9642678b6d40','爲溫樂堂五綠亭解嘲','高斯得','宋','宋诗','song-poetry','','[]','園林非不佳，名字著難穩。',192,'全唐诗/poet.song.213000.json','["園林非不佳，名字著難穩。", "稍與流俗異，譏呵來噂噂。", "我堂名溫樂，竊慕涑水翁。", "我亭名五綠，又希午橋公。", "客來笑不已，誚我何其鄙。", "拳拳二相國，所愛人爵耳。", "聞之爲一咍，爭端自予開。", "嗟予信鄙矣，笑客亦愚哉。", "相誠吾所愛，何必裴與馬。", "唐非無李盧，宋亦有章蔡。", "爾知相何物，是謂聖賢宅。", "士而不爲此，何以下膏澤。", "孟軻出晝意，宣尼載質心。", "溫豈獨甘樂，裴非錮園林。", "二扁有深意，客詎窺其涘。", "吾言豈狂言，刀尺自孔氏。"]'),
('e0da9436-2374-4787-bc0f-4ab29bfbee0d','題黄巖蔡氏青在亭','高斯得','宋','宋诗','song-poetry','','[]','逢人說愛山，誰何是真愛。',144,'全唐诗/poet.song.213000.json','["逢人說愛山，誰何是真愛。", "苟無丘壑情，在眼猶不在。", "君看終南客，豈不卧興對。", "奈何心自盲，坐失煙霞態。", "蔡侯故靜者，肯與青山背。", "作堂老其間，列岫儼襟带。", "蘿月散庭隅，白雲屯戶外。", "疏櫺納遥碧，平几挹橫黛。", "青山信在茲，心鏡兩融會。", "豈效逋客徒，匿情紿松檜。", "咨余秉微尚，頗亦厭塵壒。", "幸君分半青，著我函丈對。"]'),
('51703f07-e78a-4661-b34a-41911bb76b98','遊巾山得晴字','高斯得','宋','宋诗','song-poetry','','[]','巾山何亭亭，拔地蹲中城。',144,'全唐诗/poet.song.213000.json','["巾山何亭亭，拔地蹲中城。", "蒼龍擢雙角，盤空鬭孤撐。", "崇雉儼環抱，兼如在滌牲。", "有時霽霧搴，插我堂東榮。", "雖勞拄笏望，猶賒杖藜行。", "值茲陽和候，鮮暉吐新晴。", "擺去纏牽累，少暢窺臨情。", "藉蘭得勝引，共此酒一盛。", "咏餘百憂集，樂極萬感生。", "去國魂難招，懷人涕易盈。", "雖無丘壑姿，宿昔芥塵纓。", "寄言山中叟，未慕同幽貞。"]'),
('78775e8a-452b-4dbb-a9a2-b30473a5e211','次韻徐景說見寄併呈牟存叟','高斯得','宋','宋诗','song-poetry','','[]','東南有華屋，結構清江濆。',288,'全唐诗/poet.song.213000.json','["東南有華屋，結構清江濆。", "規橅百年遠，庭宇無纖氛。", "前林蓺杞梓，後圃植蘭蓀。", "嘉賓日還往，門戶生精魂。", "雖慚北第壯，猶能植乾坤。", "主人遺後意，豈欲徒飽溫。", "相期大此屋，傳世垂無垠。", "人事一朝異，祖訓成仇冤。", "姦隸竊其柄，良朋中路捐。", "殖貨以自封，顧笑以爲歡。", "耳目就聾塞，誰其與忠言。", "不念乃祖心，望爾椒聊蕃。", "感激當世事，家國初無分。", "宗子誤置相，匪人轉洪鈞。", "癉善樹羣慝，痏國開亂原。", "權豪競叨懫，赤子愁吟呻。", "我室既盡毀，大盜將起吞。", "藐焉蟣蝨臣，埋輪承誤恩。", "睨冀不能擊，狐狸加霆震。", "撫己方自恧，顧指爲尤愆。", "百壬妄見猜，欲取棋枰翻。", "誰知孤臣心，但求王室安。", "舉目百嫫中，莫若二子妍。", "願識徑畈徑，更認存齊存。"]'),
('46af1ce7-d56b-450a-8451-32e94a6509b5','迓杜丞相檥舟白鶴山下有感','高斯得','宋','宋诗','song-poetry','','[]','維舟候新鉉，薄言憩茲山。',168,'全唐诗/poet.song.213000.json','["維舟候新鉉，薄言憩茲山。", "叢祠倚層阜，迴阡俯澄灣。", "竚立心目瞿，白鶴懸榜顔。", "嘉名契舊隠，身疑墮其間。", "沓嶂森古木，荒塗翳枯菅。", "田空少鴻鴈，谷腥富豺獌。", "更懷山中人，騎鶴去不還。", "平生抱炯介，輈張困羣姦。", "徂謝易永久，十年閟松關。", "紛吾信虛薄，宿昔蒙砭頑。", "及茲落海嶠，初心汩憂患。", "朅來因見召，感涕凄其潸。", "亦欲蔭青茆，賞心諒難攀。", "孤憤竟何及，顛毛自令䰔。"]'),
('64bd8178-d93c-4229-91ae-232b30d7105a','龜溪即事五首  其一','高斯得','宋','宋诗','song-poetry','','[]','頑雲蔀鶴嶺，積雪明龜溪。',72,'全唐诗/poet.song.213000.json','["頑雲蔀鶴嶺，積雪明龜溪。", "枌榆社已屋，斯焉卜幽棲。", "亦有好事人，除館溪之西。", "門巷寄深窈，青山有攀躋。", "平生秉微尚，頗忻詠歸兮。", "且可投吾簪，安能棲會稽。"]'),
('5814c963-c3ba-4c25-ba2d-fc6e2e3857fd','龜溪即事五首  其二','高斯得','宋','宋诗','song-poetry','','[]','父兄吳下宅，師友苕溪磯。',72,'全唐诗/poet.song.213000.json','["父兄吳下宅，師友苕溪磯。", "亦欲從之遊，喣濕相因依。", "暌孤諒無樂，旅瑣良可唏。", "古來遯世士，獨立取衆非。", "咨予匪能然，翼短難高飛。", "懷哉訂頑翁，示我真指歸。"]'),
('ae559d3b-1f0c-4c2c-addf-12a3a123d2f0','龜溪即事五首  其三','高斯得','宋','宋诗','song-poetry','','[]','王庭陟俊茂，三年蝨其間。',68,'全唐诗/poet.song.213000.json','["王庭陟俊茂，三年蝨其間。", "愚忠竟何補，積咎成丘山。", "媿彼海上漚，臨機鴥其飜。", "昭□□□□，嗟嗟亦胡顔。", "汝今尚無覺，復倚榮辱關。", "晨門獨何人，永。"]'),
('9bdc815f-644e-4ecf-bc20-f58df8fa8691','龜溪即事五首  其四','高斯得','宋','宋诗','song-poetry','','[]','二疏仕漢庭，才術相頡䀪。',72,'全唐诗/poet.song.213000.json','["二疏仕漢庭，才術相頡䀪。", "竝傳已云寵，同歸更輝光。", "蹇予與季父，碔砆而琳琅。", "不才自宜汰，顯斥庸何傷。", "處我嫌疑間，斯義安所當。", "潜聖譏鄰醯，焉廋渠肺腸。"]'),
('9526edeb-8644-412f-906f-f38d95591b59','龜溪即事五首  其五','高斯得','宋','宋诗','song-poetry','','[]','曩從太史氏，論次金匱書。',72,'全唐诗/poet.song.213000.json','["曩從太史氏，論次金匱書。", "龍興渡江後，麐止今皇初。", "微辭記當時，隻字寧敢虛。", "彼阿者誰子，顧欲私毀譽。", "陽秋記慕容，史記名山儲。", "二子亦過計，人心焉可誣。"]'),
('2466989a-6f6f-45b3-b24d-e675d6dd68f8','送不浮弟歸金陵','高斯得','宋','宋诗','song-poetry','','[]','分袂四百旬，盍簪三十日。',168,'全唐诗/poet.song.213000.json','["分袂四百旬，盍簪三十日。", "君來一何遲，君去一何疾。", "題彼原上鴒，飛鳴不相失。", "奈何緣薄宦，參辰各方一。", "我鬚盡成絲，君紒纔如栗。", "人生幾相見，歲月去如斥。", "兩蘇欠同歸，二陸事堪慄。", "天倫盎中薺，富貴劍頭蜜。", "崏下饒蹲鴟，吳中富仙朮。", "縱不死同丘，其可生異室。", "願君解龜後，休汝毋他適。", "建鄴水易滋，武昌魚多乙。", "急來共藜羹，蔭此青林密。", "春風棣華開，溪頭望歸鷁。"]'),
('df5c7665-49be-43a2-90ac-d190272f8b45','不浮次韻予亦再賦','高斯得','宋','宋诗','song-poetry','','[]','咨余運頹侵，非復少年日。',168,'全唐诗/poet.song.213000.json','["咨余運頹侵，非復少年日。", "嵇康既習懶，長卿又嬰疾。", "避客如避仇，俗子意多失。", "獨於聲氣同，迹兩心事一。", "糲飯盤菹芹，濁酒籩撰栗。", "家食雖清貧，尚有幣餘斥。", "每思世路巇，身不寒而慄。", "何如掩關卧，黑甜過崖蜜。", "覺來荷長纔，樂圃斸芝朮。", "末路值令弟，自遠造餘室。", "未久欲思歸，依人似高適。", "飛飛羽差池，秋鴈避春乙。", "可憐陸士衡，嗚咽送親密。", "橈音轉回塘，無由望文鷁。"]'),
('a8d9ed6b-acfc-48fe-bf2f-8e81a0289630','讀謝章奏疏賦朝陽吟','高斯得','宋','宋诗','song-poetry','','[]','岷峨禿如赭，江漢濁如泔。',192,'全唐诗/poet.song.213000.json','["岷峨禿如赭，江漢濁如泔。", "云何只隔夜，潑黛挼青藍。", "得非氣沆碭，祝融困西戡。", "秋風抗手謝，天公吾敢貪。", "此邦舊崛奇，神氣虎眈眈。", "山爲萬仞高，水作千尺涵。", "爾來遽一變，風景殊不堪。", "月墮雞不晨，露警鶴猶鼾。", "長畢綬若若，修緡府潭潭。", "坐令死瓦色，空濛亙西南。", "劃聞卷阿奏，翠鳳鳴孤嵐。", "尹氏誰敢指，家父獨縱談。", "三十六峰下，有此奇偉男。", "戛摩參井燄，剗磢山川慙。", "予方感嫠緯，耳此距躍三。", "作歌爲賈勇，罪我如飴甘。"]'),
('b689325b-2ebd-4ca9-8bb1-6bbd4eafa4a5','吏道','高斯得','宋','宋诗','song-poetry','','[]','勞牽迫吏道，僒若洪縻拘。',108,'全唐诗/poet.song.213000.json','["勞牽迫吏道，僒若洪縻拘。", "九春回塵土，一迹園林無。", "直此休沐暇，偕我良知娛。", "殘梅謝衆卉，初柳荑僵株。", "四運巧相斥，流目悲榮枯。", "俯仰潺湲沫，惻耳彌驚吁。", "故山渺何在，漱石良辰徂。", "爲邦歲已朞，宣城可歸與。", "執柯勿睨視，州有達士模。"]'),
('77441994-534d-4276-acba-fbea7d1364c8','物貴','高斯得','宋','宋诗','song-poetry','','[]','一從泉法亂，都野咸荒荒。',144,'全唐诗/poet.song.213000.json','["一從泉法亂，都野咸荒荒。", "片楮母偏重，無子相低昂。", "姦人竊其權，百物因大翔。", "握薪重尋桂，尺魚貴河魴。", "我聞輦轂下，鞅法牛毛詳。", "物物揭成價，大字懸康莊。", "膴鮑榷公肆，餠師聚官場。", "市易祖嘉問，均輸肖弘羊。", "罻羅四面布，摇手觸刑章。", "哀哉今之人，逢時何不祥。", "穀斛八錢漢，米斗三錢唐。", "安得生其時，鼓腹詠太康。"]'),
('ab6121f3-055f-4865-86bb-3d96b8cff71e','增賦','高斯得','宋','宋诗','song-poetry','','[]','吾哀天寶後，刻剝窮錐刀。',96,'全唐诗/poet.song.213000.json','["吾哀天寶後，刻剝窮錐刀。", "豆實不得喫，蕨賣輸官曹。", "民生於斯時，生意如鴻毛。", "安知咸淳際，赤子滋嗸嗸。", "稅租責三倍，田野晨號咷。", "柔桑稊未茁，調帛已騷騷。", "驕兵飫醲鮮，黎民窄糠糟。", "九關虎豹守，哀籲愁天高。"]'),
('e1eeca5d-72b5-44fa-8461-53ca0df31f2a','桑貴有感','高斯得','宋','宋诗','song-poetry','','[]','我老與時忤，十年守窮空。',168,'全唐诗/poet.song.213000.json','["我老與時忤，十年守窮空。", "衣食相驅迫，遂師田舍翁。", "每當春蠶起，不敢怠微躬。", "晨興督家人，留心曲箔中。", "客寓無田園，專仰買桑供。", "豈謂桑陡貴，半路哀塗窮。", "三百變三千，十倍價何穹。", "家貲已典盡，厥費猶未充。", "乃知楮法壞，流毒刀兵同。", "蒼天此何人，血面訴難通。", "棄蠶滿阬谷，行當歌大東。", "預憂兒女曹，凜洌當嚴風。", "我窮何足道，四海關吾胸。", "赤子已露立，視天猶夢夢。"]'),
('d2c49efb-f3cb-4318-85d4-4d57b7bb2479','劫桑嘆','高斯得','宋','宋诗','song-poetry','','[]','美哉豳郊道，風日清且熙。',168,'全唐诗/poet.song.213000.json','["美哉豳郊道，風日清且熙。", "條桑紛冉冉，采蘩復祁祁。", "盛時不可再，亂世誠堪悲。", "守令既闇懦，兇黠何紛披。", "千林非無主，奪攘無孑遺。", "白刃鬭原野，長乂守路垂。", "羸童擁樹泣，弱隸空籃歸。", "更憐貧家女，束手看蠶饑。", "爾蠶何不幸，生此叔季時。", "千筐與萬箔，委棄如京坻。", "昔聞花門亂，倒麥折桑枝。", "幸無風塵警，氣象胡爾爲。", "天門萬里遠，吾君那得知。", "恨無古膚使，觀風采吾詩。"]'),
('1a531782-9663-4f0f-8ddb-c206953e84f1','次韻不浮問疾末章及蝗','高斯得','宋','宋诗','song-poetry','','[]','卧疴連夏秋，爾來收藥喜。',168,'全唐诗/poet.song.213000.json','["卧疴連夏秋，爾來收藥喜。", "羣腴久嚼蠟，今始甘魴鯉。", "自非天矜憐，安得吉祥止。", "寄聲問何如，感此遠方弟。", "炯然憂愛心，諄諄見詞旨。", "兼饋藥籠珍，廢疾居然起。", "末章悼飛蝗，布陣長千里。", "那知自北來，今亦徧苕水。", "公田吏如虎，收拾無滯穗。", "訴傷服大刑，遑哀室如燬。", "古來此亂國，赤子先遭棄。", "北橋千萬倉，何翅敖洛峙。", "一粒不肯捐，肯念饑由己。", "謹勿傳吾詩，隙間天螻記。"]'),
('413bf7f5-284b-4b9e-ad3b-9dd3a841741c','題錢可則芡雪庵','高斯得','宋','宋诗','song-poetry','','[]','我家雪山下，結茅幾度秋。',132,'全唐诗/poet.song.213000.json','["我家雪山下，結茅幾度秋。", "一朝劫火燎，身墮江南州。", "相逢芡雪君，感慨不能休。", "我今如喪狗，狂走長包羞。", "子幸成小築，廊巖可夷猶。", "何不學孔明，草廬傲王侯。", "何不學袁安，高卧絕行輈。", "鵷鸞恍入夢，猿鶴悽生愁。", "逋客亮非然，誰其執怨仇。", "山茅自高潔，得雪逾清修。", "三白待君足，毋爲垢氛留。"]'),
('a482f428-38e0-429d-bae1-e5cc0ff455c3','酒闌','高斯得','宋','宋诗','song-poetry','','[]','世道日淪忽，涔淚夜中滋。',228,'全唐诗/poet.song.213000.json','["世道日淪忽，涔淚夜中滋。", "客問子何傷，傷予士氣痿。", "不見齊魯鬨，所爭在糟醨。", "我吻燥已久，幸歌韓奕詩。", "若遭禁酒國，曹瞞爾何爲。", "一鏖臯蘭下，赤壁竟不支。", "雖云竟不支，主翁自憐之。", "騎虎不敢下，悲鳴亦可嗤。", "朝廷盡君子，拄撐頼公師。", "似此好局面，諸生願扶持。", "尹京用老蔡，恐飜元祐規。", "斯言是耶非，識者當能知。", "啞鐘懸清廟，瘖虎伏路垂。", "此而爲君子，小人當謂誰。", "幣輕物痛躍，赤子命一絲。", "尚曰此元祐，天乎欲誰欺。", "醪粲恩誠深，報復機誠危。", "獨哀三百年，豢此終何裨。", "咸幡不復舉，志士徒傷悲。"]'),
('8f64151d-0971-4606-b904-053d762f8b49','蜀酒','高斯得','宋','宋诗','song-poetry','','[]','我辭相國歸，遺我酒十器。',72,'全唐诗/poet.song.213000.json','["我辭相國歸，遺我酒十器。", "拜受起潸然，爲上有蜀字。", "狐狸之所嘷，種秫寧有地。", "得非父兄血，或是鄉人淚。", "我飲不下咽，思廣相國賜。", "願得投岷江，咸使西南醉。"]'),
('c8df6d75-876e-4449-b32f-53d6986e0dfa','端午日觴客東湖遇雨移飲壽台樓分韻得壁字','高斯得','宋','宋诗','song-poetry','','[]','玄暉東田遊，明遠東城歷。',120,'全唐诗/poet.song.213000.json','["玄暉東田遊，明遠東城歷。", "深心慕塵軌，湖舷擬觴客。", "零雨或尼之，輟策駢茲席。", "霽虹带高岑，傾羲被迴陌。", "良知共遐睎，數陪竹林七。", "境恬微尚愜，賞勝幽懷適。", "懷沙事千載，舊恨猶能闢。", "延首瞻樓顔，新愁渺難釋。", "天問愧非才，且可浮大白。", "徙倚驚漏窮，晨宵挂東壁。"]'),
('6c1f0295-ed3b-4e1c-a341-f556b800405c','贈道士劉友鶴','高斯得','宋','宋诗','song-poetry','','[]','翰林紛萬族，白鶴稱善鳴。',96,'全唐诗/poet.song.213000.json','["翰林紛萬族，白鶴稱善鳴。", "標榜在詩易，斯義淵然精。", "子今自羽客，復慕胎僊名。", "烟熅吐奇訊，警露爭圓清。", "平臯播馨蘭，廣隰蔭芳苓。", "於焉事飛薄，安得有惡聲。", "聾俗詎知我，胡爲枉攖情。", "帝鄉闊萬里，短羽無遐征。"]'),
('ee4d55f3-e1c4-49ea-a106-4467fc9cd48c','讀哲宗長編','高斯得','宋','宋诗','song-poetry','','[]','我於咸淳際，偶讀紹符編。',168,'全唐诗/poet.song.213000.json','["我於咸淳際，偶讀紹符編。", "昏氣塞宇宙，臨文深慨然。", "孽惇暴於虎，泰陵度如天。", "惇言一脫口，輒奉以周旋。", "嘯呼盡頑兇，排斥咸忠賢。", "意偏覆轍蹈，時移善政還。", "濟惡蔡元度，推波曾子宣。", "紀綱耳目地，悉以私人專。", "其間如商英，牙吻尤呀然。", "神靈不可測，黨人得生全。", "矧乃崇觀後，於邑更堪言。", "孝弟堯舜道，禍反階中天。", "聖經豈誤人，無乃說用燕。", "孤臣淚迸血，後來其監旃。"]'),
('2e54f8c1-bb2a-4dca-8984-c767707e5d45','近者昌言多出諸賢之後有感一首','高斯得','宋','宋诗','song-poetry','','[]','吾觀唐虞時，輔佐多世胄。',144,'全唐诗/poet.song.213000.json','["吾觀唐虞時，輔佐多世胄。", "一時謀謨嘉，十世典刑舊。", "古道日以衰，象賢始不懋。", "近者梧桐鳴，多出芝蘭秀。", "杜李倡其前，劉胡繼其後。", "最後康樂公，卓出漢庭右。", "元氣倚迓續，疵國資匡救。", "起予氣爲增，感事眉復皺。", "彼出進士科，視此一何陋。", "但貪一束芻，甘作三緘味。", "真堪爲僕僮，尚敢矜廉茂。", "誰能持我詩，往爲披怐瞀。"]'),
('a520dd21-07da-45a8-8f43-41f4adf38095','生日自嘲','高斯得','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','今朝出門去，路逢揶揄子。',120,'全唐诗/poet.song.213000.json','["今朝出門去，路逢揶揄子。", "汝形何龍鍾，汝色何顦顇。", "人皆鑽當路，汝獨鑽故紙。", "故紙高泰山，不直一杯水。", "當路衆所趨，汝獨無一字。", "玉堂炳宮燭，金華曳絲履。", "珥筆立螭頭，屬車陪豹尾。", "世人共歆羨，汝乃獨掩鼻。", "七十不回頭，汝亦自苦耳。", "抗手謝少年，吾今將仕矣。"]'),
('7f47f612-0100-482e-ab3e-3a31aaa0159d','次韻俞掞縣尉見贈釣臺賦梅','高斯得','宋','宋诗','song-poetry','','[]','嚴風摺繁圃，嘉卉難爲香。',108,'全唐诗/poet.song.213000.json','["嚴風摺繁圃，嘉卉難爲香。", "坐令衆芳林，直爲蕭艾鄉。", "妖紅與嫚紫，乘時鬭新粧。", "梅生處扃外，皭然絅衣裳。", "獨無摧折憂，一笑春洋洋。", "猶懷臭味感，苦口嗟難嘗。", "風人妙託物，予德慚菲涼。", "坡公詎爲役，涪翁可齊芳。", "尚此短兵接，當君陣堂堂。"]'),
('a352ee20-8c08-4f0e-85c5-4e81afba2cc9','齒落','高斯得','宋','宋诗','song-poetry','','[]','韓公四十五，已賦齒落詩。',96,'全唐诗/poet.song.213000.json','["韓公四十五，已賦齒落詩。", "呀然頓崩弛，存者皆浮危。", "我今恰半百，衰暮固其時。", "一齒闕當門，摵其秋葉飛。", "感茲生有涯，撫枕中夜悲。", "伊人未聞道，文與百世期。", "吾今食粟耳，將隨野草萎。", "聖路千萬里，加鞭猶可遲。"]'),
('1e5b2cec-aa13-449f-99d9-e46b8560272a','次韻功遠兄惠詩見勞','高斯得','宋','宋诗','song-poetry','','[]','平生聞父師，擇術明諾諤。',264,'全唐诗/poet.song.213000.json','["平生聞父師，擇術明諾諤。", "豈不依德言，其奈根器弱。", "昕庭開獸樽，坐聽諸臣咋。", "誰其酌嘗之，自牖勤納約。", "維時鶴山翁，鐵作元祐脚。", "振鬣一以鳴，萬馬立皆却。", "此老埋虎丘，自頃氣何索。", "徽音闋不嗣，吾儕得無怍。", "偶從鋒鏑餘，來被纓組縛。", "每懷季父風，自笑吾痹惡。", "十駕希乘黄，其敢自菲薄。", "啾啾竟何裨，有如叢間爵。", "那知桓將軍，早已憚孫綽。", "鴥彼韝上鷹，掣臂將汝攫。", "何不追冥鴻，幡然見幾作。", "會逢故人劉，危言取眙愕。", "腥庮忌雕胡，薋菉妬芳若。", "遂仇作俑人，意欲屏醫藥。", "樂哉餘不亭，閑身頗堪著。", "寒谿靜可鑒，青山崒如削。", "未能及黎侯，且可棲晉鄂。", "憑誰共行藏，歸語故山鶴。"]'),
('a699eb11-d2be-447c-b403-fdadcfa89417','贈蜀僧欽師','高斯得','宋','宋诗','song-poetry','','[]','天台招提藪，我常避其塵。',96,'全唐诗/poet.song.213000.json','["天台招提藪，我常避其塵。", "夫豈無名緇，近膩終汗人。", "衲子來西州，見之獨情親。", "豈惟枌社意，亦喜叢林聲。", "欽公惜我去，索贈良殷勤。", "子道我弗學，安能淑而身。", "雖然第一義，儒釋曾何分。", "要踏石頭路，須還鐵脚根。"]'),
('9adce7df-9cce-4d29-87ce-5f748b923467','次韻李通甫賦中秋','高斯得','宋','宋诗','song-poetry','','[]','秋容滿苕谿，天籟生菌閣。',144,'全唐诗/poet.song.213000.json','["秋容滿苕谿，天籟生菌閣。", "幽懷對蕭辰，意味更沖泊。", "招朋傾一盛，相與慰牢落。", "抵掌談世事，亦可資一噱。", "須臾白玉盤，高掛青綃幙。", "賞心與景會，喜極悲還作。", "渺然望西南，慨想舊猿鶴。", "豈無首丘情，歸去事耕鑿。", "奈何朝廷上，聚鐵方鑄錯。", "棄置勿復道，洗盞更深酌。", "我老倦吟詩，無悰紀行樂。", "故人詩筒來，晨簷有鳴鵲。"]'),
('17b1654f-ab3d-4628-a0fc-95dca08bed1f','送劉養源遊吳中','高斯得','宋','宋诗','song-poetry','','[]','自我識松澗，于今二十年。',144,'全唐诗/poet.song.213000.json','["自我識松澗，于今二十年。", "譬彼鴻與虬，薄霄而棲川。", "憶昔初見時，予客劉養源。", "邂逅一相遇，松澗稱其賢。", "蹇予久騷屑，養源亦蕭然。", "携家輦轂下，炊玉斗萬錢。", "貸粟監河侯，蓋爲生事牽。", "訪予苕之濱，欲學東方先。", "率然集吳地，求汲松澗泉。", "予謂子往矣，轍鱗今復鮮。", "杜陵送李君，南入黔中天。", "應爲汧公醉，剩操雲嶠篇。"]'),
('7f60efcb-a1ed-49c7-b021-1cd6bb1f8550','次韻不浮和東坡端午遊真如寺','高斯得','宋','宋诗','song-poetry','','[]','君居秣陵時，日夜書旁午。',120,'全唐诗/poet.song.213000.json','["君居秣陵時，日夜書旁午。", "念我方投閑，遠方同甘苦。", "別來日月長，如髮不可數。", "弟兄兩浮萍，功名一炊黍。", "相逢飲佳節，小慰情悽楚。", "東坡舊公案，君房妙言語。", "乃翁滿腹書，一字不堪煮。", "晚歲膝上君，端能繼華祖。", "我已困屠龍，君應思畫虎。", "相期寸田耕，心亨無齟齬。"]'),
('2adc4e87-a7c9-47cd-8e14-d93f81433503','平生欲一遊金陵而不得再用韻簡不浮','高斯得','宋','宋诗','song-poetry','','[]','金陵帝王州，遺事多典午。',120,'全唐诗/poet.song.213000.json','["金陵帝王州，遺事多典午。", "我昔讀其書，撫卷輒凄苦。", "一時豪傑士，錯出可勝數。", "榮名既銷歇，陳迹付離黍。", "惟有東山翁，于今尚翹楚。", "我欲一訪之，千載同晤語。", "酒於白下酌，茗向鍾山煮。", "北道有主人，載酒思出祖。", "但畏傍人譏，率野非兕虎。", "此事從昔然，非予獨齟齬。"]'),
('5bbdf8f2-f5b3-42b6-a4fd-198f65497d8c','不浮欲卜居霅川而未决再用韻趣之','高斯得','宋','宋诗','song-poetry','','[]','君如夏日槐，濃陰正亭午。',120,'全唐诗/poet.song.213000.json','["君如夏日槐，濃陰正亭午。", "我如秋渚蓮，心老味加苦。", "卜居既未果，會面真堪數。", "二米同一稃，何時如秬黍。", "我今居異邦，一齊咻衆楚。", "出門無所詣，欲話誰晤語。", "盍念荆同生，毋憂豆逢煮。", "急來共伏臘，相與續妣祖。", "昔人兄弟多，八龍及三虎。", "安有予二人，而堪長齟齬。"]'),
('acd9e217-74d3-4e91-a678-06817b9d91ed','不浮弟攝興國守書趣其歸','高斯得','宋','宋诗','song-poetry','','[]','自君攝富川，政聲達王畿。',180,'全唐诗/poet.song.213000.json','["自君攝富川，政聲達王畿。", "鄉邦大夫士，相率聯書馳。", "欲控江州督，版授俾真爲。", "羣來質於予，予則力止之。", "父兄本公論，彼反疑爲私。", "諸公悵然去，未免方輪嗤。", "日者召書來，自言攝承朞。", "駑馬戀短豆，或者能無譏。", "累牘上尚書，願趣新侯來。", "白頭分趨幕，不敢求旌麾。", "開書喜見面，與我同肝脾。", "高安別未久，德進兄嗟咨。", "我今亦復然，坡潁真吾師。", "雖無逍遥堂，遲君同賦詩。", "已掃安樂窩，扁舟早來歸。"]'),
('2855328d-8457-4dcf-b4f9-7f7e1e1d13f7','次韻王深道領客登翠屏','高斯得','宋','宋诗','song-poetry','','[]','東皇趣歸旆，行色在隴麥。',120,'全唐诗/poet.song.213000.json','["東皇趣歸旆，行色在隴麥。", "撫舊念易盈，感逝憂難釋。", "謂春姑徐驅，爲我咏今夕。", "天涯浩漫漫，迷路那可索。", "林芳坐自銷，庭草已如積。", "南亭慨靈運，東園悲阮籍。", "咨余畏簡書，無路追羣屐。", "故知凝睇處，惟見嵊尖碧。", "如邛欠宿願，入越成誤適。", "一笑命淥樽，人生匪金石。"]'),
('32e9c8ec-ea9e-44f5-8793-a8fdee93d0ab','題王茂悅郴州白水奇清園','高斯得','宋','宋诗','song-poetry','','[]','靈區有異産，化國無潜珍。',264,'全唐诗/poet.song.213000.json','["靈區有異産，化國無潜珍。", "坡公論人物，我則賦奇清。", "壯哉此白水，誰其瀉青冥。", "薶藏富媼嗇，抉剔天公嗔。", "霹靂起神物，贔屭擘巨靈。", "陽山得瀑谷，永嘉頼斧斤。", "乃知出世事，須待開物人。", "倒懸訝瑶池，吹立驚滄溟。", "千穗落曉鏡，萬仞垂天紳。", "清寒入山骨，霏潤霑人巾。", "麕麕爲瘦爽，草木皆堅貞。", "臞仙挹瓢飲，俗士湔塵纓。", "度堂匪秩讌，築館先儲英。", "函書靜秩秩，子佩來瘽瘽。", "清風濂溪像，古柏文翁庭。", "從容講道要，宛轉餘詩情。", "謫仙一派妙，休文八詠新。", "茲惟佳山水，我嘗駐騏駰。", "平湖尚蕪漫，絕境宜荆榛。", "按圖重嘅嘆，歲月今崢嶸。", "壯觀誇好句，窘步欹豐擎。", "聊以贈我友，無庸寄山神。"]'),
('11b99c14-09a0-4a82-b4da-fd097eee4b9e','書室揭劉元城陳了齋像以自厲','高斯得','宋','宋诗','song-poetry','','[]','我昔天台游，偶得陳公像。',120,'全唐诗/poet.song.213000.json','["我昔天台游，偶得陳公像。", "以公謫是邦，祠堂懸真相。", "尋執憲于衡，復得劉元城。", "以公子孫寓，家傳遺寫真。", "揭之書室內，朝夕得晤對。", "焉能爲之役，妄意他年配。", "劉公色貞堅，疾惇固宜然。", "陳公甚和易，排京乃敢言。", "惇京爲腐草，二公長不老。", "汝其擇于斯，庶以傳不朽。"]'),
('2dc47bf3-21eb-4672-8e82-57f3737292f8','次韻詹丞賀得祠','高斯得','宋','宋诗','song-poetry','','[]','我生天地間，自笑一疣物。',192,'全唐诗/poet.song.213000.json','["我生天地間，自笑一疣物。", "燕蝠爭晨暝，龍蠖安伸屈。", "三度侶黄冠，十載謝丹紱。", "無學陪旃厦，無才演綸綍。", "晨策恣幽探，午窗饒睡兀。", "平生正坐口，自使窮到骨。", "紛紛蝶爭春，悄悄蟆啖月。", "從來彭澤琴，不勝昭陽羯。", "安有冷笑姿，可入豔陽節。", "積年幾穴床，經旬不踰闑。", "時逐志和風，慣卧袁安雪。", "初無子公書，誰其項斯說。", "忽令管龍宮，傳聞從鴈帛。", "還來弄香火，幸不廢書冊。", "偷閒容我輩，用世付時哲。", "鵬鷃各逍遥，何煩較優劣。"]'),
('393edd82-fcf0-4d5a-a986-01d61ef79eb2','感事','高斯得','宋','宋诗','song-poetry','','[]','太師百僚長，歷代皆有之。',108,'全唐诗/poet.song.213000.json','["太師百僚長，歷代皆有之。", "所用有賢否，邦以分安危。", "惟彼太公望，桓桓定周基。", "至於尹氏徒，寧逃小雅譏。", "漢唐姑勿論，我朝有元龜。", "潞公四朝老，德望鎮華夷。", "咄哉京檜侂，言之可歔欷。", "近者揚王庭，舉朝莫言非。", "太潞不可作，吾其誰與歸。"]'),
('680b2726-3a07-4fea-a1da-c8532a998c74','鬼瞰吟','高斯得','宋','宋诗','song-poetry','','[]','相公不入府，却走湖上宅。',204,'全唐诗/poet.song.213000.json','["相公不入府，却走湖上宅。", "朝游廟堂上，暮作水雲客。", "公府爵羅張，別墅車轂擊。", "三日斂履朝，萬楫戈船疾。", "畔官羲和誅，離局春秋責。", "主寬置不問，士佞那敢斥。", "倡優湛夜宴，臺館窮晨策。", "華堂枕千巖，幽龕通百尺。", "知非晉公洞，故是伯有窟。", "蘧蘧夢蝶飛，冉冉長蛇出。", "煩冤哭中夜，魑魅來白日。", "方期燕婉求，難拒幽明迫。", "天不相厥居，鬼乃瞰其室。", "不見霍氏亡，千妖日叢積。", "不見蔡京敗，萬怪無寧迹。", "持危豈顛墜，起穢宜蕩滌。", "君看韓家園，斜陽空寂歷。"]'),
('60b2ac3f-4cae-4756-8339-151bdddbe169','次韻劉養源見寄二十韻','高斯得','宋','宋诗','song-poetry','','[]','山寺傳好語，盈耳歡聲騰。',240,'全唐诗/poet.song.213000.json','["山寺傳好語，盈耳歡聲騰。", "側聞新天子，有意綏黎烝。", "金雞肆大眚，民散蒙哀矜。", "詔書日夜下，合沓來凌兢。", "訪落首鮐背，導諫延龜朋。", "講習召遺席，軺車聘才能。", "官簿還故邸，孝思齊定陵。", "宛如春氣至，頓釋朝霜凝。", "神龍妙噓雲，妖狐疑聽冰。", "維今萬粃政，欲言何可勝。", "安得批肝血，排雲叫觚稜。", "崇蘭變成艾，春鳩化爲鷹。", "貪夫野外贙，善類風中燈。", "百壬各自媚，兩如偏見憎。", "盈庭蒼玉佩，絕響朱絃繩。", "願我聖明后，金臺擇先登。", "昭蘇聵聵聽，凌厲高高層。", "陰霾半夜駮，日月高衢升。", "吾儕老𤱶畝，鼓腹歌中興。", "齒髮已自料，息翅甘冥鵬。"]'),
('24eb8e68-e8cf-403b-ba4e-3e7ee7ed5fe3','要君','高斯得','宋','宋诗','song-poetry','','[]','聖人戒要君，春秋罪同弒。',288,'全唐诗/poet.song.213000.json','["聖人戒要君，春秋罪同弒。", "推此無上心，將何所不至。", "近者凶相歸，决烈誰能比。", "羣愚惑其跡，咸謂難奪志。", "老夫非聖人，固知决無是。", "或問何以知，答云非奧祕。", "豈有患失夫，能爲勇退事。", "未聞介推歸，留母以爲質。", "府中俱蕩析，般移到花卉。", "殿前卒二百，輦載填城市。", "都人尨其愚，家家失歡喜。", "讙言真不返，剝剝競彈指。", "朝士獨可憐，一朝失怙恃。", "聯章乞還相，留莽無少異。", "天王雖聖明，勉徇非得已。", "御前金字牌，一日數十置。", "冠蓋何紛紛，排日遣郎吏。", "端明奉璽書，侍郎傳睿旨。", "師王袖親批，祈懇流涕泗。", "相公卧愈堅，那肯東山起。", "陛下如迫臣，臣當還故里。", "羣使駭其言，連名奏天陛。", "安知夜半舟，已渡曹娥水。", "新亭候徒勞，劉裕已還第。"]'),
('29c58b2e-5c57-42d4-acf2-712c5325f2b0','五月','高斯得','宋','宋诗','song-poetry','','[]','五月出師時，老臣抱憂懼。',120,'全唐诗/poet.song.213000.json','["五月出師時，老臣抱憂懼。", "端筴問詹尹，願告吉凶故。", "卦得明夷終，驚愕不敢露。", "庸知三日後，日眚大可怖。", "天象與人占，真如相對語。", "師出無寸功，敗書常踵路。", "世道復誰論，當局委而去。", "更令水中榆，裊裊擎槃露。", "秋風日以高，吾未得死所。", "援筆識蓍辭，淚血滿襟素。"]'),
('48c5aa25-49a3-4935-bb21-ffd812f96f4f','次韻方泳道見寄','高斯得','宋','宋诗','song-poetry','','[]','延首浙河外，浮氛翳青天。',228,'全唐诗/poet.song.213000.json','["延首浙河外，浮氛翳青天。", "下有豺與贙，紛其集中田。", "況復直歲祲，蒿萊莽連阡。", "民流入他郡，百里無人烟。", "咨予忝觀風，七州命所懸。", "駐車問疾苦，入耳潸潸然。", "期令萬蒼黔，生意春無邊。", "一網獵羣饕，其敢諉力綿。", "天王自聖明，凝旒蔽其前。", "曰此何罪辜，而誣飲貪泉。", "奉使既不稱，還印歸民編。", "南窗可笑傲，雙溪恣流連。", "不貪金門步，不慕東壁躔。", "但願紫皇寤，赤子逃烹煎。", "賢聚國脈壯，吏良民瘼痊。", "臣雖就九死，沒齒無怨言。", "方子遠投贈，厲我彌貞堅。", "枯木已無心，安能被朱絃。", "江水倘可楫，吾其劍西川。"]'),
('71e69960-be32-41f0-a842-2b725f024257','次韻王深道見寄','高斯得','宋','宋诗','song-poetry','','[]','虛齋隠几坐，憂思來萬端。',240,'全唐诗/poet.song.213000.json','["虛齋隠几坐，憂思來萬端。", "我带舊盈骼，忽復數孔寬。", "追思昔迷復，驅馳困塵鞍。", "終蹈世塗險，衽席生瀧灘。", "平生仗忠信，意若無驚湍。", "雖有被野羅，何篡凌風翰。", "嫠憂抱耿耿，進退良獨難。", "亦欲紉蕙茝，殷勤奉所歡。", "終疑薛居州，一暴難勝寒。", "衆陰日夜長，正氣日以單。", "國枋落熏腐，民生困貪殘。", "言路久榛棘，肉食咸空餐。", "蹇予宿嗜好，與世殊鹹酸。", "柰何不自愛，當門植芳蘭。", "故效五柳君，歸求容膝安。", "我友在天末，洞我腸與肝。", "新詩妙鎸發，字如湯銘盤。", "盍簪眇無因，東望慨其歎。", "遥聞病新愈，致我囊中丹。", "願君彊吞咀，百年永相看。"]'),
('b0c740f8-2440-4b07-87c8-a921c478efee','次韻劉友鶴端午三首  其一','高斯得','宋','宋诗','song-poetry','','[]','昔經屈原坂，寒湍下悲鳴。',72,'全唐诗/poet.song.213000.json','["昔經屈原坂，寒湍下悲鳴。", "又渡汨羅江，洐記曾輸誠。", "慨彼幽亂國，成此湘纍名。", "彫胡不受膩，淆予膳膏腥。", "離騷二十五，往往言其清。", "招汝千載後，來乎不來靈。"]'),
('0c5e891a-d7f5-4e68-9d0a-45a80ad23f41','次韻劉友鶴端午三首  其二','高斯得','宋','宋诗','song-poetry','','[]','桐江五月涼，波上摶層颸。',72,'全唐诗/poet.song.213000.json','["桐江五月涼，波上摶層颸。", "傷屈念已愴，懷嚴瀨逾滋。", "維彼不逢世，如斯良遇時。", "懷沙與釣瀨，異節同光輝。", "故人去奚傷，宗國逃懼非。", "精義貴有質，聖遠咨從誰。"]'),
('de70b9cd-021b-4bd8-8c6a-c443bd4d9d2a','次韻劉友鶴端午三首  其三','高斯得','宋','宋诗','song-poetry','','[]','箋天欲移病，心與孤鶴飛。',72,'全唐诗/poet.song.213000.json','["箋天欲移病，心與孤鶴飛。", "苔青弁峯秀，遥昔夢佳期。", "恬鱗慕深藻，倦翮懷安枝。", "焉能繫浮名，翬翔辰昇霏。", "已約東里伴，無煩北山移。", "他年倚磵門，望子蹁躚衣。"]'),
('5ddfab03-c466-4625-935f-0e3336bc447b','道中遇雨','高斯得','宋','宋诗','song-poetry','','[]','車中覽書罷，舉頭失青山。',84,'全唐诗/poet.song.213000.json','["車中覽書罷，舉頭失青山。", "五日無纖雲，春晴固應慳。", "須臾驟雨過，忽已羅青鬟。", "天公自知我，所遇無不安。", "奈何苦相戲，晦明翻覆間。", "浮雲雖暫收，未肯故山還。", "終當買不借，踐此泥塗艱。"]'),
('9296382f-51f0-442b-a1be-9fe7a5249e21','送王深道赴荆門教授','高斯得','宋','宋诗','song-poetry','','[]','蒼龍掛秋漢，凉風鼓吾袪。',144,'全唐诗/poet.song.213000.json','["蒼龍掛秋漢，凉風鼓吾袪。", "夜中不能寐，慷慨悲有餘。", "美人背我去，山川渺盤紆。", "平生嵇叔夜，龍性不可拘。", "以茲直諒益，弱念咸刊除。", "四海豈無交，誰爲真丈夫。", "溫蜀本兄弟，不過姓氏殊。", "臨分悄無言，執手空踟躕。", "世事舉目知，安能共淪胥。", "君理江介枻，我念苕濱廬。", "後會難前期，且復立斯須。", "努力崇明德，歲寒盟可渝。"]'),
('2bda8625-96a0-4076-bd08-c08b16ea9633','次韻北澗禪師留別','高斯得','宋','宋诗','song-poetry','','[]','維北有深澗，其中貯幽泉。',120,'全唐诗/poet.song.213000.json','["維北有深澗，其中貯幽泉。", "茲泥不可滓，萬境涵澄鮮。", "老人挹其流，濁世相周旋。", "清寒滌腴膩，八解不敢專。", "我來宿招提，踰月從金仙。", "解后澗瀕老，筆力回百川。", "參寥一以去，詩宗久無傳。", "阿師佩密印，絕後如光前。", "禪房竹色靜，秋深暑將闌。", "雙巖儻入夢，寄予白雲篇。"]'),
('40ab4127-e01b-4294-99f7-7dad5469f800','中秋獨坐有感','高斯得','宋','宋诗','song-poetry','','[]','三年三中秋，月作一樣奇。',192,'全唐诗/poet.song.213000.json','["三年三中秋，月作一樣奇。", "清貧不設客，老倦不吟詩。", "今年更淒涼，兒孫鎖秋闈。", "獨坐南窗下，兀兀如孤羆。", "追思歡娛地，無如少壯時。", "尚記壬辰歲，鶴山靖州歸。", "八月十五夜，月華散前墀。", "諸父秋山閣，羣從幽芳池。", "賦詩各分韻，醉墨紛淋漓。", "鶴山讀我句，終夜相嗟咨。", "明朝操紙來，傾倒里中兒。", "一往三十載，坐念心生悲。", "前輩已彫謝，諸兄亦無遺。", "奇孤一身在，流落天之涯。", "明月如昨日，而我鬢成絲。", "天人固異分，何煩涕交頤。"]'),
('424259d4-5fd0-49a3-a962-435b41087fca','又中秋分韻得處字','高斯得','宋','宋诗','song-poetry','','[]','西風滌殘㶼，秋水靜如濾。',120,'全唐诗/poet.song.213000.json','["西風滌殘㶼，秋水靜如濾。", "客心悲未央，感茲年芳去。", "聊携池上酌，相與豁煩慮。", "我殽楚以陳，曾未舉前箸。", "延首視太清，飛娥已來御。", "屏翳雖放紛，不敢捩眼覷。", "清輝豈不佳，祇益畸人苦。", "故鄉值良辰，輒與親暱醵。", "轉蓬隨天風，異縣不可據。", "明年看清光，那知又何處。"]'),
('98a2c681-47d7-48a7-8be7-1be8e1cd69d1','自敘六十韻','高斯得','宋','宋诗','song-poetry','','[]','蒼蒼大峩山，高標致青天。',288,'全唐诗/poet.song.213000.json','["蒼蒼大峩山，高標致青天。", "西江走其下，東井躔其顛。", "積此二儀氣，鍾爲萬古賢。", "粵從揚馬來，作者接項肩。", "我家高陽氏，遂古已嬋嫣。", "爰及開府公，世德乃昭宣。", "挺生六男子，如鼇海上連。", "逢時供世用，報國或軀捐。", "二季遇明主，皇極佐後先。", "英芬播家國，餘輝照山川。", "咨予食舊德，一綫千鈞懸。", "結髮日礱砥，植節圖貞堅。", "龍飛四十春，先皇始招延。", "絳侯正驕主，答策聊相鎸。", "無心得天下，人力何有焉。", "有司矜其愚，寘之龜列前。", "先人既死城，□遭禍愈挻。", "挈身歸君父，叨沐登史筵。", "是時嘉熙末，大臣私自便。", "抗疏警其偷，側目尤讒言。", "未幾孽嵩來，當國恣且專。", "白發竝相議，一斥踰三年。", "祁公俄入相，招我赤城邊。", "公尋薨于位，游老司陶甄。"]'),
('cdf413b1-0d0e-4030-8c62-a2cebdea07bb','池荷就衰有感','高斯得','宋','宋诗','song-poetry','','[]','雙池萬荷花，姣好欺子都。',144,'全唐诗/poet.song.213000.json','["雙池萬荷花，姣好欺子都。", "秋風一披拂，槁悴如三閭。", "子有君子操，昔人所歎譽。", "奈何不自奮，俛仰悲榮枯。", "荷花不能言，請以意對吾。", "兩間草木蕃，萬象粲以舒。", "一從鶗鴂鳴，荃蕙首見疏。", "况我值末運，忽忽良辰徂。", "相隨就衰叔，容色何能愉。", "抗手謝荷花，子誠志士模。", "嬰肸悼季世，箕干感淪胥。", "舂陵大中正，所品良非虛。"]'),
('cfc9a217-26c1-4196-9a4f-0d5c93d4787a','九日分韻得花字','高斯得','宋','宋诗','song-poetry','','[]','秋日何烈烈，憂心在丘麻。',108,'全唐诗/poet.song.213000.json','["秋日何烈烈，憂心在丘麻。", "老圃跬步間，無悰問黄花。", "及茲九九候，清樽暢幽遐。", "朋簪既肅穆，宴豆亦靜嘉。", "風雨知蕭辰，颯然掠窗紗。", "喬松助聲勢，轟豗掉狂車。", "萸囊頓精神，似與老守誇。", "淵明有三徑，我獨歸無家。", "浮驂竟安適，佇立空咨嗟。"]'),
('96c17033-61c7-41c8-8206-051933d13309','學詩','高斯得','宋','宋诗','song-poetry','','[]','燕說談古書，六籍無詩如。',108,'全唐诗/poet.song.213000.json','["燕說談古書，六籍無詩如。", "彼序鬼一車，毛鄭賁其須。", "古今幾大儒，亦復鼓應桴。", "歷年二千餘，耳目爲所驅。", "卓哉紫陽朱，訂頑砭其愚。", "俗說力掃除，沙沉得簡珠。", "士惑真難祛，于今道猶孤。", "高叟一鄙夫，服膺與世殊。", "在天懸方諸，如聞嘆起予。"]'),
('cabe1c17-7efc-40ff-b031-e76cb1db12c7','讀書','高斯得','宋','宋诗','song-poetry','','[]','問翁幾何年，翁年七十餘。',84,'全唐诗/poet.song.213000.json','["問翁幾何年，翁年七十餘。", "尚作蠹書蟲，嗟翁一何愚。", "旋增通典缺，旋修阜陵書。", "毫芒集閲盡，白編還卷舒。", "五詩諷被底，柳集誦日晡。", "玩物能喪志，聖賢言皦如。", "賦受有奇偏，誰能爲耘鋤。"]'),
('b429e6c7-ecaa-4395-884f-40ab688017ab','讀荆軻傳','高斯得','宋','宋诗','song-poetry','','[]','夜讀荆軻傳，掩卷喟然嘆。',156,'全唐诗/poet.song.213000.json','["夜讀荆軻傳，掩卷喟然嘆。", "結交天下士，賢哉太子丹。", "報秦一片心，秋蓮孤劍寒。", "介紹田先生，得結荆卿歡。", "太子一語疑，先生甘自殘。", "荆卿欲藉手，臨事敢開口。", "走見樊於期，願借將軍首。", "將軍搤擥言，念此固已久。", "得復平生讎，性命何足有。", "四雄英烈風，精誠凌白虹。", "函關初未入，氣已吞祖龍。", "其事雖不就，簡牘光無窮。", "奈何今之人，蹙縮如寒蟲。"]'),
('0d85f6e2-4172-4c5f-bc38-4d5bafcb1ca7','九日會客面嶽亭以采菊東籬下悠然見南山分韻得采字詩','高斯得','宋','宋诗','song-poetry','','[]','四運相摧斥，秋容忽而改。',120,'全唐诗/poet.song.213000.json','["四運相摧斥，秋容忽而改。", "英英晚節花，含霜發鮮彩。", "游子感蕭辰，命侶登爽塏。", "湘山儼橫陳，秀色如有待。", "獨憐祝融峯，盡日埋靉靆。", "安得誅雲師，吾將罪真宰。", "悠悠元亮心，千載宛如在。", "遥知把不盈，搔首終朝采。", "勝達不可追，迷塗誰堪悔。", "棄置勿復談，且復澆磊磈。"]'),
('89ef0c69-1b9c-4a73-a1aa-795f2a4fd234','謝鄭如晦餉酒詩','高斯得','宋','宋诗','song-poetry','','[]','淵明久閑居，欲釀苦無秫。',156,'全唐诗/poet.song.213000.json','["淵明久閑居，欲釀苦無秫。", "蕭條倚東籬，目斷盃中物。", "可人王荆州，白衣來扣寂。", "高情屬天雲，于今照方策。", "我窮交舊絕，門外無行迹。", "舊時如海腸，轍鮒等枯澀。", "誰憐東溟臣，西江分一滴。", "嗟哉子立賢，肯念黄州客。", "清酒冬百壺，昔酒夏千石。", "陶然北窗下，但覺天地窄。", "東西高雖異，南北鄭能一。", "感荷吾子德，酬報乏珪璧。", "但誦昌黎詩，以謝鄭羣錫。"]'),
('8bc9e443-fd37-4f65-8ea0-19e740aa6b06','題天台夏肯甫曉山亭詩','高斯得','宋','宋诗','song-poetry','','[]','謝公晨策花崖登，杜陵早起開前林。',144,'全唐诗/poet.song.213000.json','["謝公晨策花崖登，杜陵早起開前林。", "徽之朝挹西山爽，退之曉望南山稜。", "古人看山自有候，箇中意味誰探尋。", "林霏夕斂羣動息，澤氣宵上英雲蒸。", "不於此際毓神秀，安得向曙嵐光凝。", "平生苦不識夜氣，見山忽得鄒人心。", "卷書默坐會有得，此豈文字能摹臨。", "斯亭題扁有咀嚼，慎勿只遣供閒吟。", "直須齩破第一義，庶幾山鬼逢知音。"]'),
('a76fc425-37ff-4905-9b93-2c6fa118e3c2','題趙致道茅齋','高斯得','宋','宋诗','song-poetry','','[]','三百年前茅屋歌，誰其繼者茅齋銘。',112,'全唐诗/poet.song.213000.json','["三百年前茅屋歌，誰其繼者茅齋銘。", "杜陵憂世何其切，鶴山觀物何其精。", "兩詩妙處均不朽，吾能合異融其真。", "綺櫳雕宇貯豪士，此豈有意矜吾民。", "從來大庇天下手，乃在茅棟茨檐人。", "請君觀銘驗吾德，復來歌義充吾仁。", "庶幾體用歸一貫，二老可作當欣欣。"]'),
('3199b221-502b-43c1-a906-2ba77f1b2410','五月六日約諸友遊北山舟已具而予偶不能出諸友和坡公法華寺詩亦賦一首','高斯得','宋','宋诗','song-poetry','','[]','區中無由舒眼界，欲上雲峰觀九派。',192,'全唐诗/poet.song.213000.json','["區中無由舒眼界，欲上雲峰觀九派。", "頗聞黄龍擅奇特，儻得窺臨真一快。", "清苕一綫僅委蛇，具區萬頃何滂湃。", "又聞法華兩招提，清曠夐絕人境隘。", "池光瀲灧鏡無臺，山色清寒身不壞。", "石林幻出三玲瓏，萬虎千羆斷雄怪。", "幽貞叶策天相之，梅雨初晴白日曬。", "州家幸肯借官船，亟饌魚蝦菹韮薤。", "奈何欲往竟不諧，徒羨諸公脫天械。", "歸來爭發古錦囊，令予伎癢如爬疥。", "嵇康本自不羈人，况復時屯方翮鎩。", "終當於此結菁茅，庶可償渠猿鶴債。"]'),
('d8e3075a-20d9-4e5c-a16a-14875fc1bcda','劉友鶴以詩贈別次韻送之','高斯得','宋','宋诗','song-poetry','','[]','昔披朝霞尋洞天，五峰矗漢高巑岏。',192,'全唐诗/poet.song.213000.json','["昔披朝霞尋洞天，五峰矗漢高巑岏。", "靈君營魄去千歲，秋桂春蘿空鎖寒。", "古心未死不忍去，摇摇風纛空中懸。", "五年失脚墮時網，夢思重到無由緣。", "朅來出守山水郡，公餘頗得窮幽偏。", "丹丘仙客舊心賞，騎鶴過之同晤言。", "詩妍青林華煜煜，氣老幽澗松桓桓。", "問余君土信奇絕，孰與吾山多紫烟。", "桐江緡魚炯志節，緱山笙鶴誇神仙。", "能衡鐵炭識輕重，衆山部婁真如拳。", "羽人聞此深領會，笑指雙臺催棹船。", "題詩莫作世間語，會有剜剔青苔看。"]'),
('0187aef7-6cd2-4544-99b0-6a7570731613','時雪應禱周子車和東坡所次柳子玉韻見貽用韻答賦','高斯得','宋','宋诗','song-poetry','','[]','大冬衍陽人久渴，井泥無泉百川竭。',112,'全唐诗/poet.song.213000.json','["大冬衍陽人久渴，井泥無泉百川竭。", "老天有意濡沫之，一夜幻成三尺雪。", "勿嘲見卵索時夜，在眼來牟疑彷彿。", "蹇予誰敢貪天功，片片無非后皇德。", "由來此物貴臘前，况復霏霙當暢月。", "坡公守潁足風流，坐看斜飛詠愁絕。", "明朝亦欲踵前規，試與諸君相暖熱。"]'),
('85dd6d08-4ad4-46ea-97b3-c9cb35e34e7e','出其東門行','高斯得','宋','宋诗','song-poetry','','[]','君不見會稽太守第五倫，罷官潛去逃吏民。',211,'全唐诗/poet.song.213000.json','["君不見會稽太守第五倫，罷官潛去逃吏民。", "不知當時何所畏，乘船夜渡曹娥津。", "只緣惠愛入人髓，攀車叩馬千萬羣。", "使君若不行詭道，愛河浩渺難抽身。", "舊聞吳興解郡綬，歸路南指朝天京。", "爾來史項後先去，云何却出東城闉。", "橫山伺候不知數，携壺挈榼相邀迎。", "使君自揣非壽我，西子不潔將汙人。", "水軍二百耀南路，三更一舸臨湖門。", "會稽吳興迹相似，誰知愛惡殊其情。", "畏匡戒薛聖賢有，豈比汝曹祇自焚。", "嗟哉後人亦監此，慎忽繼踵成三人。", "從今要辨守賢否，只觀去路東南分。"]'),
('4afbd204-9043-4fff-ae69-74c50d226bf7','禹柏行','高斯得','宋','宋诗','song-poetry','','[]','往年上會稽，凌空禹穴曾得窺。',233,'全唐诗/poet.song.213000.json','["往年上會稽，凌空禹穴曾得窺。", "今年浮沅湘，又見禹柏蹲山陂。", "茫茫禹迹遍天下，獨此二物稱神奇。", "凌雲意氣銷鑠盡，根心就化空存皮。", "樛柯入地枯不死，反更上擢青銅枝。", "被以九龍名，流傳自何時。", "得非木宿蒼龍精，儲英萃異成雄奇。", "頭角崔嵬訝撐拄，牙鬚磔裂相紛披。", "孔明廟柏信稱古，上距何翅千年奇。", "杜陵品藻一何陋，遺落鼻祖收孫枝。", "諉云此地不身到，何由得集衡湘詩。", "嗚呼，衡之山巍巍，湘之水瀰瀰。", "地氣何太偏，獨於草木乎鍾之。", "柏兮手植自神禹，竹也種傳由舜妃。", "誰能爲天分此畀人物，庶幾可使悍俗嚚風移。"]'),
('63c30110-5209-4347-9ed0-af7fbd1f3b59','題浯谿寺','高斯得','宋','宋诗','song-poetry','','[]','舂陵太守真好奇，結茅肥遯湘江湄。',160,'全唐诗/poet.song.213000.json','["舂陵太守真好奇，結茅肥遯湘江湄。", "三吾出意作新字，脫略蒼籀遺冰斯。", "溪山於我本何有，占斷不許傍人窺。", "人生天地遠行客，戀身外物庸非癡。", "漫郎仙去五百載，名字永與茲山垂。", "要知忠義不磨處，雖不自與人與之。", "至今過者望卷石，森然魄動中興碑。", "此公何用專壑鄙，世上寧有爭墩兒。", "我來訪古刜蓬藋，悵然不識亭臺基。", "掃出蟬噪發斯義，元子可作然吾詩。"]'),
('7837da91-dc4e-403e-a0ce-3f4d64e4bcec','次韻王深道寄題其弟敏道菊山','高斯得','宋','宋诗','song-poetry','','[]','黄花有鑒能品人，俗士往往遭眼白。',128,'全唐诗/poet.song.213000.json','["黄花有鑒能品人，俗士往往遭眼白。", "獨憐寂寞陶長官，到死同盟不相釋。", "至今采采東籬詩，千載晶光猶陸離。", "獶人妙質久無記，羞對紛紛女曹兒。", "子今風塵走異縣，故山舉頭不可見。", "奈何友此隠逸花，三嗅幽香意中戀。", "我聞瀛堧足隑州，夢生八翼飛秋秋。", "不須苦覓菊山句，晚節相期拂衣去。"]'),
('341d8b0c-182d-4af1-81e0-2b89906bc0cf','次韻不浮弟自金陵相過','高斯得','宋','宋诗','song-poetry','','[]','老夫睡眼方昏花，夢中忽聞歌隸華。',192,'全唐诗/poet.song.213000.json','["老夫睡眼方昏花，夢中忽聞歌隸華。", "暮春逢此晴雨好，足慰飄零少陵老。", "知君重踏東華塵，先訪雪堂老師兄。", "大篇鏗鍧來扣寂，讀之宛如花萼集。", "花殘誰復倚欄干，黄鶴催歸呼子安。", "此花當屈第一指，徐娘風情猶可喜。", "詩成共賦豈厭多，惠連何不偕羊何。", "古來難并良與美，報答春光一盛旨。", "勿云數見恐不鮮，勿憂相煎豆萁然。", "我今已信天行止，小馮當門乃吾意。", "一春花惱只顛狂，行樂最怕功名妨。", "杜牧尋春遲有悔，且須十日澆磊隗。"]'),
('9f674916-fdc2-46b5-8de5-de7607dd9a27','再次韻','高斯得','宋','宋诗','song-poetry','','[]','神仙不求三朶花，顔色不求陰麗華。',192,'全唐诗/poet.song.213000.json','["神仙不求三朶花，顔色不求陰麗華。", "但願時清風日好，娛此無裘癡鈍老。", "花光雲錦柳麴塵，買春不用孔方兄。", "止過寂寂還寂寂，有弟有弟遠方集。", "客來我常爲段干，長恐高卧驚袁安。", "踉鏘開門門措指，爲見阿同無量喜。", "阿同爾來新詩多，句法不減水部何。", "盎然醺人如酒美，夢回牙頰聞餘旨。", "我詩端如食小鮮，間厠八珍徒赧然。", "掀髯浩歌不能止，酒酣一麾鐵如意。", "高樓搥碎謫仙狂，茫茫宇宙隘而妨。", "手捋虎須終不悔，謫仙與我如龔隗。"]'),
('627a4d8b-9e3d-4ad4-bf18-7dd2b38f19df','絕交行','高斯得','宋','宋诗','song-poetry','','[]','男兒獨立天地間，太華絕尖一何陗。',160,'全唐诗/poet.song.213000.json','["男兒獨立天地間，太華絕尖一何陗。", "子房不肯下蕭曹，伯夷本自輕周召。", "往來舞袖拂雲霄，醉裏扁舟凌海嶠。", "鳳饑肯向雞求餐，玉潔不與蠅同調。", "山高路斷客來稀，日晏廛空臂爭掉。", "窮塗李白友俗人，歲晚杜甫交年少。", "前門長揖後門關，當面論心背後笑。", "雲門輕與凡耳彈，夜光莫怪兒童誚。", "君平世棄政自佳，老子知希渠所要。", "人間對面九疑峰，未許衝風鼓無竅。"]'),
('f4381be6-6c85-4296-bea9-32ad75e2024d','物貴日甚','高斯得','宋','宋诗','song-poetry','','[]','自從爲關以爲暴，物價何止相倍蓰。',128,'全唐诗/poet.song.213000.json','["自從爲關以爲暴，物價何止相倍蓰。", "人生衣食爲大命，今已勦絕無餘遺。", "真珠作襦錦作袴，白玉爲飯金爲糜。", "蒼天蒼天此何人，遘此大疾誰能醫。", "無食吾欲食其肉，無衣吾欲寢其皮。", "誰能爲我覆八溟，一洗世界無瘡痍。", "絲麻糞土被天下，菽粟水火賙民饑。", "風后力牧不可起，吾輩碌碌安能追。"]'),
('e49f504a-03a7-4376-9ce4-c94d8fefd1ff','次韻徐景說贈安象祖','高斯得','宋','宋诗','song-poetry','','[]','千仞崗頭孤鳳飛，翰林萬族驚且啼。',192,'全唐诗/poet.song.213000.json','["千仞崗頭孤鳳飛，翰林萬族驚且啼。", "桐江得樹一棲息，足以慰我饑渴思。", "飄然徑度爛柯去，再儀天陛來何時。", "子今追逐一何遠，所期不負平生知。", "獨慙託我非所任，泌水洋洋難療饑。", "夜光明月要人識，而我何知和與隋。", "端人擇友必有取，定交從此夫何疑。", "長安綠槐十二街，五都遊客爭奔馳。", "咄哉掉臂不肯住，來同聖路乘堅肥。", "嗟余舊學荒已久，安能扣擊探玄機。", "世事舉目已可知，淹留此土終何爲。", "苕谿一曲攪歸夢，與子共賦臨流詩。"]'),
('cf0aa5e3-03fd-430d-b563-bf56582963f4','次韻劉養源見寄','高斯得','宋','宋诗','song-poetry','','[]','咨余暮齒依蒲柳，見君無門慚九九。',288,'全唐诗/poet.song.213000.json','["咨余暮齒依蒲柳，見君無門慚九九。", "小臣久去孔鸞庭，太史曾供牛馬走。", "忽聞妖彗出不虞，天子驚惶下手書。", "孤忠泣血悼危亂，有詔不應心何如。", "一陽剝盡羣陰長，四海八荒俱痛癢。", "充庭溢序豈無人，借問何人真挺鯁。", "老夫空憶陳王前，語戇惟懼人抄傳。", "擒賊擒王真古語，肯於鷄肋安尊拳。", "相如雖乏三千牘，自謂一言能報國。", "此腰揕斧尚不辭，更問世間閒禍福。", "但愁蠖濩宸居深，司馬門遠終浮湛。", "德音秩秩猶在耳，罪言殺士俄相尋。", "權戚當朝底時節，不見朱雲攀檻折。", "弗於要處箴膏肓，毛舉萬端何屑屑。", "友鶴仙人當暮秋，詩來開卷風颼颼。", "句法森嚴何所自，丈夫冠冕垂前旒。", "淡交如君真耐久，何不來同一杯酒。", "期君他日孟浩然，男兒事業無窮年。"]'),
('4022cea3-b906-48ee-bb33-7d59972879f3','次韻王深道見寄','高斯得','宋','宋诗','song-poetry','','[]','社鼷屋鼠非難攻，我力如綿不能動。',112,'全唐诗/poet.song.213000.json','["社鼷屋鼠非難攻，我力如綿不能動。", "生令墨吏彌奮張，氣湧如山高巃嵷。", "天王聖明侔日月，跂望丹霄眥幾裂。", "孤忠耿耿達無路，獨抱幽香分蕪絕。", "諸偷恣睢方摇尾，忽報台州隨逝水。", "人不代天天代人，造物明威乃如此。", "嗟予粗不愧守官，繄有承君鎸志完。"]'),
('18087264-f8f9-4a19-983e-6a2b25aac60d','次韻張䇓見寄','高斯得','宋','宋诗','song-poetry','','[]','掀髯一笑天地間，八代文衰誰爲起。',227,'全唐诗/poet.song.213000.json','["掀髯一笑天地間，八代文衰誰爲起。", "夷陵丹砂空自光，中山老{兀夋}不可使。", "一從麥秀獲麟臺，二千餘載無文字。", "謫仙豈無希聖心，誰其起予二三子。", "張君忽贈白雲句，墨妙筆精真可喜。", "宗師奇澀費吟噍，三讀方能得其意。", "奮髯蒼鼠色無冤，吐氣黑蛟雲可致。", "恨子初筵我旅酬，妙處安能爲摽指。", "懼遭掎摭不哦詩，畏觸禍刑寧作史。", "翰林主人子墨卿，昔也同盟今趣異。", "不見當年聖德詩，猶被他人呼怪鬼。", "慙君問我乞餘丸，安得錦囊出懷裏。", "丈夫蓋棺事始定，斯文固應付後死。", "試問涪翁餘七言，松苓臭味固相似。"]'),
('1a92a848-b44f-40a1-9e5a-87812672216a','西湖競渡遊人有蹂踐之厄','高斯得','宋','宋诗','song-poetry','','["\u897f\u6e56"]','杭州城西二月八，湖上處處笙歌發。',208,'全唐诗/poet.song.213000.json','["杭州城西二月八，湖上處處笙歌發。", "行都士女出如雲，驊騮塞路車聯轄。", "龍舟競渡數千艘，紅旗綠棹紛相戞。", "有似昆明水戰時，石鯨秋風動鱗甲。", "抽釵脫釧解佩環，匝岸遊人爭賞設。", "平章家住葛山下，麗服明粧四羅列。", "喚船催入裏湖來，金錢百萬標竿揭。", "傾湖坌至人相登，萬衆崩騰遭踏殺。", "府門一旦尸如山，生者呻吟肱髀折。", "西湖自是天下景，何况遨頭古今壓。", "一時死者何足道，且得嘉話傳千葉。", "諫官御史門下士，九重天高誰敢說。", "溪翁聊爾作歌謠，謹勿傳抄取黥刖。"]'),
('b3dd24e1-15a2-4f4a-9677-e92027ffc2b0','三麗人行','高斯得','宋','宋诗','song-poetry','','["\u897f\u6e56"]','相公列屋芙蓉城，烟紅露綠千娉婷。',336,'全唐诗/poet.song.213000.json','["相公列屋芙蓉城，烟紅露綠千娉婷。", "朝回迎笑擁前後，忽遭唾棄嫌羶腥。", "汝曹面作死瓦色，爭似平康坊裏人。", "連眉倒暈雙鴉鬢，臨春璧月陽臺雲。", "西湖喧天歌鼓閙，列坐長筵未狎賓。", "紫衣中使天上至，黄封百榼羅前庭。", "海螯江柱堆𡾋峞，猩脣熊白爭鮮新。", "微哉何曾食萬錢，陋矣楊家送八珍。", "酒酣自有娛客具，非絲非竹非歌聲。", "呼盧一擲數百萬，劉毅酸寒何足陳。", "此時相公眼生纈，平康一笑華堂春。", "鷄鳴鐘動却歸去，相公手自與金銀。", "恩纏愛結無與比，何意一朝遭怒嗔。", "偶緣病起思破悶，亟遣花使傳丁寧。", "誰知青鳥不解事，還報從人嬉水亭。", "立驅百騎捽而至，判司姓賈如弟兄。", "同遊七吏俱簿錄，一日得錢千萬緡。", "大書明梏令湖曲，蘇堤掃迹無蹄輪。", "風流宰相推第一，但恐稷契羞同倫。", "腥風霎霎塞宇宙，萬年遺臭何時泯。", "要當壯士爲一洗，我老無力覆八溟。"]'),
('9153cd23-65a5-4644-a50f-e2cfd878f9e9','次韻周子車喜雨','高斯得','宋','宋诗','song-poetry','','[]','平生報國無才力，日夜只祈天雨粟。',192,'全唐诗/poet.song.213000.json','["平生報國無才力，日夜只祈天雨粟。", "詎今歲事少差池，怪證誰云一而足。", "入春郡國多苦旱，起瞻四方何蹙蹙。", "陋邦愚守介其間，造物私之意何篤。", "桑蠶有歲麥有秋，十里欣欣人足欲。", "爾來勤雨纔浹旬，日日眼穿雲石觸。", "哀哉赤子命如綫，亟籲蒼穹求迓續。", "果然馬上天瓢翻，誰謂龍公慳一掬。", "吾儕所學自孔氏，頗信此身兼位育。", "真能辦得一寸心，勺水固知焦可沃。", "君詩信美嫌太誇，只恐流傳辜自速。", "八荒延首待甘霖，傅說誰其踵芳躅。"]'),
('a3a931c7-8315-456e-9291-82af37809b03','次韻雪寒郡中糶米養源有賦','高斯得','宋','宋诗','song-poetry','','[]','父兮兒饑母兮寒，缾中無粟囊無錢。',192,'全唐诗/poet.song.213000.json','["父兮兒饑母兮寒，缾中無粟囊無錢。", "天公何不知人苦，獰風裂膚雪塞戶。", "我來日月雖未多，舛令已干天譴呵。", "醫瘡眼下尚無藥，更有妙訣瘳沉疴。", "拔貧爲富非不窘，坐視溝瘠吾何忍。", "長民要識天之天，此事前人固加謹。", "我倉我庾雖甚枵，且須傾空蘇瘵凋。", "慙無大德與汝曹，聊以小惠爲寬條。", "何時公私俱露積，慰我片片心事赤。", "圩豐食可接青黄，盜弭丸無探赤白。", "老夫藉手得歸田，免譏取禾三百廛。", "君詩太誇不可傳，吾恐聞者譏貪天。"]'),
('4927f3b9-3603-4c24-8cd3-dc414b1b1126','莫恃勢行','高斯得','宋','宋诗','song-poetry','','[]','夜燈讀書史，摽然撫予胸。',353,'全唐诗/poet.song.213000.json','["夜燈讀書史，摽然撫予胸。", "奇哉天下士，英雄見略同。", "子長嘆息羋家事，謂勢於人將有窮。", "謫仙作詩戒鯨鯢，亦云勿恃風濤之勢如白龍。", "乃知世上夸毗子，控摶外物終成空。", "君不見寡大夫圍初得楚，章華臺前汗成雨。", "鄭田周鼎哆然求，齊桓晉文何足數。", "一朝乾谿萬衆潰，饑卧獨枕涓人股。", "君不見夫差稱霸會黄池，諸侯不敢捩眼窺。", "臨盟爭長莫敢拒，吳竟爲先晉次之。", "中原甫歸敗笠澤，甬東百家悕可悲。", "君不見趙家主父尤雄强，吞滅代北如驅羊。", "詐稱使者入秦地，威風驚倒秦昭王。", "暮年立子一失計，探鷇沙丘終餓亡。", "誦詩讀史餘，更披金匱書。", "章蔡與秦韓，往事尤可吁。", "惇欲族誅元祐人，薦福鑱碑立諸京。", "紹興五十三家檜掌股，慶元五十九人侂牙齦。", "章蔡投荒韓授首，秦亦奄奄泉下人。", "當時氣勢動山嶽，如今一窖寒灰塵。", "後來視今猶視昔，哀哉踵路雙輈傾。", "三書讀罷燈亦暗，齁齁一枕東方明。"]'),
('a8556001-9c22-4344-89d9-c8950f8e6f9e','次韻趙郎中泛舟之作','高斯得','宋','宋诗','song-poetry','','[]','危樓傑出清苕滸，一眺蒼然盡平楚。',128,'全唐诗/poet.song.213000.json','["危樓傑出清苕滸，一眺蒼然盡平楚。", "倚欄興盡蘭橈舉，時聽長年作吳語。", "趙盾當權人共苦，白蘋清風渺何處。", "人生得閒價無伍，天遣吾儕共休汝。", "公孫愛客茶屢煮，風味端能繼桑苧。", "晚凉一巵薦菰黍，清唱時聞采蓮女。", "紀茲勝踐須燕許，好與留題鎮烟嶼。", "吾詩老去渾漫與，不畏傳抄殫萬楮。"]'),
('de4c45b0-ec89-4917-878f-cfb456c9152f','編局','高斯得','宋','宋诗','song-poetry','','[]','舜爲天子臯爲士，瞽瞍殺人執而已。',124,'全唐诗/poet.song.213000.json','["舜爲天子臯爲士，瞽瞍殺人執而已。", "從來三尺天下平，析律二端真可鄙。", "近聞編局蕩巢穴，盡取鼠輩尸諸市。", "布衣韋带三十餘，笞配黥流動千里。", "獨遺太學四五士，但以姦京法從事。", "秦相不重褒衣人，曷爲忠恕而已矣。", "乃知能掉三寸舌，極惡窮凶猶可恃。", "大理得臯陶，汝曹應顙泚。"]'),
('4bad3218-0f50-404d-bc2f-914ee5fa5e54','官田行','高斯得','宋','宋诗','song-poetry','','[]','噫呼嘻樂哉，咸淳三年之秋大有年。',378,'全唐诗/poet.song.213000.json','["噫呼嘻樂哉，咸淳三年之秋大有年。", "近自浙河東西江與淮，遠及七閩二廣連四川。", "黄雲一望千萬里，莫辨東西南北阡。", "甌窶汙邪滿溝塍，秧馬折軸擔頳肩。", "天公更好事，十日不打雨。", "三邊不動塵，穡人更何慮。", "自從田歸官，百姓糟糠難。", "况復連年苦饑饉，草根木實爲珍餐。", "嵯峨殍骨橫千里，待得今年能者幾。", "只道伸眉得一笑，酒肉淋漓渾舍喜。", "誰知一粒不入腸，總是公家主家米。", "夜聞東家鄰，偃仰啼孤婢。", "我問汝爲誰，答云無食無兒窮婦人。", "今年公田分司官吏惡，那有遺秉滯穗霑饑貧。", "大家京坁那復有，惜米如珠藏在囷。", "我聞唐家天子即位當四年，天下斗米惟三錢。", "我皇不減貞觀主，相公亦如房杜賢。", "奈何米價百倍踰貞觀，此病豈得無其源。", "嗚呼噫嘻，我知之矣。", "自從買公田，豐年亦凶年。", "此何人哉，悠悠蒼天。", "更有一事尤堪怪，欲說未說心先怕。", "今年處處皆有秋，何故天台大水獨無一粒收。", "一粒不收猶自可，臣水王，君火囚，此事頗關宗社憂。"]'),
('243b1980-4857-4990-9e84-388f58d3f2c7','讀陸逵常簿奏篇喜而有賦','高斯得','宋','宋诗','song-poetry','','[]','老翁關門貪睡味，朝廷近事到耳疎。',144,'全唐诗/poet.song.213000.json','["老翁關門貪睡味，朝廷近事到耳疎。", "朝起忽收故舊信，得此痛哭流涕書。", "書中所道果何事，人心天命關機樞。", "昔無叛民今已起，赤子至此誰之辜。", "公田下損而上益，楮法子廢而母孤。", "三尺孤童盡知得，誰能暴虎編其須。", "朝陽一鳴百聵醒，幸哉僅有而絕無。", "三后在天甚神聖，佑此一脈皇基扶。", "我非慶曆石守道，聊題數語昭羣愚。"]'),
('266e991d-feaa-4c0c-b8f6-c6c2ee92c25a','和劉養源','高斯得','宋','宋诗','song-poetry','','[]','日景何須土圭測，臘盡熙熙好春色。',224,'全唐诗/poet.song.213000.json','["日景何須土圭測，臘盡熙熙好春色。", "明眉翠柳弄精神，調舌珍禽破岑寂。", "疊嶂融融遲日麗，雙溪渙渙層冰釋。", "行看騎簇昭亭曉，還聞猿嘯高齋夕。", "宛陵山澤紛紆餘，爾來憔悴緣急符。", "安得春風百萬斛，爲散和氣還郊墟。", "北帝回車已浸遠，東皇布令應潛孚。", "原疇蘇醒天雨玉，草木滋潤淵生珠。", "我詩背城猶借一，吏氣暫掃因元日。", "預憂簿領還壓頭，不得時陪竹林七。", "苕溪葦間舟延緣，白魚朱橘不論錢。", "幽棲已入五更夢，早春顧渚何時煎。", "老師謹勿先抽單，苦嫌道院颼颼寒。", "吟編未載兩觳觫，莫惜娉婷珠一斛。"]'),
('08a1b633-7ccf-495f-bfb7-5b86b89337f6','讀梅福傳有感','高斯得','宋','宋诗','song-poetry','','[]','君不見綏和天子在御世五春，畫堂甲觀寂寂空無人。',199,'全唐诗/poet.song.213000.json','["君不見綏和天子在御世五春，畫堂甲觀寂寂空無人。", "豈無壯髮類元帝，奈燕飛來啄皇孫。", "三星屢暗紫宮裏，羣臣默默誰扣閽。", "忽聞縣道上急變，乃是南昌梅子真。", "書言願蚤建三統，以孔子後上繼殷。", "存人自立乃周武，壅人自塞爲亡秦。", "陛下若欲保繼嗣，成湯不祀宜留神。", "子真先曾拄王鳳，言不見省徒報聞。", "小臣讀史每流涕，福於異代猶諄諄。", "而况交柯紫荆樹，東枝顦顇西枝榮。", "有能建此第一義，本支百世何足云。", "我今那復效梅叟，聊欲全生吳市門。"]'),
('71f2cfe9-f9e8-4de2-8c59-063c98c666fd','記二首兒四日雷二異','高斯得','宋','宋诗','song-poetry','','[]','咸淳七年正二月，天災人異何稠疊。',352,'全唐诗/poet.song.213000.json','["咸淳七年正二月，天災人異何稠疊。", "細推厥咎端有繇，孤臣未言先泣血。", "日當丙子月當寅，湖州毘山有妖孽。", "曹家産子威殺人，二首一身連骨節。", "左首似爹右似娘，渾舍驚走趾欲折。", "里胥不敢上其事，一州喧喧騰頰舌。", "從來天子天下首，二首之占何待說。", "我聞唐家儀鳳年，的證端爲今日設。", "涇州之民有生兒，異幹同軀不容裂。", "是時武氏乘其夫，唐祚中微殆將滅。", "聖朝家法與唐異，四星在天循軌轍。", "咎在君陽非太陰，媧羿雖殊禍俱烈。", "人妖示變未三旬，二月天災來不輟。", "粵從己亥至壬寅，據曆雷聲未當發。", "胡爲砰訇震天鼓，四日四夜聲不絕。", "上天威怒端有意，要使吾君用剛决。", "夏竦姦邪致天變，仁皇感悟真明哲。", "只憑霹靂一聲雷，掃去有同湯沃雪。", "後來高廟遵故典，湯相罷歸同一訣。", "奈何災異過兩朝，猶復留此大饕餮。", "二首之兒四日雷，占雖不同應無別。", "作詩會入五行傳，謹勿流傳取剠刖。"]'),
('00c6d902-4edd-4c58-8c0c-c2c932bd8e36','鷄禍詩','高斯得','宋','宋诗','song-poetry','','[]','君不見西漢初，永光年，當時鷄變禍連延。',167,'全唐诗/poet.song.213000.json','["君不見西漢初，永光年，當時鷄變禍連延。", "冠距名將尊已成，坐令戚里傾中天。", "那知千五百年後，咸淳之歲爲續絃。", "黑鷄兩翅生五距，食輒傷人萬口傳。", "家鷄盡縛向市賣，美味不敢登盤筵。", "皆云黑鷄乃癸酉，十二相屬符昭然。", "生不於他獨於翅，蓋言羽翼爪距全。", "我欲攀龍報天公，無路可到明光宮。", "安得尸鄉祝鷄翁，爲我用術禳其凶。", "天子九九八十一萬歲，免使真人白水還飛龍。"]'),
('5c3f32d6-288d-461a-82c1-07a91a9f0c45','冬大雷電','高斯得','宋','宋诗','song-poetry','','[]','方冬十月天炎蒸，雷公吼怒聲憑憑。',148,'全唐诗/poet.song.213000.json','["方冬十月天炎蒸，雷公吼怒聲憑憑。", "投壺玉女忽大笑，晦明倏爍來相乘。", "天方收聲地藏蟄，激怒豈爲陰所陵。", "圓蒼寓意端有在，要使强臣生戰兢。", "强臣聞之但一笑，小兒怖我終何能。", "白鷄巨浸九齡亞，青鼠妖星千道稜。", "我猶視爾爲戲劇，此雷何啻蟲薨薨。", "聖君小變亦知懼，姦臣大異那能懲。", "寄語天公停此小伎倆，只須一聲霹靂王茂宏。"]'),
('20d3d163-e271-4a3f-8a33-be10cb0c475e','孤憤吟四十韻','高斯得','宋','宋诗','song-poetry','','[]','岷峨老人白頭哭，宇宙頻年生意蹙。',384,'全唐诗/poet.song.213000.json','["岷峨老人白頭哭，宇宙頻年生意蹙。", "自從解綬遠遁逃，日望君王戒危辱。", "幡然盡改亂亡事，斬新爲輯和平福。", "叢祠獵去嘷夜狐，遠嶽收取鳴陽族。", "閎籍惟供永巷埽，竇梁總向高閣束。", "上方月進絕前蹊，汙吏日攘行顯僇。", "賦租時爲率土蠲，恩澤尤當近畿足。", "聖心悔禍誠勇猛，天命何憂難迓續。", "老人靜中揩眼看，時事轉覺令心寒。", "旄頭妖彗久不出，黔首剜肉殊未完。", "炎然凶渠氣脈壯，莆婺姦黨根株盤。", "小臣乘間肆邪論，衆正盈庭徒坐觀。", "北衙無人素爲地，南徼何路能通天。", "首血淋漓誰困鄧，頭子勾追空憶韓。", "儀舜鳴周九苞鳳，溢序盈庭五彩鸞。", "若爲千載遭聖代，不肯一唳驚朝端。", "得非盡善遇堯舜，毋庸賣直同箕干。", "我聞屋漏知在下，君欲箸籌煩暫借。", "尺籍無糧創市田，告身易醉空酬價。", "膏腴已被公家奪，磽瘠復遭姦佃嚇。", "積庾如京寧復得，羸胔盈溝誰爲嘅。", "蚩尤兵革自久遠，新莽王田徒擾害。", "哀鴻慘淡集中澤，饑虎咆哮行曠野。", "柯山一鬨猶未平，苕水三貪尤可怕。"]'),
('5e10afc7-f1e4-46e5-bcb8-1fe1e8f5e98a','送庸齋赴召','高斯得','宋','宋诗','song-poetry','','[]','宗臣一去今三年，玉堂詔許還坡仙。',352,'全唐诗/poet.song.213000.json','["宗臣一去今三年，玉堂詔許還坡仙。", "黨魁久屈再徵用，識與不識皆歡顔。", "先生出處固有道，諸公進說徒啾喧。", "或云時事正孔棘，百萬生靈皆倒懸。", "公卿唯阿固權位，閹戚盤互拏金錢。", "三垂蹙蹙迫軍壘，萬口嗸嗸愁實田。", "南交黠寇謀斡腹，東海逆雛方聚船。", "奈何揖遜救焚溺，同姓體國寧其然。", "或云大老世模楷，晚節要同金石堅。", "不聞鳴犢反潛聖，况復白駒遺衆賢。", "濟川必待烝徒楫，傾否亦資茅茹連。", "試看醉翁門下士，當今誰者居清聯。", "角巾支杖亟還里，覽輝翔集毋輕前。", "我當靜慮爲折衷，咄此二議何其偏。", "卦爻時義各有當，聖賢出處無非天。", "五真應二泰可致，四不求初屯豈亨。", "要知君相誠與否，卓識諒已窮幾先。", "苟能舉國聽夫子，雖不俟駕何尤焉。", "嚴風吹衣落閩土，幸與盟主相周旋。", "酒邊抵掌談世事，愛君憂國固拳拳。", "鴻飛遵渚望不及，中夜起坐徒煩煎。", "心乎愛矣思有助，斐然狂簡成茲篇。"]'),
('75fc37c7-70c5-4c34-aaa1-4a5f872dfe43','閒中讀書次第','高斯得','宋','宋诗','song-poetry','','[]','紫陽禮編甫盡卷，亟償通典平生願。',112,'全唐诗/poet.song.213000.json','["紫陽禮編甫盡卷，亟償通典平生願。", "增損溫公鑑目成，要把二巖書貫穿。", "夜燈覽徹六一文，眉山鉅集思重見。", "七書卷帙二千餘，加我三年當閲徧。", "爾來兩目漸眵昏，一一手鈔寧敢倦。", "固知衰頹力不勝，其奈嗜好頑難變。", "又恐貪多或溺心，閉閤時燒香一篆。"]'),
('6b4a1c3c-1408-4794-9289-ed9f89d27452','園中讀書','高斯得','宋','宋诗','song-poetry','','[]','南樓幽簾雖粗適，猶嫌塵務妨閒逸。',112,'全唐诗/poet.song.213000.json','["南樓幽簾雖粗適，猶嫌塵務妨閒逸。", "讀書老圃四無人，啼鳥落花春寂寂。", "試垂修綆汲義泉，更把長纔斸玄窟。", "已無俗物敗人意，猶有睡魔入吾室。", "且須時擎看山脰，不妨暫著穿花屐。", "君平身世兩相棄，韓子老大百無益。", "但願殘生更幾年，了我床頭二三策。"]'),
('b87f98ef-4ece-40f5-a0af-0494a42febbf','次韻養源避暑西湖','高斯得','宋','宋诗','song-poetry','','["\u897f\u6e56"]','牆擁千竿竹，簾縈一穗香。',48,'全唐诗/poet.song.213000.json','["牆擁千竿竹，簾縈一穗香。", "避暄情散朗，懷舊意悲凉。", "小簟琉璃色，新醅琥珀光。", "夢回聞剝啄，渾欲懶衣裳。"]'),
('effe1353-ca9b-4174-9811-8a759f8b9b18','次韻戴石屏見寄','高斯得','宋','宋诗','song-poetry','','[]','霞嶠詩人窟，夫君獨擅場。',48,'全唐诗/poet.song.213000.json','["霞嶠詩人窟，夫君獨擅場。", "太羹無厚味，嘉稷有真香。", "投老安蓬戶，平生似草堂。", "遥知道機熟，尊酒百憂忘。"]'),
('a4a3b95d-cb99-45d0-b2a3-56087ab99d33','晚秋','高斯得','宋','宋诗','song-poetry','','[]','颯颯晨飈凜，蕭蕭暝色凄。',48,'全唐诗/poet.song.213000.json','["颯颯晨飈凜，蕭蕭暝色凄。", "拒霜城上下，衰柳岸東西。", "老去慵青簡，憂來俯碧溪。", "饑烏誰教汝，故作傍人啼。"]'),
('8e231971-d51d-4b49-8f39-31673b323321','江夫人挽詩','高斯得','宋','宋诗','song-poetry','','[]','悲哉金氏誌，未讀涕先零。',48,'全唐诗/poet.song.213000.json','["悲哉金氏誌，未讀涕先零。", "祖統他宗嗣，婺憂再世丁。", "天矜人一念，姑與婦三齡。", "幸有孫枝秀，翹然蔭戶庭。"]'),
('fe37d7ca-e21e-474c-b0c7-905e3ce12e93','病起二首  其一','高斯得','宋','宋诗','song-poetry','','[]','老去增書癖，還遭病見磨。',48,'全唐诗/poet.song.213000.json','["老去增書癖，還遭病見磨。", "杜詩能止瘧，周易解祛魔。", "不得青編伴，惟應白日過。", "坐多膚欲痹，時起眺清波。"]'),
('de437a96-b547-4e52-a689-1b2e9a0115bf','病起二首  其二','高斯得','宋','宋诗','song-poetry','','[]','頮面驚權出，梳頭感髮稀。',48,'全唐诗/poet.song.213000.json','["頮面驚權出，梳頭感髮稀。", "鶴饑從自瘦，驥老更求肥。", "蕭索盤中饌，寬長身上衣。", "惟餘酒未減，興至羽觴飛。"]'),
('11a8daf4-3a5a-4cc6-a544-79208883afa1','鶴林吳尚書挽詩二首  其一','高斯得','宋','宋诗','song-poetry','','[]','珠緯躔奎後，坤文世載英。',48,'全唐诗/poet.song.213000.json','["珠緯躔奎後，坤文世載英。", "奇才冠元祐，大手擅端平。", "時事雖難並，詞華略與京。", "自從雙鳥寂，禁柳謾嚶鳴。"]'),
('d313d9bd-a587-4d69-b028-7f0ec9a4da79','鶴林吳尚書挽詩二首  其二','高斯得','宋','宋诗','song-poetry','','[]','魁孽奸時論，詞臣格詔除。',48,'全唐诗/poet.song.213000.json','["魁孽奸時論，詞臣格詔除。", "承明俄罷直，光範肯馳書。", "東土淹靈運，南州哭仲舒。", "平生丞弼望，只此閟高墟。"]'),
('bc5a3549-6433-4cf6-90e0-6290b4a7cc0d','吳參政挽詩三首  其一','高斯得','宋','宋诗','song-poetry','','[]','造化千年秀，皇家數世仁。',48,'全唐诗/poet.song.213000.json','["造化千年秀，皇家數世仁。", "功名光慶祐，人物輩乾淳。", "犖犖旂常紀，睽睽鼎鼐新。", "憗留天不許，國步痛斯頻。"]'),
('c0bd8a8d-4362-4aa8-8bf2-925329d5d1b5','吳參政挽詩三首  其二','高斯得','宋','宋诗','song-poetry','','[]','中外踰三紀，勤勞備百爲。',48,'全唐诗/poet.song.213000.json','["中外踰三紀，勤勞備百爲。", "韓公飽經濟，杜杞困驅馳。", "風靜千屯祲，春回數路饑。", "江淮與襄漢，何地不豐碑。"]'),
('494e2ae9-95a9-4160-af30-70aadcd95f75','吳參政挽詩三首  其三','高斯得','宋','宋诗','song-poetry','','[]','念昔先君子，慈恩託下陳。',48,'全唐诗/poet.song.213000.json','["念昔先君子，慈恩託下陳。", "嵇孤雖願識，李御竟無因。", "賞遇肝腸照，書題骨肉親。", "數行知己淚，西望幾沾巾。"]'),
('9dfa6f33-50c3-44b5-986e-548af559b18b','題林屋洞天','高斯得','宋','宋诗','song-poetry','','[]','將返鴟夷棹，聊觀古洞天。',48,'全唐诗/poet.song.213000.json','["將返鴟夷棹，聊觀古洞天。", "蒼崖環谷口，圓嶠結湖壖。", "大藥漸無質，還丹莫浪傳。", "具區如弱水，重到定何年。"]'),
('eb30ed33-8527-4661-a52d-51a05605592b','陳樞密挽詩二首  其一','高斯得','宋','宋诗','song-poetry','','[]','讀公淳寶疏，風節一何奇。',48,'全唐诗/poet.song.213000.json','["讀公淳寶疏，風節一何奇。", "凜凜戮丁刃，堂堂伐鄭師。", "良醫渠不使，傾厦故難支。", "不見陳攻蔡，當年亦右司。"]'),
('bc5a4f38-b0b0-4d50-8795-19034bf27aaf','陳樞密挽詩二首  其二','高斯得','宋','宋诗','song-poetry','','[]','直道終難恃，平生一險夷。',48,'全唐诗/poet.song.213000.json','["直道終難恃，平生一險夷。", "蠻谿憔悴日，公府笑談時。", "來識魯山面，空看有道碑。", "雉膏殊未食，付與寧馨兒。"]'),
('c162587a-78e1-4c57-9d57-9e9257f5feea','書事四首  其一','高斯得','宋','宋诗','song-poetry','','[]','晨炊出避寇，中夜尚傷弓。',48,'全唐诗/poet.song.213000.json','["晨炊出避寇，中夜尚傷弓。", "赤地眠枯秸，青天入短蓬。", "可憐窮白叟，所至聚黄童。", "老耳雖多聵，時聞話相公。"]'),
('31a86937-8d99-4e44-8b13-207dcdf715e6','書事四首  其二','高斯得','宋','宋诗','song-poetry','','[]','坎壈乾坤志，蒼茫宇宙身。',48,'全唐诗/poet.song.213000.json','["坎壈乾坤志，蒼茫宇宙身。", "十年猶鎩翮，尺澤豈遊鱗。", "汗簡時鑽蠹，斯文企獲麟。", "但憂來日少，滄海闊無津。"]'),
('951b977e-b511-4d7e-a494-781a7a3688eb','書事四首  其三','高斯得','宋','宋诗','song-poetry','','[]','不必繙金匱，何須校石渠。',48,'全唐诗/poet.song.213000.json','["不必繙金匱，何須校石渠。", "科條唐代典，刀尺漢人書。", "後世應知我，時人莫起予。", "祈天無厚望，更予十齡餘。"]'),
('2de0e9f3-640c-471a-8a0b-f08288a3e068','書事四首  其四','高斯得','宋','宋诗','song-poetry','','[]','兩月竄荆棘，愁生祇自憐。',48,'全唐诗/poet.song.213000.json','["兩月竄荆棘，愁生祇自憐。", "屈盤茅屋底，擎跽野人前。", "盡室踰百指，看囊無一錢。", "長安望不見，何日靜戈鋋。"]'),
('09f33cb0-3e01-4fb1-b8a8-4914d742c20f','耽書','高斯得','宋','宋诗','song-poetry','','[]','年來得奇疾，彷彿似書淫。',48,'全唐诗/poet.song.213000.json','["年來得奇疾，彷彿似書淫。", "二史番休讀，三詩夢覺吟。", "少時輕寸晷，老去惜分陰。", "只恐前生是，蓬山閣上蟫。"]'),
('071e044d-0437-472a-9893-cdcba5d75bf5','端午小飲分韻得身字','高斯得','宋','宋诗','song-poetry','','[]','此節知何節，悲歡發興新。',48,'全唐诗/poet.song.213000.json','["此節知何節，悲歡發興新。", "懷沙弔沉塚，高戶慶長身。", "豪氣今安在，忠魂死不泯。", "詠餘增感慨，命酒慰沾巾。"]'),
('bae7b9aa-d75b-4955-9bb3-655054286e89','立春日集杜句  其一','高斯得','宋','宋诗','song-poetry','','[]','春日垂霜鬢，江村亂水中。',48,'全唐诗/poet.song.213000.json','["春日垂霜鬢，江村亂水中。", "偷生長避地，愁坐正書空。", "乞米煩佳客，應門試小童。", "布衾冷如鐵，長夜豈堪終。"]'),
('4a93c814-8437-4ae9-89a4-7105e296f80c','立春日集杜句  其二','高斯得','宋','宋诗','song-poetry','','[]','早行石上水，泥濘苦相牽。',48,'全唐诗/poet.song.213000.json','["早行石上水，泥濘苦相牽。", "盜賊浮生困，艱辛衆目憐。", "囊空罄金錯，米盡折花鈿。", "更有傷心處，君臣豺虎邊。"]'),
('88896b54-5139-4fa5-9872-dd2473bf86ba','存齋牟端明挽詩','高斯得','宋','宋诗','song-poetry','','[]','碩德千人表，高風一世欽。',240,'全唐诗/poet.song.213000.json','["碩德千人表，高風一世欽。", "師承文靖正，識拔秀巖深。", "奧學方前古，雄文獨擅今。", "史筵新發軔，儒館力抽簪。", "蕭艾俄當路，蘅蘭夐出林。", "螭頭恩舄奕，豹尾步嶔崟。", "斮脛思全玉，圍腰肯待金。", "綬甘辭若若，戟喜對森森。", "孽火遭千劫，讒波沸百壬。", "然臍機穽巧，拔眼計謀陰。", "誣詆淵衷監，成蠲寵命臨。", "一麾猶偃蹇，三節又侵尋。", "聽履星辰近，司綸雨露湛。", "世方期汲直，人已感遲任。", "披腹平生節，攀髯晚歲心。", "幅巾朝第就，遺服暮庭廞。", "書殿榮封塚，玄臺閟在岑。", "鶴山初共被，苕水晚同襟。", "感舊鬚成雪，懷人涕作霖。", "元成負文采，端可嗣徽音。"]'),
('038d4b02-3c83-408a-9200-1af8dce61e99','鄒樞密挽詩','高斯得','宋','宋诗','song-poetry','','[]','有偉倫魁彥，風標九牧傾。',216,'全唐诗/poet.song.213000.json','["有偉倫魁彥，風標九牧傾。", "直聲同日揭，峻節與霜明。", "賀旅羞權隸，佳兵折寇萌。", "一麾人共惜，再入道彌貞。", "專對思尊主，塗歸首正名。", "終然踈汲黯，誰復挽陽城。", "訪落當元祀，干旄並兩英。", "馹車方稅鞅，局面已翻枰。", "不憚箋天苦，堅留出晝行。", "一言嬰虎怒，八載與鷗盟。", "改瑟新元化，持樞贊國成。", "咎言方洶湧，悟主獨和平。", "南谷撩歸夢，東藩薄宦情。", "寒花馨晚節，潜穎謝浮榮。", "落落靈光殿，堂堂董相塋。", "國人歌輟杵，志士淚緣纓。", "隸也常尊孟，嗟哉未識荆。", "易名如得與，猶足慰平生。"]'),
('d3ed41d4-0295-49cd-bac6-82134ec4448b','讀天台侍郎黄公神道碑','高斯得','宋','宋诗','song-poetry','','[]','昔纂寧宗紀，名臣嘆寂寥。',120,'全唐诗/poet.song.213000.json','["昔纂寧宗紀，名臣嘆寂寥。", "鉅姦方枋國，多士謾盈朝。", "快讀黄公傳，如聞舜代韶。", "盡言醒衆聵，獨立聳清標。", "辨枉全張猛，持身簡豎刁。", "要途方凜凜，歸夢已摇摇。", "疏廣還家勇，羲之入海遥。", "寒花矜晚節，老檜傲霜朝。", "遷史雖猶缺，邕碑亦孔昭。", "咨予無健筆，魂去若爲招。"]'),
('782c0690-aaeb-495a-bd1d-d306b1dfc3f1','奏院豫七弟挽詩','高斯得','宋','宋诗','song-poetry','','[]','瑟瓚天資美，洪樞地胄華。',120,'全唐诗/poet.song.213000.json','["瑟瓚天資美，洪樞地胄華。", "安恬羞善宦，孝謹克承家。", "籀學耽奇古，文房好靜嘉。", "顔瓢空不繼，原粟散無涯。", "庭徑長生草，山園妙識花。", "公門捐造請，內典却紛拏。", "留邸空陳迹，分麾付一嗟。", "階蘭芳欲盡，池草句誰誇。", "甚欲號森栢，其如歎繫瓜。", "遥將萬行淚，灑向夕陽斜。"]'),
('9466e8ea-67f2-4052-a1ed-880d976cdfe4','挽亡弟豫九制參詩','高斯得','宋','宋诗','song-poetry','','[]','山園有佳樹，生處本同枝。',144,'全唐诗/poet.song.213000.json','["山園有佳樹，生處本同枝。", "客土何年異，孤根兩處移。", "西栽種嶺下，東植霅溪湄。", "君壯方逢世，吾衰久忤時。", "丘園甘寂寞，門戶倚扶持。", "乘障能名著，參籌婉畫奇。", "平生境雖順，末路數終奇。", "屢厄梟鳴暴，仍遭馬踶危。", "客魂翔寓里，旅櫬出京師。", "鴈澤羈孤影，鴒原躑躅悲。", "殫予暮光景，恤汝衆孤婺。", "臨穴萬行淚，九原知不知。"]'),
('949adf90-53dc-45e9-81df-6facebbf6b20','谿亭春日二首  其一','高斯得','宋','宋诗','song-poetry','','[]','嚶嚶春哢沸青郊，老鶴翛然獨在臯。',64,'全唐诗/poet.song.213000.json','["嚶嚶春哢沸青郊，老鶴翛然獨在臯。", "澹沲和風眠五柳，沖融暖日醉三桃。", "盡輸樂事歸妍唱，肯把牢愁寄續騷。", "想得舊遊時入夢，西堂春草未應薅。"]'),
('11bb6674-d69d-44c6-b28d-9de90f29c78f','谿亭春日二首  其二','高斯得','宋','宋诗','song-poetry','','[]','豈不懷歸蜀道難，故來谿上稅浮驂。',64,'全唐诗/poet.song.213000.json','["豈不懷歸蜀道難，故來谿上稅浮驂。", "新詩功次日遷九，潜聖儀刑晝接三。", "窗竹有情陪素隠，園花無頼恣紅酣。", "要將雲淡風輕句，參請宗門老晦菴。"]'),
('dfcfeed5-e8ad-43fb-b7db-782b332450dc','送胡吏部赴闕  其一','高斯得','宋','宋诗','song-poetry','','[]','枌榆陰裏植甘棠，民坐春風吏履霜。',64,'全唐诗/poet.song.213000.json','["枌榆陰裏植甘棠，民坐春風吏履霜。", "治粟久持膚使節，握蘭歸噴望郎香。", "去思應共湘江永，來諗誰云周道長。", "拖玉腰金君不羨，令名姱節看流芳。"]'),
('89a8abcc-f2d1-4096-ae9c-27976aeb4823','送胡吏部赴闕  其二','高斯得','宋','宋诗','song-poetry','','[]','郎省分携恰五朞，相逢一笑楚江碕。',64,'全唐诗/poet.song.213000.json','["郎省分携恰五朞，相逢一笑楚江碕。", "釣魚山下人方到，回鴈峰頭客已歸。", "夜雨未厭揮麈柄，春風無奈趣鞍鞿。", "臨岐但祝加餐飯，人物如今角宿稀。"]'),
('0b7c574d-08ab-4fa5-87ac-60f0c0e73c61','建寧府鹿鳴宴詩','高斯得','宋','宋诗','song-poetry','','[]','鶴書夜下建谿南，拔盡鄉英萬口談。',64,'全唐诗/poet.song.213000.json','["鶴書夜下建谿南，拔盡鄉英萬口談。", "帝闕佇聽臚唱九，賓筵試詠鹿鳴三。", "身名雖待文章顯，氣質須從道義涵。", "海內如今人物眇，掀天事業要奇男。"]'),
('e1942eff-4410-489a-971c-19603d0a8552','題張志山留稿','高斯得','宋','宋诗','song-poetry','','[]','一眼高懸四海空，評詩誰出杜陵翁。',64,'全唐诗/poet.song.213000.json','["一眼高懸四海空，評詩誰出杜陵翁。", "紫鸞翠駁真難並，翡羽鯨魚定孰雄。", "門外飛來清婉句，壇中報起寂寥風。", "錦囊已逐春風去，何日花前一醉同。"]'),
('fce6daaa-ee09-4044-b636-b736492de32a','勸農有感三首  其一','高斯得','宋','宋诗','song-poetry','','[]','井卦分明說勞農，周人田制寓其中。',64,'全唐诗/poet.song.213000.json','["井卦分明說勞農，周人田制寓其中。", "但令此念純無已，可使吾民養不窮。", "數豆荒餐延野老，一篇腐語誨村童。", "爾忱不屬知何補，謾道天公靳屢豐。"]'),
('4c842ad2-6a23-47a9-a246-f3bcdfc4273b','勸農有感三首  其二','高斯得','宋','宋诗','song-poetry','','[]','三代興甿法已精，田官衆建日諄勤。',64,'全唐诗/poet.song.213000.json','["三代興甿法已精，田官衆建日諄勤。", "一年一度情何簡，于縣于州責孰分。", "愛禮存羊斯僅可，賣刀買犢匪攸聞。", "周官千載何曾試，我欲重拈靜楚氛。"]'),
('01e00ea3-21ac-4c8e-8301-a34570441388','勸農有感三首  其三','高斯得','宋','宋诗','song-poetry','','[]','衍漾春郊徧野疇，不堪回首劍南州。',64,'全唐诗/poet.song.213000.json','["衍漾春郊徧野疇，不堪回首劍南州。", "勸農官吏渾冠鶡，力穡丁夫總带牛。", "苦欲如邛嗟未得，自憐適越竟何求。", "春風萬斛濃於酒，一與畸人盪許愁。"]'),
('b6ade2f1-3fa1-412c-a293-00d6144969d6','次韻趙庸齋賀除閩漕','高斯得','宋','宋诗','song-poetry','','[]','方向江湖拜散人，天王明聖尚哀臣。',64,'全唐诗/poet.song.213000.json','["方向江湖拜散人，天王明聖尚哀臣。", "牽舟未得還三峽，乘傳何堪使七閩。", "作牧幸逢青眼舊，論交寧歎白頭新。", "却愁未稅周原鞅，公已催歸上要津。"]'),
('49b0602c-2661-490e-a689-069d3ed359e8','庸齋再賦予亦再和','高斯得','宋','宋诗','song-poetry','','[]','苕濱衰白一羈人，五玷皇華遣使臣。',64,'全唐诗/poet.song.213000.json','["苕濱衰白一羈人，五玷皇華遣使臣。", "已自無恩及南楚，那能有福散東閩。", "預憂刺史聲名減，不稱君侯佳句新。", "踏徧山川成底事，徒令沮溺笑知津。"]'),
('e466378b-b9af-466b-86c7-6fbf421d0d7b','次韻養源雙溪閣野眺','高斯得','宋','宋诗','song-poetry','','[]','雨餘久不眺寒城，平楚遥知一望清。',64,'全唐诗/poet.song.213000.json','["雨餘久不眺寒城，平楚遥知一望清。", "老杜頗慵看白谷，大王惟愛寫黄庭。", "剪裁花柳春刀尺，錯綜江山帝緯經。", "終待幅巾同遠望，逃他天械與天刑。"]'),
('e500341e-f4ac-4690-9075-677e925afcc3','送不浮赴沿江制參二首  其一','高斯得','宋','宋诗','song-poetry','','[]','地褊難頒虎竹分，不妨六度作參卿。',64,'全唐诗/poet.song.213000.json','["地褊難頒虎竹分，不妨六度作參卿。", "九江日落回君首，三樹風吹動我情。", "此別不堪分袂苦，何時重聽對床聲。", "到官休道無來使，湓浦雙魚自可烹。"]'),
('53440324-24db-4a48-8c82-fe8be8338c04','送不浮赴沿江制參二首  其二','高斯得','宋','宋诗','song-poetry','','[]','缾中儲粟苦無多，百口張頤劇雁鵝。',64,'全唐诗/poet.song.213000.json','["缾中儲粟苦無多，百口張頤劇雁鵝。", "王粲依劉寧得已，嚴公待甫定如何。", "且須省却癡兒事，只好長爲醉後歌。", "瓜熟歸來再相聚，阿兄猶自種陽坡。"]'),
('96e23df1-1d1e-4ad0-a9b6-6ef6b3b46ea1','次韻上饒溫淳投贈','高斯得','宋','宋诗','song-poetry','','[]','從來箕斗只虛名，石火光中了一生。',64,'全唐诗/poet.song.213000.json','["從來箕斗只虛名，石火光中了一生。", "寂寞九京薶子政，荒凉三徑老淵明。", "我方遯世人爭棄，君獨憂時意未平。", "多謝相逢便如故，次山詞氣浩縱橫。"]'),
('74752ceb-4241-445e-ab94-9720067ef071','送饒漕','高斯得','宋','宋诗','song-poetry','','[]','已催四牡使騑歸，江漢旋歌命召詩。',64,'全唐诗/poet.song.213000.json','["已催四牡使騑歸，江漢旋歌命召詩。", "借問儀庭集鸞鳳，何如當道卧熊羆。", "柳迎士行成陰密，樓得元規發興奇。", "少待邊亭永清晏，却歸簪筆侍龍墀。"]'),
('df3b32a6-a6d6-41e4-9215-2bf2a66116f8','次韻戴石屏見簡二首  其一','高斯得','宋','宋诗','song-poetry','','[]','採玉探珠遍九圍，先容分不到離奇。',64,'全唐诗/poet.song.213000.json','["採玉探珠遍九圍，先容分不到離奇。", "委心自信天行止，用世定慙道覺知。", "且可謾持東海釣，終期不負北山移。", "杜陵雖老心猶壯，盍與同尋蜀相祠。"]'),
('39b4befc-5a86-42f8-9fe1-a1c09cc319a7','次韻戴石屏見簡二首  其二','高斯得','宋','宋诗','song-poetry','','[]','入東頗亦交名勝，安道聞孫更崛奇。',64,'全唐诗/poet.song.213000.json','["入東頗亦交名勝，安道聞孫更崛奇。", "明月清風能我共，高山流水只君知。", "遥憐把酒懷人處，正是登樓望遠時。", "安得抽簪投海岸，相從朗誦快心詩。"]'),
('51b1277d-fabd-4689-b389-2e16c320e40d','送史深之入蜀','高斯得','宋','宋诗','song-poetry','','[]','我讀江湖夜雨編，西風搔首一凄然。',64,'全唐诗/poet.song.213000.json','["我讀江湖夜雨編，西風搔首一凄然。", "如何經濟二三策，僅見琳琅千萬篇。", "小隠安能老丹嶠，壯懷猶欲上青天。", "此行若與涪翁遇，定把詩家古印傳。"]'),
('b710d75f-842e-43c5-b60e-f6d94fb888a8','次韻施秀才新樓有賦','高斯得','宋','宋诗','song-poetry','','[]','白鶴山中熊豹姿，可憐營窟傍苕溪。',64,'全唐诗/poet.song.213000.json','["白鶴山中熊豹姿，可憐營窟傍苕溪。", "無家那得還三蜀，寄跡堪嗤傅一齊。", "共詫閤能捫斗柄，誰知堂不愛榱題。", "厦成人已辭騷國，何日同登醉似泥。"]'),
('54e3896c-5b96-4f7a-ac88-1f958f1adc9c','飲牡丹','高斯得','宋','宋诗','song-poetry','','[]','尚記年時醉我賓，抽簪起舞坐生春。',64,'全唐诗/poet.song.213000.json','["尚記年時醉我賓，抽簪起舞坐生春。", "誰呼七七逡巡手，重現三三夢幻身。", "獨樂園中老居士，沉香亭北謫仙人。", "吾今望此如蜂蟻，莫怪名花向我顰。"]'),
('f7ab0cbc-d56f-4954-ae9f-cfc14d489bba','夜坐有感','高斯得','宋','宋诗','song-poetry','','[]','自嘆吾生行且休，誰能長抱畏塗憂。',64,'全唐诗/poet.song.213000.json','["自嘆吾生行且休，誰能長抱畏塗憂。", "三番自取刳腸害，百鍊多成繞指柔。", "鞭鳳笞鸞勞夢想，鬭雞走狗好沉浮。", "從今投劾歸漁隠，手掬清波蕩許愁。"]'),
('643e0b78-c87c-4234-8bf2-36e17c6a7766','次韻趙庸齋見寄','高斯得','宋','宋诗','song-poetry','','[]','人在南山第幾重，采薇端可繼高蹤。',64,'全唐诗/poet.song.213000.json','["人在南山第幾重，采薇端可繼高蹤。", "褰衣辟世鋤三徑，閉戶求仁印五峰。", "周室如何廢常隸，楚人猶聽集夫容。", "大書元祐黨魁傳，今代豈無人姓龔。"]'),
('9816510e-96d3-4f0f-af49-0aaac39e2fcd','鄧侍郎再和予亦再答','高斯得','宋','宋诗','song-poetry','','[]','烟雨凄迷主簿峰，傷心蕙帳十年空。',64,'全唐诗/poet.song.213000.json','["烟雨凄迷主簿峰，傷心蕙帳十年空。", "夢魂吳蜀千山隔，歸路湘江一水通。", "莊舄相看均是客，虞卿何事獨嗟窮。", "天涯邂逅誠多幸，許挈詩囊入社中。"]'),
('8f0fa920-4e5d-4144-a415-da02dac87c9f','春日偶成','高斯得','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','七年高卧霅溪濱，閲盡諸公上要津。',64,'全唐诗/poet.song.213000.json','["七年高卧霅溪濱，閲盡諸公上要津。", "共怪朝無書一字，寧知項有鐵千觔。", "淵明肯仕義熙世，劉老要完元祐人。", "四壁新堂基已就，從今飽挹洞庭春。"]'),
('d005854e-aa6d-4fab-a2d2-c8ec34c8d786','蜀錦亭','高斯得','宋','宋诗','song-poetry','','[]','故國名花夐不同，景陽機裏織春風。',32,'全唐诗/poet.song.213000.json','["故國名花夐不同，景陽機裏織春風。", "莫將麗質驚丹卉，只把孤根託化工。"]'),
('c4bb4543-67ff-43df-8ff7-dfef34d04249','孤憤吟十三首  其一','高斯得','宋','宋诗','song-poetry','','[]','檜侂當權十五年，始終只被一私纏。',32,'全唐诗/poet.song.213000.json','["檜侂當權十五年，始終只被一私纏。", "人心失盡天心怒，燎火炎炎故不然。"]'),
('1d84db25-13df-4ace-8a15-dbce99e97936','孤憤吟十三首  其二','高斯得','宋','宋诗','song-poetry','','[]','金繒私許北方盟，君父前頭却隠情。',32,'全唐诗/poet.song.213000.json','["金繒私許北方盟，君父前頭却隠情。", "今日禍胎從此始，罪浮孽檜與權京。"]'),
('5f55720e-52fd-46b8-8aaf-0208833d1e51','孤憤吟十三首  其三','高斯得','宋','宋诗','song-poetry','','[]','先帝方歸盛德園，龍輴半夜浙江邊。',32,'全唐诗/poet.song.213000.json','["先帝方歸盛德園，龍輴半夜浙江邊。", "孤臣泣血無他請，願把姦臣訴九天。"]'),
('98bbdbfd-bb09-4aa3-a035-c3e7b5366f9d','孤憤吟十三首  其四','高斯得','宋','宋诗','song-poetry','','[]','軍功閣束萬人多，兵部門前雀可羅。',32,'全唐诗/poet.song.213000.json','["軍功閣束萬人多，兵部門前雀可羅。", "悍將武夫心失盡，可知棄甲與投戈。"]'),
('feba7bf8-05db-4fe6-b1dd-96b85725ea5f','孤憤吟十三首  其五','高斯得','宋','宋诗','song-poetry','','[]','國家元氣是人材，稍露光芒盡力摧。',32,'全唐诗/poet.song.213000.json','["國家元氣是人材，稍露光芒盡力摧。", "今日舉朝皆婦女，邦衡此語亦誠哉。"]'),
('f155cf29-13c5-4368-a02e-0647ce761b90','孤憤吟十三首  其六','高斯得','宋','宋诗','song-poetry','','[]','掃除學法啗諸生，精銳銷磨直可坑。',32,'全唐诗/poet.song.213000.json','["掃除學法啗諸生，精銳銷磨直可坑。", "乞斬三姦亦人爾，汝曹何忍負齋黌。"]'),
('5bf6ba8b-f4be-4ee3-a234-479cdf4cae4e','孤憤吟十三首  其七','高斯得','宋','宋诗','song-poetry','','[]','無罪無辜竄逐人，幾經大霈不霑恩。',32,'全唐诗/poet.song.213000.json','["無罪無辜竄逐人，幾經大霈不霑恩。", "更將改正張羅網，結盡千千萬萬冤。"]'),
('b6edecb1-a280-4572-b306-2f9359c8de35','孤憤吟十三首  其八','高斯得','宋','宋诗','song-poetry','','[]','彊買民田自噬膚，大家破盡爲催租。',32,'全唐诗/poet.song.213000.json','["彊買民田自噬膚，大家破盡爲催租。", "幾多怨氣沖霄漢，天欲無誅可得乎。"]'),
('5bfccdeb-2a6b-43d9-9485-b9ee3f7d111c','孤憤吟十三首  其九','高斯得','宋','宋诗','song-poetry','','[]','督帳行趨建業東，壯哉迎敵氣如虹。',32,'全唐诗/poet.song.213000.json','["督帳行趨建業東，壯哉迎敵氣如虹。", "勸君猛捨一腔血，莫學檀公誤乃翁。"]'),
('8c1e8478-377b-42be-887a-5675514d8dbd','孤憤吟十三首  其一○','高斯得','宋','宋诗','song-poetry','','[]','乘桴頤浩元無策，進蹕豐公妙達權。',32,'全唐诗/poet.song.213000.json','["乘桴頤浩元無策，進蹕豐公妙達權。", "寧死老身終不去，太皇此語可回天。"]'),
('200f00fe-041b-4597-aad7-e28c14b3e651','孤憤吟十三首  其一一','高斯得','宋','宋诗','song-poetry','','[]','覆按山陵挈累行，金多季子橐齎輕。',32,'全唐诗/poet.song.213000.json','["覆按山陵挈累行，金多季子橐齎輕。", "殿中御史尤堪戮，盡室逃歸駭一城。"]'),
('0c639d64-7245-4170-85c9-01a1934f8f67','孤憤吟十三首  其一二','高斯得','宋','宋诗','song-poetry','','[]','囊封癸酉罄愚惷，第一親征次守江。',32,'全唐诗/poet.song.213000.json','["囊封癸酉罄愚惷，第一親征次守江。", "啼得血流無用處，自憐弱步要豐扛。"]'),
('fb0ea244-7afe-445c-a9ce-d4267be2096f','孤憤吟十三首  其一三','高斯得','宋','宋诗','song-poetry','','[]','阜錄新書幸已成，名山藏去復傳人。',32,'全唐诗/poet.song.213000.json','["阜錄新書幸已成，名山藏去復傳人。", "毋令十載編摩苦，竟與家書共厄秦。"]'),
('640a7398-a2b7-4fbf-bafd-8d2a3ca6f169','聞楊元極去國','高斯得','宋','宋诗','song-poetry','','[]','傾厦難將一木支，微垣累疏亦何爲。',32,'全唐诗/poet.song.213000.json','["傾厦難將一木支，微垣累疏亦何爲。", "鳳凰本自翔千仞，不待區區奪我池。"]'),
('124fa492-1897-4051-ab5d-c4033eac90bf','題愛梅亭','高斯得','宋','宋诗','song-poetry','','[]','生世梅花是故知，相逢不負歲寒期。',32,'全唐诗/poet.song.213000.json','["生世梅花是故知，相逢不負歲寒期。", "自從一點梢頭白，看到青陰弄實時。"]'),
('b6a605f3-6f53-48e2-99b9-ca327f7fdb63','題同濂閣','高斯得','宋','宋诗','song-poetry','','[]','霽月光風灑落人，與君同調故憐君。',32,'全唐诗/poet.song.213000.json','["霽月光風灑落人，與君同調故憐君。", "不須嘆息知音少，後世豈無揚子雲。"]'),
('54b41ca3-150e-4ae0-99fd-336bd91c0635','台州宴包知府樂語','高斯得','宋','宋诗','song-poetry','','[]','使君五馬日邊來，猶是當年逸驥才。',64,'全唐诗/poet.song.213000.json','["使君五馬日邊來，猶是當年逸驥才。", "漢竹光榮知妙簡，召棠蔽芾喜重栽。", "試聽孝肅傳新令，竚看文清拜首台。", "盛事難逢須爛醉，樓頭玉漏莫相催。"]'),
('63f24462-4560-4321-8fab-327dc12f5069','宴建寧知府趙尚書樂語','高斯得','宋','宋诗','song-poetry','','[]','本意苕溪老釣蓬，乘軺來訪玉仙翁。',64,'全唐诗/poet.song.213000.json','["本意苕溪老釣蓬，乘軺來訪玉仙翁。", "並遊元自從迂叟，將漕何妨拜潞公。", "宿世神交雙劍合，平生心事一樽同。", "乾坤整頓須公等，夜掣鈴絛紫禁風。"]'),
('dd94def3-4767-4fb7-93df-86606e502bdb','建寧府宴徐意一知院樂語','高斯得','宋','宋诗','song-poetry','','[]','幅巾支杖勇還鄉，昨夜方開晝錦堂。',64,'全唐诗/poet.song.213000.json','["幅巾支杖勇還鄉，昨夜方開晝錦堂。", "司馬高風傾國慕，韓公晚節襲人香。", "已忻綠野脩初服，好爲丹山酹一觴。", "卜夜莫嫌秋漏永，仙翁鶴骨儘康强。"]'),
('5f7b8c99-ec17-4b36-8b5e-0738fe8c1b5d','次魏明己表弟韻送劉長翁赴福建倉','高斯得','宋','宋诗','song-poetry','','[]','玉皇拔西珍，金節撫南服。',240,'全唐诗/poet.song.213000.json','["玉皇拔西珍，金節撫南服。", "雄稜摺荒陬，祥飆扇寒谷。", "長孺振河內，相如諭巴蜀。", "唯昔垂鴻名，于今躡遐躅。", "墨夫跼一迹，赤子懸萬目。", "周原重華遣，漢庭愜剸屬。", "棲粱飽群鴻，復陂歌兩鵠。", "欽哉使指將，俾爾民命續。", "寧虛獨坐三，與布寬條六。", "豈伊於粵陋，獨占京東福。", "盍朝翠雲裘，重佩水蒼玉。", "危枰活枯棋，駭浪安巨舳。", "儒登朝廷尊，賢聚功化速。", "匪惟密親願，茲謂蒼生祝。", "攀援駟馬車，惆悵驪駒曲。", "音塵慰寂蔑，炯介在明淑。", "贈言希古人，陳義詭流俗。", "謹毋千倉求，惟先百姓足。", "道學振考亭，文風傾嶽麓。", "庶幾七閩人，勿替千禩肅。"]'),
('20a138c9-a01d-4dce-857e-8ec62b96682a','群玉山留題','謝奕修','宋','宋诗','song-poetry','','[]','天竺呼猿未當奇，化工鎪剔亦應疲。',32,'全唐诗/poet.song.213000.json','["天竺呼猿未當奇，化工鎪剔亦應疲。", "漫山盡是玲瓏玉，却笑名園以假爲。"]'),
('69a26c4d-aa4a-4ff6-b2ea-213936e6351a','琴歌','王謹禮','宋','宋诗','song-poetry','','[]','低露下，深幕垂，月照孤琴空絃咽，宵淚誰憐此夜心。',24,'全唐诗/poet.song.213000.json','["低露下，深幕垂，月照孤琴空絃咽，宵淚誰憐此夜心。"]'),
('f2cda083-60f3-4470-8d97-8b0584894c4c','西湖','王南一','宋','宋诗','song-poetry','','["\u897f\u6e56"]','翠巘嵯峨插斗牛，仙家風景自清幽。',64,'全唐诗/poet.song.213000.json','["翠巘嵯峨插斗牛，仙家風景自清幽。", "從來此縣傳佳讖，就築西湖占上流。", "層塔可梯升後進，五峰有路達前修。", "邦人接踵登科去，我亦京華共宦遊。"]'),
('5d63ce54-e64f-479b-944c-98568f75db4a','閫相可翁先生偕王人有湖山游獲侍坐先生有詩輒用韻','豐茝','宋','宋诗','song-poetry','','[]','西郊陪衮繡，雲步入千山。',48,'全唐诗/poet.song.213000.json','["西郊陪衮繡，雲步入千山。", "行樂五星聚，浮生半日閒。", "尋棋楓葉下，載酒藕花間。", "譚笑長城在，何人敢度關。"]'),
('cd7559ba-264a-495e-9fe0-14f558bcdc06','應舉早行','繆蟾','宋','宋诗','song-poetry','','[]','半戀家山半戀牀，起來顛倒著衣裳。',64,'全唐诗/poet.song.213000.json','["半戀家山半戀牀，起來顛倒著衣裳。", "鐘聲遠和雞聲雜，燈影斜侵劍影光。", "路崎嶇兮憑竹杖，月朦朧處認梅香。", "功名苦我雙關足，踏破前橋幾板霜。"]'),
('46b4b4f3-c54d-4a49-9c67-5a34cca626f3','賀山','徐灼','宋','宋诗','song-poetry','','[]','昔人來隱遯，茲山始得名。',48,'全唐诗/poet.song.213000.json','["昔人來隱遯，茲山始得名。", "巖扃鎖積翠，石罅流餘清。", "花石今何在，菁茅久已生。", "爲言唐賀老，千載有殊情。"]'),
('0e708bff-20a5-4c63-98df-0eaab885a6e4','大滌洞  其一','顧然','宋','宋诗','song-poetry','','[]','清涼不着人間暑，三伏來遊九鎖山。',32,'全唐诗/poet.song.213000.json','["清涼不着人間暑，三伏來遊九鎖山。", "箬底神丹末須問，平生寧有此時來。"]'),
('26a635e9-476a-4a94-a958-d4ba5f263c36','大滌洞  其二','顧然','宋','宋诗','song-poetry','','[]','山頭赤日炙手熱，簷底鳴泉玉擊樅。',32,'全唐诗/poet.song.213000.json','["山頭赤日炙手熱，簷底鳴泉玉擊樅。", "慚愧龍公作餘戲，夢中渾認雨翻江。"]'),
('c00c1391-b51c-4585-adf1-081537fbcd2c','淳祐己酉月正人日春雨堂宴三學同舍即事','鄭霖','宋','宋诗','song-poetry','','[]','十年隨牒訪三高，不覺星星上鬢毛。',64,'全唐诗/poet.song.213000.json','["十年隨牒訪三高，不覺星星上鬢毛。", "尚憶齏鹽形夜夢，聊因椒柏薦春醪。", "文盟再會知何日，臭味相投屬我曹。", "總是虞庠舊培植，致君當不愧夔皋。"]'),
('7e6f4dd8-083b-4018-9316-ad00704e1dfc','提刑曾寶章宴安撫陳侍郎樂語','鄭霖','宋','宋诗','song-poetry','','[]','聽得敷綸天上頭，二星交會玉虹流。',64,'全唐诗/poet.song.213000.json','["聽得敷綸天上頭，二星交會玉虹流。", "風生三路軍容壯，春到雙江喜氣浮。", "談笑預知傳露布，勸酬只恐促更籌。", "會看印佩黄金斗，肯羨當年定遠侯。"]'),
('fbca985f-0814-4135-b104-a361c9c8f420','安撫陳侍郎宴曾提刑樂語','鄭霖','宋','宋诗','song-poetry','','[]','恰好鶯花一半春，福星相會贛江濱。',64,'全唐诗/poet.song.213000.json','["恰好鶯花一半春，福星相會贛江濱。", "丈人師吉符前讖，膚使心同掃舊塵。", "看劍引盃宜酩酊，輕裘緩带倍精神。", "從今浄洗天河甲，有詔催歸兩重臣。"]'),
('c7672a79-5c9f-4384-b1be-883b69eafe15','彭知軍宴交代都運陳寶章樂語','鄭霖','宋','宋诗','song-poetry','','[]','使軺嚴戒鼓逢逢，熊軾頒春到此邦。',64,'全唐诗/poet.song.213000.json','["使軺嚴戒鼓逢逢，熊軾頒春到此邦。", "炳炳福星臨一道，融融愛日照橫江。", "斷霞秋日閑飛鶩，荒草寒烟不吠厖。", "臺府交歡同一體，從今俗返古淳龐。"]'),
('f6607942-6c69-4c72-bb9d-4f4f287ce30b','贈無擇老禪因觀稼  其一','鄭霖','宋','宋诗','song-poetry','','[]','兩年風雨爲民愁，那得偷閒物外遊。',32,'全唐诗/poet.song.213000.json','["兩年風雨爲民愁，那得偷閒物外遊。", "誰謂秋鴻留爪甲，吳儂一稔展眉頭。"]'),
('4a17efd2-6a09-4eec-b5c8-39fc4e07f13f','贈無擇老禪因觀稼  其二','鄭霖','宋','宋诗','song-poetry','','[]','每謁祠堂憇虎邱，山僧煮茗雪花浮。',32,'全唐诗/poet.song.213000.json','["每謁祠堂憇虎邱，山僧煮茗雪花浮。", "陸泉便作曹溪會，引得清風話未休。"]'),
('e03f5f11-0ba3-4dd0-84bf-47d51723883d','劍池','鄭霖','宋','宋诗','song-poetry','','[]','屬鏤堪爲後人傷，池溜清泉有恨長。',32,'全唐诗/poet.song.213000.json','["屬鏤堪爲後人傷，池溜清泉有恨長。", "不斬妖邪斬忠直，淡烟荒草鹿麋場。"]'),
('25d28285-0f07-4084-99de-920fe9ff3bb3','集仙納凉','鄭霖','宋','宋诗','song-poetry','','[]','縣灘如沸鼎，玄館足清幽。',48,'全唐诗/poet.song.213000.json','["縣灘如沸鼎，玄館足清幽。", "竹逕不留暑，蓮池先借秋。", "學仙師有訣，戀祿我懷羞。", "安得雙鳬舄，乘風八極游。"]'),
('3193f2e0-da9c-4fb8-803e-3e5be0c9bcdc','閲武喜晴和厲寺正韻','游清夫','宋','宋诗','song-poetry','','[]','閲武堂前宿雨晴，柳營刁斗五更鳴。',64,'全唐诗/poet.song.213000.json','["閲武堂前宿雨晴，柳營刁斗五更鳴。", "風生貔虎誇身健，日射旌旗照眼明。", "管領春光三月暮，雕鎸詩句十分清。", "折衝樽俎今餘事，自有胸中十萬兵。"]'),
('4e43853f-fa2f-409b-a98d-c40b26d2d869','面香閣','戴逸卿','宋','宋诗','song-poetry','','[]','邑事日填委，汩汩勞其生。',60,'全唐诗/poet.song.213000.json','["邑事日填委，汩汩勞其生。", "攬衣登茲樓，便覺神思清。", "茂林鬰松桂，好山列檐楹。", "景物自瀟灑，有酒誰共傾。", "故園隔蒼嶺，行當脫塵纓。"]'),
('c80ef8bd-ea3f-40d0-a52b-80481ac51eec','寒亭','莊元戌','宋','宋诗','song-poetry','','[]','亭當六月猶冰□，谷到三冬似焰吹。',32,'全唐诗/poet.song.213000.json','["亭當六月猶冰□，谷到三冬似焰吹。", "會得漫郎題品意，愛它冷暖不隨時。"]'),
('df960d31-92dc-4b53-a662-be0f60b6da75','讀馬援傳','黄伯樞','宋','宋诗','song-poetry','','[]','後車薏苡落讒人，珠貝文犀竟失真。',32,'全唐诗/poet.song.213000.json','["後車薏苡落讒人，珠貝文犀竟失真。", "馬革裹尸猶不恨，何須勝瘴與輕身。"]'),
('6137fafe-80dc-4787-b6b5-d587aafc8c52','和陳子華武夷築精舍','葉明','宋','宋诗','song-poetry','','[]','衮衮諸公臺省居，可憐無地著吾廬。',64,'全唐诗/poet.song.213000.json','["衮衮諸公臺省居，可憐無地著吾廬。", "前因本是四禪派，今日相追九老圖。", "憂顧全閩曾倚重，誅鋤遺孽豈容逋。", "兔葵燕麥玄都滿，休憶桃霞映綠湖。"]'),
('77f7affd-4502-4442-89d6-c74d60666a25','題馮唐廟','葉明','宋','宋诗','song-poetry','','[]','千百年來漢老郎，曉來燈火晚來香。',32,'全唐诗/poet.song.213000.json','["千百年來漢老郎，曉來燈火晚來香。", "庭前不用尋碑記，已載班書數十行。"]'),
('bae17f3c-2c38-4b8c-bf06-4f86c9c37bd6','題合浦守袁梧像','林溥','宋','宋诗','song-poetry','','[]','大造無私只一中，歷公五任協民風。',64,'全唐诗/poet.song.213000.json','["大造無私只一中，歷公五任協民風。", "景星三出南台瑞，邊驛千章北海忠。", "日映彤弓開嶺北，龍翔滄海啟江東。", "只因外補功名損，可恨車音萬里空。"]'),
('3f675b2b-7dce-4f9e-9723-a59fb8419f66','浄土寺追和東坡韻','楊棟','宋','宋诗','song-poetry','','[]','令君督來期，書郵日旁午。',144,'全唐诗/poet.song.213000.json','["令君督來期，書郵日旁午。", "世事不足論，清游乃先務。", "朝朝叩禪關，復此得浄宇。", "淺斟琥珀濃，細嚼銀絲縷。", "味雋問牛酥，軒高來燕乳。", "曲折溪屢橫，尖圓峰可數。", "萬頃喧桑田，一簇靜松塢。", "由來鏡中人，不殊草頭露。", "越主朝汴宮，蜀客盡吳語。", "剝蝕浄土碑，荒殘峽山路。", "桑梓如之何，誰能忘一顧。", "日詢錦橋新，三歎清流俯。"]'),
('a111fe14-21ec-438c-86e7-3a4b325fba98','游大滌棲真洞  其一','楊棟','宋','宋诗','song-poetry','','[]','携手清苕去，高楓丹葉森。',48,'全唐诗/poet.song.213000.json','["携手清苕去，高楓丹葉森。", "漁樵九鎖曲，風雨一窗深。", "索酒貪山月，添衣怯洞陰。", "鳳歸天柱曉，樓閣有鳴琴。"]'),
('0fa27e5c-c59c-421f-8215-332fa5f0091b','游大滌棲真洞  其二','楊棟','宋','宋诗','song-poetry','','[]','山峨來夾案，泉急自穿渠。',48,'全唐诗/poet.song.213000.json','["山峨來夾案，泉急自穿渠。", "密記東陽訣，高題上帝居。", "牙兒藏寶篋，山子走籃輿。", "曲折璣衡轉，溪坳可結廬。"]'),
('88f80675-a0f7-4962-bbe6-4a9c35e03624','丁巳再游題蓬山堂泉石','楊棟','宋','宋诗','song-poetry','','[]','瓊流鑒空，混沌一隙。',20,'全唐诗/poet.song.213000.json','["瓊流鑒空，混沌一隙。", "紫霄柱下，清泉白石。"]'),
('43ea47bf-989f-4974-8e1d-f5ca8e55c3ca','遊龍光寺','胡大成','宋','宋诗','song-poetry','','[]','香宇依空結，虛軒傍水開。',48,'全唐诗/poet.song.213000.json','["香宇依空結，虛軒傍水開。", "沙明鴻影度，逕靜竹風來。", "午磬傳清梵，晴花點綠苔。", "寥寥人境外，宴坐送餘杯。"]'),
('3bf0d3e5-067b-494c-b52d-5bb884d39216','三脆麵','趙密夫','宋','宋诗','song-poetry','','[]','筍蕈初萌杞採纖，燃松自煮供親嚴。',32,'全唐诗/poet.song.213000.json','["筍蕈初萌杞採纖，燃松自煮供親嚴。", "人間玉食何曾鄙，自是山林滋味甜。"]'),
('bd418b1f-139f-4aba-8f1b-9fdd57263023','梅花','盛文韶','宋','宋诗','song-poetry','','[]','翠羽啁啾夜，空山偃蹇時。',48,'全唐诗/poet.song.213000.json','["翠羽啁啾夜，空山偃蹇時。", "看人多冷眼，出手盡高枝。", "香細巡檐得，寒深踏雪知。", "紛紛後來者，紅紫莫矜奇。"]'),
('d51cb301-9a1f-411a-abb2-97c122164704','題東洞','陳宗臣','宋','宋诗','song-poetry','','[]','蔚藍勝概世應稀，中有高人隠翠微。',32,'全唐诗/poet.song.213000.json','["蔚藍勝概世應稀，中有高人隠翠微。", "那日徵書來古洞，恩光榮耀倍山輝。"]'),
('52929c51-9c4e-4542-81b7-d943092c1772','海棠','陳松龍','宋','宋诗','song-poetry','','[]','移根千里入名園，酒暈紅嬌氣欲昏。',32,'全唐诗/poet.song.213000.json','["移根千里入名園，酒暈紅嬌氣欲昏。", "待得太真春睡醒，風光已不似開元。"]'),
('390c9f37-d3c4-4fd4-a2f5-cbad5c43fcac','酴醾','陳松龍','宋','宋诗','song-poetry','','[]','布葉敷條翠作圍，自生芒刺護裳衣。',32,'全唐诗/poet.song.213000.json','["布葉敷條翠作圍，自生芒刺護裳衣。", "莫嫌野興難拘束，只伴春風亦見幾。"]'),
('8da106ae-8562-4d41-a6e7-7563bd11c50a','贈菴僧','陳松龍','宋','宋诗','song-poetry','','[]','獨羨爲僧者，塵緣不到門。',48,'全唐诗/poet.song.213000.json','["獨羨爲僧者，塵緣不到門。", "采薪松落子，移徑竹生孫。", "古井汲雲氣，寒山招月魂。", "猶憐生死海，應□出前村。"]'),
('1217c5e3-c98d-4f5a-97ce-e874eafeb157','句  其一','陳松龍','宋','宋诗','song-poetry','','[]','梨花春二月，杜宇夜三更。',12,'全唐诗/poet.song.213000.json','["梨花春二月，杜宇夜三更。"]'),
('517d234a-5936-4f51-9372-94c0feaa8bdb','句  其二','陳松龍','宋','宋诗','song-poetry','','[]','庭暗梨花疑有月，堤晴楊柳自生烟。',16,'全唐诗/poet.song.213000.json','["庭暗梨花疑有月，堤晴楊柳自生烟。"]'),
('c84010c6-49a9-43cf-9cb6-a6e794c0e2b8','句  其三','陳松龍','宋','宋诗','song-poetry','','[]','薦菊明詩眼，看梅長道心。',12,'全唐诗/poet.song.213000.json','["薦菊明詩眼，看梅長道心。"]'),
('7ea3abdf-c3bb-419f-b9f8-89af3aac74bb','懷友李衜行','趙希{東彡}','宋','宋诗','song-poetry','','[]','鷗聚情方洽，如何又別離。',48,'全唐诗/poet.song.213000.json','["鷗聚情方洽，如何又別離。", "盍簪無甚樂，判袂覺凄其。", "有約常逾歲，相逢未有期。", "登臨閒散處，悵望日輪西。"]'),
('40096e57-03fc-40eb-bd0b-5b0486bae567','和宋伯仁韻','李景雷','宋','宋诗','song-poetry','','[]','自笑馮唐老未侯，短衣匹馬異鄉遊。',64,'全唐诗/poet.song.213000.json','["自笑馮唐老未侯，短衣匹馬異鄉遊。", "卧聞破屋蕭蕭雨，坐聽西風葉葉秋。", "鄴下已非公幹在，周南徒歎子長留。", "丈夫蓋世英雄氣，肯學世間兒女愁。"]'),
('d542edd2-a836-4282-9755-d548063a2463','穀','趙孟淳','宋','宋诗','song-poetry','','[]','農夫怨，農夫怨，此怨非是怨年荒，此怨翻因年穀賤。',104,'全唐诗/poet.song.213000.json','["農夫怨，農夫怨，此怨非是怨年荒，此怨翻因年穀賤。", "終年辛苦不少懈，及到秋成擬償債。", "誰知斛粟不百錢，利尚不償本仍在。", "秋來露冷刈穫時，早是朝來債又催。", "况兼荒政輸官急，不管農夫垂淚泣。", "君王明哲洞無遺，此怨君王知不知。"]'),
('cf0000a8-791b-4711-9b23-c75ea6e1be5b','題高尚書夜山圖二首  其一','趙孟淳','宋','宋诗','song-poetry','','[]','月底江山如晝好，樓中几席與秋清。',32,'全唐诗/poet.song.213000.json','["月底江山如晝好，樓中几席與秋清。", "剡藤不到高人手，一段風流可得成。"]'),
('d3ec4f0d-2bfe-43cd-9c7f-fde6bfb6c58b','題高尚書夜山圖二首  其二','趙孟淳','宋','宋诗','song-poetry','','[]','江行山立月盤桓，有客無言樓上看。',32,'全唐诗/poet.song.213000.json','["江行山立月盤桓，有客無言樓上看。", "清興肯隨城漏盡，夜深風露恐高寒。"]'),
('20e2957c-578f-4838-83fd-a29196b04cf2','題桃','趙孟淳','宋','宋诗','song-poetry','','[]','滴粉挼酥暈幾重，風前紅雨一枝濃。',32,'全唐诗/poet.song.213000.json','["滴粉挼酥暈幾重，風前紅雨一枝濃。", "世間是色皆爲妄，除却夭桃單種松。"]'),
('05deea2d-860a-436d-83c5-c36d82d63003','題梅','趙孟淳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雪意垂垂浸碧虛，香生一縷上琴書。',32,'全唐诗/poet.song.213000.json','["雪意垂垂浸碧虛，香生一縷上琴書。", "何須百萬西湖宅，遇有梅花便可居。"]'),
('601daa00-252f-49f6-b32d-9cd54664e504','句','趙孟淳','宋','宋诗','song-poetry','','[]','落花遇雨掃不去，敗草經春剗又生。',16,'全唐诗/poet.song.213000.json','["落花遇雨掃不去，敗草經春剗又生。"]'),
('4eb3c80a-21d6-41d0-8355-8aaf6c3d520a','唐玄宗鐵像','熊與龢','宋','宋诗','song-poetry','','[]','巍冠攢疊碧雲花，坐閲山中幾歲華。',32,'全唐诗/poet.song.213000.json','["巍冠攢疊碧雲花，坐閲山中幾歲華。", "莫把金丹輕點化，正愁生死困安家。"]'),
('46e7a4ff-56d7-477e-a5f9-31bffb2c874c','木平飼龍亭次韻方巨山','熊與龢','宋','宋诗','song-poetry','','[]','耳見何如得眼聞，山根磅礴極初分。',64,'全唐诗/poet.song.213000.json','["耳見何如得眼聞，山根磅礴極初分。", "浮漚起滅自潭影，大地晴陰空嶺雲。", "何處老人來聽講，他年少府有移文。", "由來清調須吾輩，幸不山王愧五君。"]'),
('6ac68d92-685d-4b13-9806-17b0ebe7116b','鶯脰湖','趙時遠','宋','宋诗','song-poetry','','[]','鶯去湖存事渺茫，梵宮占斷水雲鄉。',64,'全唐诗/poet.song.213000.json','["鶯去湖存事渺茫，梵宮占斷水雲鄉。", "四圍煙樹浪濤闊，六月橋亭風露涼。", "遠近征帆歸別浦，高低漁網掛斜陽。", "翠微深處一聲笛，驚起眠沙鷗鷺行。"]'),
('0401a302-ee52-4996-809e-677955fc038d','四景詩和孫僉判穎叔韻 荻塘柳影','趙時遠','宋','宋诗','song-poetry','','[]','午天雲淡日遲遲，水面長條带影垂。',32,'全唐诗/poet.song.213000.json','["午天雲淡日遲遲，水面長條带影垂。", "不是纖腰渾不定，自緣無力受風吹。"]'),
('05df7723-f6d6-4f48-b837-3ef6af15d6d5','四景詩和孫僉判穎叔韻 禪院風荷','趙時遠','宋','宋诗','song-poetry','','[]','荷風細細晚生涼，暑氣絪縕入座香。',32,'全唐诗/poet.song.213000.json','["荷風細細晚生涼，暑氣絪縕入座香。", "飲盡碧筒人笑語，花邊驚起睡鴛鴦。"]'),
('80f39dda-f357-46f0-b381-fa9582131d52','四景詩和孫僉判穎叔韻 平湖秋月','趙時遠','宋','宋诗','song-poetry','','[]','樓臺兩岸枕長流，落日行人競檥舟。',32,'全唐诗/poet.song.213000.json','["樓臺兩岸枕長流，落日行人競檥舟。", "清夜湖光平似鏡，冰輪冷浸玉壺秋。"]'),
('d8cec1fe-cd0b-4225-8fc1-c8351fa9f41a','四景詩和孫僉判穎叔韻 仙磯晴雪','趙時遠','宋','宋诗','song-poetry','','[]','斂盡同雲放日暉，寒光凜凜透重衣。',32,'全唐诗/poet.song.213000.json','["斂盡同雲放日暉，寒光凜凜透重衣。", "扁舟清曉尋溪轉，髣髴王猷訪戴歸。"]'),
('daea11c0-0548-483e-9a2e-5c9c29a8f8b7','詠楊妃菊','李山節','宋','宋诗','song-poetry','','[]','命委馬嵬坡畔泥，驚魂飛上傲霜枝。',32,'全唐诗/poet.song.213000.json','["命委馬嵬坡畔泥，驚魂飛上傲霜枝。", "西風落日東籬下，薄倖三郎知不知。"]'),
('5435b59d-871a-4d1d-ad69-42a33f661ec9','發長沙','釋紹嵩','宋','宋诗','song-poetry','','[]','秋入長沙縣，無人畫得成。',48,'全唐诗/poet.song.213000.json','["秋入長沙縣，無人畫得成。", "晚風輕浪疊，落日亂蛩鳴。", "一雨洗煩暑，千山指去程。", "回期誰可定，行樂且吾生。"]'),
('abd90a0d-6007-47c4-9586-97e29a538238','舟發清江','釋紹嵩','宋','宋诗','song-poetry','','[]','穩泛一船東，生涯真轉蓬。',48,'全唐诗/poet.song.213000.json','["穩泛一船東，生涯真轉蓬。", "煙浮平野碧，波軟夕陽紅。", "浦樹家家異，風光處處同。", "回看蒼木杪，眼界入雲中。"]'),
('eb522067-05be-43b0-a3aa-48d7e7f5eac0','感山書事','釋紹嵩','宋','宋诗','song-poetry','','[]','愛此棲心靜，陶然度歲華。',48,'全唐诗/poet.song.213000.json','["愛此棲心靜，陶然度歲華。", "放慵真有味，化俗獨無涯。", "隔沼連香芰，疎籬带晚花。", "細評清絕處，倚杖看蜂衙。"]'),
('fc882160-14d5-4451-8786-7087fe083bc8','曲江解舟','釋紹嵩','宋','宋诗','song-poetry','','[]','動靜非常態，此行風正秋。',48,'全唐诗/poet.song.213000.json','["動靜非常態，此行風正秋。", "巉巉孤棹起，渺渺大江流。", "蟬噪日將落，煙生山欲浮。", "無心與時競，吟凭釣魚舟。"]'),
('0affbc8e-045b-437f-9031-92142d1d7087','江亭小憩','釋紹嵩','宋','宋诗','song-poetry','','[]','不到茲亭久，軒窗眼界開。',48,'全唐诗/poet.song.213000.json','["不到茲亭久，軒窗眼界開。", "江流翻白浪，樹影掃青苔。", "有鳥銜花出，無人送酒來。", "快然心自適，此地亦悠哉。"]'),
('a0c1d4d4-0945-4a43-9a44-f9aac0aa797e','舟中口號','釋紹嵩','宋','宋诗','song-poetry','','[]','閤皁風煙外，殘蟬送客愁。',48,'全唐诗/poet.song.213000.json','["閤皁風煙外，殘蟬送客愁。", "雲連平地起，水带斷槎流。", "樹隠重重竹，江呈岸岸秋。", "晚來供望眼，微徑雜歸牛。"]'),
('d279dbd1-5a18-4670-bbc2-6c6c9d34dda7','臨川道中','釋紹嵩','宋','宋诗','song-poetry','','[]','歷歷沿荒岸，初聞落日蟬。',48,'全唐诗/poet.song.213000.json','["歷歷沿荒岸，初聞落日蟬。", "江花鋪淺水，村館復臨川。", "徑仄傍無地，峰回別有天。", "吾行吾自返，茲意與誰傳。"]'),
('5f81976e-52f3-4278-b265-0a0f297dba57','客思','釋紹嵩','宋','宋诗','song-poetry','','[]','欲暮多覊思，客行悲故鄉。',48,'全唐诗/poet.song.213000.json','["欲暮多覊思，客行悲故鄉。", "背關餘古木，落葉墮寒霜。", "驛樹收殘雨，柴門掩夕陽。", "此身南復北，雙鬢易蒼浪。"]'),
('66801abd-ada3-4a4c-a040-b8cafc45e17d','遊古寺次朋上人韻','釋紹嵩','宋','宋诗','song-poetry','','[]','黄葉前朝寺，携朋上故基。',48,'全唐诗/poet.song.213000.json','["黄葉前朝寺，携朋上故基。", "近山煙外遠，芳草露中衰。", "磧磧風吹面，霏霏雨散池。", "旅情何計是，排悶强裁詩。"]'),
('c2ac2302-2993-479d-a09c-f404725880b6','旅次','釋紹嵩','宋','宋诗','song-poetry','','[]','樹勢分孤壘，江流復舊痕。',48,'全唐诗/poet.song.213000.json','["樹勢分孤壘，江流復舊痕。", "斷橋斜取路，小徑曲通村。", "山疊雲霞際，林垂橘柚繁。", "箇中有佳句，欲就已忘言。"]'),
('a5b2cc9f-031d-4521-b5e3-f5a376915d5a','晚泊丫頭巖','釋紹嵩','宋','宋诗','song-poetry','','[]','旅泊依村樹，高吟似得隣。',48,'全唐诗/poet.song.213000.json','["旅泊依村樹，高吟似得隣。", "斜風吹敗葉，落日照行塵。", "擾擾成何事，飄飄任此身。", "客心君莫問，贏得鬢如銀。"]'),
('4f381f77-8d45-4b7b-86d2-544d01417577','道中即事','釋紹嵩','宋','宋诗','song-poetry','','[]','饒水回回轉，白雲西復東。',48,'全唐诗/poet.song.213000.json','["饒水回回轉，白雲西復東。", "日斜喧急雨，天闊退飛鴻。", "薄暮沿西峽，隆寒正北風。", "茲行有勝事，未敢歎途窮。"]'),
('7e4976c4-506e-4f0c-84da-6c8db25bd68a','舟中值雨','釋紹嵩','宋','宋诗','song-poetry','','[]','客路雨連日，吾生良可嗟。',48,'全唐诗/poet.song.213000.json','["客路雨連日，吾生良可嗟。", "蕭蕭打蓬急，脈脈受風斜。", "野望迷青草，江聲走白沙。", "今宵何處宿，欹枕聽鳴蛙。"]'),
('2ba15a0c-9cb2-424f-aa0e-4abbb8a70395','題山寺','釋紹嵩','宋','宋诗','song-poetry','','[]','江上山頭寺，陰階竹掃苔。',48,'全唐诗/poet.song.213000.json','["江上山頭寺，陰階竹掃苔。", "舟橫漁唱晚，松暮鶴飛回。", "野渡花爭發，春荷葉半開。", "嬉遊不可極，留眼要重來。"]'),
('991457bc-04d8-4888-962a-16d1bd0fa8ba','憩江寺','釋紹嵩','宋','宋诗','song-poetry','','[]','衆岫聳寒色，長溪抱碧岑。',48,'全唐诗/poet.song.213000.json','["衆岫聳寒色，長溪抱碧岑。", "波傾三峽急，樹合四時陰。", "野寺江天豁，禪房花木深。", "幽簾宜永日，閑坐聽春禽。"]'),
('003568d1-29b1-497b-a15b-a0559ae1af81','題園菴','釋紹嵩','宋','宋诗','song-poetry','','[]','地僻無賓侶，林疎露短籬。',48,'全唐诗/poet.song.213000.json','["地僻無賓侶，林疎露短籬。", "紫鱗衝晚浪，白鳥占閑池。", "柳色濃垂岸，桃花濕滿枝。", "一僧年八十，邀我覓新詩。"]'),
('f513838c-ba42-4b23-b8d0-016cc4535753','江上','釋紹嵩','宋','宋诗','song-poetry','','[]','弱柳垂江翠，驚湍拍岸浮。',48,'全唐诗/poet.song.213000.json','["弱柳垂江翠，驚湍拍岸浮。", "煙生山欲盡，春半水爭流。", "棹倚袁宏渚，雲凝庾信愁。", "艱難念時事，衰謝不能休。"]'),
('60fecb7b-2ce5-4578-9f0d-f6c8394fc5ae','偶作','釋紹嵩','宋','宋诗','song-poetry','','[]','孤錫依京寺，悠悠過一生。',48,'全唐诗/poet.song.213000.json','["孤錫依京寺，悠悠過一生。", "有山供傑句，無地可歸耕。", "燕競波中影，棋添局上聲。", "流年衰此世，寂寞不勝情。"]'),
('8e936462-23c0-42f8-9b6c-aa3ae3618f6f','言命','釋紹嵩','宋','宋诗','song-poetry','','[]','宇宙雙蓬鬢，昇沉儘聽他。',48,'全唐诗/poet.song.213000.json','["宇宙雙蓬鬢，昇沉儘聽他。", "僧居隨處好，身事逐年多。", "異國逢佳節，流光等逝波。", "無謀長委命，言命欲如何。"]'),
('156bacfe-2305-4c7c-9c15-7f4f2e087946','題靈隠','釋紹嵩','宋','宋诗','song-poetry','','[]','古剎藏幽勝，山門九里松。',48,'全唐诗/poet.song.213000.json','["古剎藏幽勝，山門九里松。", "飛空花片片，落澗水淙淙。", "葉積池邊路，雲生戶外峰。", "幾因留我宿，吟到五更鍾。"]'),
('9c255080-4418-40a5-9975-02ea88feea62','野眺有感','釋紹嵩','宋','宋诗','song-poetry','','[]','流落復蹉跎，生涯總幾何。',48,'全唐诗/poet.song.213000.json','["流落復蹉跎，生涯總幾何。", "羈遊故交少，歸思夜深多。", "縱目懷青島，遥天浸白波。", "誰令貪眺望，到處被詩磨。"]'),
('a8720e03-2913-4dd2-90d1-e8024b3d590e','登城','釋紹嵩','宋','宋诗','song-poetry','','[]','奔走倦塵埃，登臨亦快哉。',48,'全唐诗/poet.song.213000.json','["奔走倦塵埃，登臨亦快哉。", "江城含變態，蹤跡共徘徊。", "古殿桐陰合，秋山晚翠開。", "相逢吟未足，更擬上高臺。"]'),
('e4a70898-6182-4b79-a3c9-7f891553f5f5','紹興道中','釋紹嵩','宋','宋诗','song-poetry','','[]','古岸侵煙出，沙岡擁地形。',48,'全唐诗/poet.song.213000.json','["古岸侵煙出，沙岡擁地形。", "斷橋人寂寂，竟日雨冥冥。", "丘壑胸中事，乾坤水上萍。", "詩成何用好，聊以記飄零。"]'),
('92eed58a-4c21-463b-b2de-845285c0493d','夜汎有懷','釋紹嵩','宋','宋诗','song-poetry','','[]','獨自上孤舟，通宵浪打頭。',48,'全唐诗/poet.song.213000.json','["獨自上孤舟，通宵浪打頭。", "天風隨斷柳，江月值新秋。", "忽忽忘年老，忙忙汎夕流。", "此生成底事，誰不遣吾休。"]'),
('7b31a129-6837-41b3-8623-71a9ae9ba989','天章道中','釋紹嵩','宋','宋诗','song-poetry','','[]','十里尋幽寺，江山幾路分。',48,'全唐诗/poet.song.213000.json','["十里尋幽寺，江山幾路分。", "逢人問息耗，指路上高雲。", "極浦明殘雨，寒流疊細紋。", "野鴉無意緒，嘹唳傍溪濆。"]'),
('95717d19-c495-48e1-8d3f-0c46f4c4e55d','登杖錫','釋紹嵩','宋','宋诗','song-poetry','','[]','登寺尋盤道，那知是與非。',48,'全唐诗/poet.song.213000.json','["登寺尋盤道，那知是與非。", "凍泉依細石，寒日淡斜暉。", "村路飄黄落，山禽凌翠微。", "數聲牛上笛，老淚欲霑衣。"]'),
('5493dc91-bd16-47fb-80f0-cfb651775dfe','遊雪竇遣興','釋紹嵩','宋','宋诗','song-poetry','','[]','此地人來少，凭欄興莫窮。',48,'全唐诗/poet.song.213000.json','["此地人來少，凭欄興莫窮。", "雲蘿難透日，喬木易高風。", "書滿閑窗下，雲生閉目中。", "焚香賦詩罷，頓悟衆緣空。"]'),
('75ea344c-a697-4c65-bf53-af09d45a6f80','題海智寺壁','釋紹嵩','宋','宋诗','song-poetry','','[]','步步入山門，門前衆水分。',48,'全唐诗/poet.song.213000.json','["步步入山門，門前衆水分。", "上潮吞海日，古廟聚寒雲。", "樹影中流見，秋濤隔嶺聞。", "還應覓新句，不琢自成文。"]'),
('4d83bae1-0306-4512-9049-b931d4b26be9','至保福精舍','釋紹嵩','宋','宋诗','song-poetry','','[]','山水尋吳越，搜奇事轉新。',48,'全唐诗/poet.song.213000.json','["山水尋吳越，搜奇事轉新。", "松風知近寺，檣燕語留人。", "雨過閑田地，雲饒落日春。", "登臨獨無語，泉石自相親。"]'),
('13cdb26e-86dd-468c-8650-95ae5fcc1962','客夜偶成','釋紹嵩','宋','宋诗','song-poetry','','[]','萬里長爲客，窮愁豈自寬。',48,'全唐诗/poet.song.213000.json','["萬里長爲客，窮愁豈自寬。", "年衰髮種種，幽集夜漫漫。", "風卷湖煙靜，雲收溪月寒。", "天涯少知遇，唯有醉江干。"]'),
('9a5f47b2-40fc-4cfb-ba5b-2a0d06059316','江上晚立','釋紹嵩','宋','宋诗','song-poetry','','[]','沙晚低風蝶，汀煙入夜舟。',48,'全唐诗/poet.song.213000.json','["沙晚低風蝶，汀煙入夜舟。", "日依平野沒，月湧大江流。", "書懶聊遮眼，詩成自點頭。", "此時臨水歎，一倍不禁愁。"]'),
('2eb9bc7d-03cb-4900-b2d7-c2c15a330f76','丈亭登舟有感','釋紹嵩','宋','宋诗','song-poetry','','[]','未厭長爲客，孤舟趁夜行。',48,'全唐诗/poet.song.213000.json','["未厭長爲客，孤舟趁夜行。", "不唯山水樂，頗覺夢魂清。", "風緩帆舒卷，雲行月送迎。", "勞生誰獨免，空復歎勞生。"]'),
('3514a1c9-b66c-4b35-8bab-fc0141407db4','送別周上人','釋紹嵩','宋','宋诗','song-poetry','','[]','此地是何鄉，懸帆興甚長。',48,'全唐诗/poet.song.213000.json','["此地是何鄉，懸帆興甚長。", "山光分首暮，草氣入林香。", "斷嶺雲歸白，棲鴉噪日黄。", "他年重會面，玄鬢莫疑霜。"]'),
('8d532055-4396-49c8-9654-6f7c04906404','鳳山西亭戲書','釋紹嵩','宋','宋诗','song-poetry','','[]','日日西亭上，凭欄取次看。',48,'全唐诗/poet.song.213000.json','["日日西亭上，凭欄取次看。", "繞崖雲慘慘，浥屨露團團。", "晝景委紅葉，松香掩白檀。", "平生勳業意，開鏡影相懽。"]'),
('d94fd7eb-bfc7-4b6c-a9bd-a6659e102e4d','山居遣興','釋紹嵩','宋','宋诗','song-poetry','','[]','百衲老空林，疎慵倦九箴。',48,'全唐诗/poet.song.213000.json','["百衲老空林，疎慵倦九箴。", "浮沉千古事，去住兩鄉心。", "絕頂無禪侶，忘言有匣琴。", "感多聊自遣，時復一閑吟。"]'),
('2a1aea28-9520-42ae-bcb3-e76f5b7580dd','湖山堂晚坐','釋紹嵩','宋','宋诗','song-poetry','','[]','木葉落時節，湖山向晚晴。',48,'全唐诗/poet.song.213000.json','["木葉落時節，湖山向晚晴。", "移床橋上坐，看客海邊行。", "寂寂饒孤興，悠悠送此生。", "遣愁聊覓句，那敢謂長城。"]'),
('49fd029b-33d5-4c42-b1d4-2736013e524b','遊吉祥登棘菴別業','釋紹嵩','宋','宋诗','song-poetry','','[]','屋在瀑泉西，看來眼轉迷。',48,'全唐诗/poet.song.213000.json','["屋在瀑泉西，看來眼轉迷。", "松風清颯颯，秋日正凄凄。", "海鳥和濤望，山鼯隔水啼。", "何須更飛錫，祇此是曹溪。"]'),
('45552ee2-c391-456c-8f97-09111c1df2ee','寫懷','釋紹嵩','宋','宋诗','song-poetry','','[]','養拙甘沉默，蕭條古寺間。',48,'全唐诗/poet.song.213000.json','["養拙甘沉默，蕭條古寺間。", "中心無所媿，在世有餘閑。", "夢釣鷗邊雪，鍾鳴枕上山。", "徘徊幽興熟，何處不開顔。"]'),
('499fd277-c1c6-44ae-ba77-4188e9491060','鳳山即事','釋紹嵩','宋','宋诗','song-poetry','','[]','久欠遊山債，因尋溪上村。',48,'全唐诗/poet.song.213000.json','["久欠遊山債，因尋溪上村。", "風沙輕漠漠，煙樹遠昏昏。", "土甑封茶葉，石泉通竹根。", "榰筇聊小立，老子笑無言。"]'),
('5488cc71-b20a-4dfc-883b-33a8bcdefed9','尋訪廣福','釋紹嵩','宋','宋诗','song-poetry','','[]','舊邑浮航外，青山千萬重。',48,'全唐诗/poet.song.213000.json','["舊邑浮航外，青山千萬重。", "訪僧舟北渡，歸寺海西峰。", "薄薄雲收日，微微雨灑松。", "可堪添客恨，聞打暮天鍾。"]'),
('47370386-79db-4fd2-acc7-7bde23aec6bd','次韻王東之郊行','釋紹嵩','宋','宋诗','song-poetry','','[]','杖屨尋春事，偷分暇日工。',48,'全唐诗/poet.song.213000.json','["杖屨尋春事，偷分暇日工。", "幽花欹照水，獨樹逈含風。", "路極陰溪裏，桃開曉色中。", "一年春好處，分付少陵翁。"]'),
('1bfc440c-49dc-4b63-b054-996a396e6f50','酬顔仲華','釋紹嵩','宋','宋诗','song-poetry','','[]','客子愁無柰，年來鬢已秋。',48,'全唐诗/poet.song.213000.json','["客子愁無柰，年來鬢已秋。", "塵埃自衮衮，勳業轉悠悠。", "島霧沉晴樹，山雞舞畫樓。", "惠連有新作，一覽病應休。"]'),
('0dbf7337-187f-4182-b0ed-ac90b53cd0d3','郊行','釋紹嵩','宋','宋诗','song-poetry','','[]','桑柘晴川口，林深一徑存。',48,'全唐诗/poet.song.213000.json','["桑柘晴川口，林深一徑存。", "披雲登斷嶺，隔水見前村。", "春去花無跡，崖傾洞有門。", "郊行聊著眼，疑是武陵源。"]'),
('7fe2e23d-d0cf-4205-b470-518927f5066c','代顔聖聞次韻即事','釋紹嵩','宋','宋诗','song-poetry','','[]','渡口水流急，憑欄凝睇勞。',48,'全唐诗/poet.song.213000.json','["渡口水流急，憑欄凝睇勞。", "遠山楓外淡，矮竹苣邊高。", "古木叢青靄，鯿魚噀白濤。", "幽閑無箇事，痛飲讀離騷。"]'),
('9adfc00d-9d81-4e71-b7a8-d63b2bffd4de','次韻梓上人  其一','釋紹嵩','宋','宋诗','song-poetry','','[]','一身無定處，誰見寂寥心。',48,'全唐诗/poet.song.213000.json','["一身無定處，誰見寂寥心。", "始爲江山靜，徒云寒暑侵。", "少孤心易感，漂泊病難任。", "未遂長棲此，孤懷自不禁。"]'),
('569d7e02-3b03-46b8-b596-b8fee5f1b98c','次韻梓上人  其二','釋紹嵩','宋','宋诗','song-poetry','','[]','江湖同避地，老眼不供愁。',48,'全唐诗/poet.song.213000.json','["江湖同避地，老眼不供愁。", "閲世臨觀美，出門聊散憂。", "漁鹽橋上市，河漢島前秋。", "奔走何時了，如今悟解不。"]'),
('b0ce183e-d2a1-4f27-a3a3-29abf6b1484b','投宿寶覺精舍','釋紹嵩','宋','宋诗','song-poetry','','[]','驛路向山郭，江蘺滿意馨。',48,'全唐诗/poet.song.213000.json','["驛路向山郭，江蘺滿意馨。", "遠雲收海雨，獨樹隠沙汀。", "桑椹纍纍紫，杉栽處處青。", "夜投寶覺寺，重上竹西亭。"]'),
('e5a859af-dacd-4219-b07b-6cc38bc7e7d4','錢清解舟有感','釋紹嵩','宋','宋诗','song-poetry','','[]','解纜浙江頭，真成汗漫遊。',48,'全唐诗/poet.song.213000.json','["解纜浙江頭，真成汗漫遊。", "山川元歷歷，雲水自悠悠。", "舉翮籠中鳥，歸心水上鷗。", "夕陽誰共感，一鴈度南樓。"]'),
('8476a3b2-08bf-41d0-a5f2-29a61f7a809a','蕭山口占','釋紹嵩','宋','宋诗','song-poetry','','[]','水鳥迎秋舫，紅輪映曙霞。',48,'全唐诗/poet.song.213000.json','["水鳥迎秋舫，紅輪映曙霞。", "冥冥小江樹，淡淡滿枝花。", "碧草望中去，青山郭外斜。", "天涯重回首，回首重傷嗟。"]'),
('4e15dc21-bf76-4f93-beca-43678857a7b5','待舟西興遣悶','釋紹嵩','宋','宋诗','song-poetry','','[]','海湧銀爲郭，吳疆與越連。',48,'全唐诗/poet.song.213000.json','["海湧銀爲郭，吳疆與越連。", "有山來枕上，無酒到愁邊。", "烈烈寒風起，悠悠落日懸。", "孤舟未得濟，少駐祖生鞭。"]'),
('64c0eda3-dcc4-4c9c-bfed-4700a40b001b','通判曾溫伯生日  其一','釋紹嵩','宋','宋诗','song-poetry','','[]','玉曆標人瑞，膺門鶚獨先。',48,'全唐诗/poet.song.213000.json','["玉曆標人瑞，膺門鶚獨先。", "風雷開盛旦，嵩岳降真賢。", "壁暗詩千首，官當歲九遷。", "得知眉壽永，何但八千年。"]'),
('d80503be-25b7-402b-9cf4-8094427dcc48','通判曾溫伯生日  其二','釋紹嵩','宋','宋诗','song-poetry','','[]','今代文章伯，長哦氣吐虹。',48,'全唐诗/poet.song.213000.json','["今代文章伯，長哦氣吐虹。", "揮犀聞妙論，許國見深衷。", "美價方稀古，離騷繼雅風。", "慇懃一雙眼，看到火城紅。"]'),
('4b4d1de5-c185-4224-a6fa-0a2b5c51f3af','書事','釋紹嵩','宋','宋诗','song-poetry','','[]','松蓋環清韻，秋風倚杖前。',48,'全唐诗/poet.song.213000.json','["松蓋環清韻，秋風倚杖前。", "棲毫思確論，擊竹自忻然。", "高鳥翔雲外，孤亭恰水邊。", "幽居經宿雨，無處不潺湲。"]'),
('c5a53e84-5bba-473a-b4ba-7df64ddf72e1','咏道中所見','釋紹嵩','宋','宋诗','song-poetry','','[]','倚杖寒山暮，高杉韻細颸。',48,'全唐诗/poet.song.213000.json','["倚杖寒山暮，高杉韻細颸。", "歸舟藏別浦，落日映荒陂。", "碧澗流紅葉，黄猿領白兒。", "石橋南畔路，岑渚復幽奇。"]'),
('6c155377-e601-4d62-b3c0-f17e5e69960d','憩靈隠寫懷','釋紹嵩','宋','宋诗','song-poetry','','[]','莫恨征途遠，題詩記獨遊。',48,'全唐诗/poet.song.213000.json','["莫恨征途遠，題詩記獨遊。", "十年行路飽，萬里此生浮。", "宇宙知何極，山川慰久留。", "倚欄哦五字，不覺散人愁。"]'),
('9256b5dc-b3c4-440b-9f8c-1ceb471a5884','雪後復雨過西湖','釋紹嵩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','觸目成幽興，詩吟十數篇。',48,'全唐诗/poet.song.213000.json','["觸目成幽興，詩吟十數篇。", "風傾竹上雪，鳥度水中天。", "急雨涔涔日，迎人小小船。", "更逢清管發，聲到客愁邊。"]'),
('81f95bdb-e1af-4df6-85d7-885d859af463','棲霞道中','釋紹嵩','宋','宋诗','song-poetry','','[]','路僻閑行遠，溪將罨畫通。',48,'全唐诗/poet.song.213000.json','["路僻閑行遠，溪將罨畫通。", "飛泉高瀉月，細柳亂摇風。", "畎畝孤城外，山川暮靄中。", "曠然忘所在，心與白雲空。"]'),
('cf330daf-ea48-44d3-9170-6d7709fedba5','題白蓮園亭','釋紹嵩','宋','宋诗','song-poetry','','[]','塔影挂清漢，分明雨後山。',48,'全唐诗/poet.song.213000.json','["塔影挂清漢，分明雨後山。", "雲寒湖貼貼，錢樣菊斑斑。", "有水園林活，無風溪樹閑。", "臨流興不盡，復自竹中還。"]'),
('a788916f-a868-4a86-b4a1-b7f4e62b3f2b','泛湖','釋紹嵩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','久客欣無事，扶衰上野航。',48,'全唐诗/poet.song.213000.json','["久客欣無事，扶衰上野航。", "迴雲覆陰谷，初日放晨光。", "楊柳千尋色，荷花一路香。", "西湖天下勝，誰與共平章。"]'),
('2eaf2b64-5f9b-4a00-a13d-0b0171d1ce83','同粲湛二上人遊北山','釋紹嵩','宋','宋诗','song-poetry','','[]','二子依公子，南山度北山。',48,'全唐诗/poet.song.213000.json','["二子依公子，南山度北山。", "興隨流水遠，心逐片雲閑。", "日月浮生外，牛羊落照間。", "慇懃華表鶴，飛去復飛還。"]'),
('3f1220f8-f175-4fec-9d9e-7aea691f5288','秋日湖上憩水僊祠','釋紹嵩','宋','宋诗','song-poetry','','[]','萬木已西風，千山景象通。',48,'全唐诗/poet.song.213000.json','["萬木已西風，千山景象通。", "岸拖秋草綠，日抹半山紅。", "穴蟻苔痕靜，詩人眼界空。", "水僊來往處，脈脈興何窮。"]'),
('9181169e-7442-4949-ba84-d4c2ed3bb7b6','野步','釋紹嵩','宋','宋诗','song-poetry','','[]','野步隨吾意，無勞問是非。',48,'全唐诗/poet.song.213000.json','["野步隨吾意，無勞問是非。", "風鶯移樹囀，江燕引鶵飛。", "一徑入寒竹，千峰駐晚暉。", "幽懷在天末，何要更忘機。"]'),
('84d4d781-831d-4d3b-a641-cd2258710f67','遊天竺','釋紹嵩','宋','宋诗','song-poetry','','[]','天竺秋重入，翛然適此心。',48,'全唐诗/poet.song.213000.json','["天竺秋重入，翛然適此心。", "路尋流水遠，門閉野雲深。", "澹泞生真趣，幽閑且自任。", "殘陽應更好，蟬合伴清吟。"]'),
('aefdf573-3a5c-41bb-aff2-a70db5880c93','自笑','釋紹嵩','宋','宋诗','song-poetry','','[]','自笑從來癖，平生斷在詩。',48,'全唐诗/poet.song.213000.json','["自笑從來癖，平生斷在詩。", "鳧鷖共容與，魂夢亦清奇。", "古調俗不樂，衰容鏡每知。", "機心吾豈有，休把運行推。"]'),
('6c97f49e-a9ba-4d9b-b071-840e0b56d935','天竺戲書','釋紹嵩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','出郭西湖近，貪看立又行。',48,'全唐诗/poet.song.213000.json','["出郭西湖近，貪看立又行。", "園林青氣動，日夕白雲生。", "映竹犬初吠，緣溪鶴自鳴。", "慇懃下天竺，泉石愜幽情。"]'),
('7746a8fe-de7a-4d34-bab7-4044f85cc681','解舟  其一','釋紹嵩','宋','宋诗','song-poetry','','[]','落日放船好，波恬爾許平。',48,'全唐诗/poet.song.213000.json','["落日放船好，波恬爾許平。", "水光浮棹碧，山意入詩清。", "世路方行險，江人莫問程。", "順流風更順，颯颯片帆輕。"]'),
('312f76eb-4d1c-48ad-a042-a26615e95ce1','解舟  其二','釋紹嵩','宋','宋诗','song-poetry','','[]','落日放船好，長河水接天。',48,'全唐诗/poet.song.213000.json','["落日放船好，長河水接天。", "遠林翻急吹，孤棹正悠然。", "風攪平雲陣，波輕片雪連。", "前村鴉噪斷，極目仰聯翩。"]'),
('f72d164d-02c3-4e9f-8603-01f521483d2d','遊何山','釋紹嵩','宋','宋诗','song-poetry','','[]','綠草閑深院，繁花的的開。',48,'全唐诗/poet.song.213000.json','["綠草閑深院，繁花的的開。", "捲簾當白晝，辭洞戀青苔。", "燕掠平蕪去，人從瀑布來。", "林間清話久，杜宇一聲催。"]'),
('a3a63092-6ac2-499d-853f-e1333f6d6120','憶遊天衣','釋紹嵩','宋','宋诗','song-poetry','','[]','寺憶新遊處，江村日暮時。',48,'全唐诗/poet.song.213000.json','["寺憶新遊處，江村日暮時。", "溪長石磊磊，天遠草離離。", "塔院關松雪，山泉滿路歧。", "那知巖下樹，一一入吾詩。"]'),
('e81457fc-06e3-4639-b08b-499236300137','旅暮即事','釋紹嵩','宋','宋诗','song-poetry','','[]','萬壑初收雨，湖聲正寂然。',48,'全唐诗/poet.song.213000.json','["萬壑初收雨，湖聲正寂然。", "薄衣臨積水，歸鳥度平川。", "仙掌雲邊樹，春風寺外船。", "詩成見新月，目極向遥天。"]'),
('455199b1-831b-498f-81ba-688941186146','東山精舍戲書','釋紹嵩','宋','宋诗','song-poetry','','[]','逈磧沙銜日，荒溪衆樹分。',48,'全唐诗/poet.song.213000.json','["逈磧沙銜日，荒溪衆樹分。", "行人隨旅鴈，尋寺入幽雲。", "遠岫林間見，啼鶯夢裏聞。", "湖山雖不語，心緒已紛紛。"]'),
('2e208e6d-b7f7-4a8e-9e52-804c276a6af0','題浄衆壺隠','釋紹嵩','宋','宋诗','song-poetry','','[]','古院無僧住，含情更惘然。',48,'全唐诗/poet.song.213000.json','["古院無僧住，含情更惘然。", "綠苔欺破閣，白鳥沒飛煙。", "壺隠遲遲日，筒分細細泉。", "欄干聊小凭，取次綴詩篇。"]'),
('59112247-a61b-4f81-b347-cc6f894cc567','贈別張西叔之豐城','釋紹嵩','宋','宋诗','song-poetry','','[]','有客功名累，蕭蕭逐轉蓬。',48,'全唐诗/poet.song.213000.json','["有客功名累，蕭蕭逐轉蓬。", "豐城千里外，茅屋萬山中。", "楊柳縈橋綠，秋梨繞地紅。", "登臨雖未並，談笑會當同。"]'),
('6c4d08af-fc3a-43d5-bb84-ad69967b8e25','酬敬上人','釋紹嵩','宋','宋诗','song-poetry','','[]','浙界殘零處，相尋聊解顔。',48,'全唐诗/poet.song.213000.json','["浙界殘零處，相尋聊解顔。", "別橋連白石，移榻對青山。", "有恨春將晚，無機性自閑。", "天涯將野眼，時見一舟還。"]'),
('66398436-e6a6-46ce-8b89-b33933613c71','遊西崦','釋紹嵩','宋','宋诗','song-poetry','','[]','小隠寄幽谷，登臨翠色中。',48,'全唐诗/poet.song.213000.json','["小隠寄幽谷，登臨翠色中。", "亂雲低薄暮，片水靜涵空。", "往往遊西崦，依依向北風。", "清猿不可聽，幽思更無窮。"]'),
('4c6aba10-d72a-46b3-a49d-59607bec8a43','江上偶謁什上人','釋紹嵩','宋','宋诗','song-poetry','','[]','在路日已久，此心誰與論。',48,'全唐诗/poet.song.213000.json','["在路日已久，此心誰與論。", "一言知具眼，萬里獨消魂。", "輟棹丹楓浦，扶筇白水村。", "縱情猶未已，吟扣野僧門。"]'),
('6ddb7de9-c189-4021-81e6-d6a1eaf54f58','客次感懷','釋紹嵩','宋','宋诗','song-poetry','','[]','投老詩成癖，愁生爲客途。',48,'全唐诗/poet.song.213000.json','["投老詩成癖，愁生爲客途。", "煙雲長在目，山水暫遊吳。", "遠意極千里，歸心寄九衢。", "一身仍更病，意緒日荒蕪。"]'),
('c06daa6c-9b6b-4c3e-9043-b91016b7808b','即事','釋紹嵩','宋','宋诗','song-poetry','','[]','殘日住孤館，虛廊遶幾迴。',48,'全唐诗/poet.song.213000.json','["殘日住孤館，虛廊遶幾迴。", "沙鷗背人去，江雨带潮來。", "古驛怪藤合，霜花錯節開。", "時因念衰疾，獨與暮猿哀。"]'),
('4674b732-bea9-4423-90cd-8fec3f2493f9','歎命','釋紹嵩','宋','宋诗','song-poetry','','[]','歎命無知己，吾徒却自寬。',48,'全唐诗/poet.song.213000.json','["歎命無知己，吾徒却自寬。", "艱難爲客慣，幽僻置身安。", "竟日霏微雨，空園浩蕩寒。", "江山多勝境，到處得吟看。"]'),
('96929943-0166-4f5e-8921-6c703b7c33c5','寓筆','釋紹嵩','宋','宋诗','song-poetry','','[]','幽徑草初青，無人知地名。',48,'全唐诗/poet.song.213000.json','["幽徑草初青，無人知地名。", "征鞍千里遠，倚杖一江橫。", "雲重欲爲雨，風和拗得晴。", "家家好春色，春色徧空明。"]'),
('9d596488-2cc5-4890-a5c0-2b422310a25f','獨遊','釋紹嵩','宋','宋诗','song-poetry','','[]','幽圃多清致，殊方此日歡。',48,'全唐诗/poet.song.213000.json','["幽圃多清致，殊方此日歡。", "松風欹枕聽，春草隔溪看。", "紅入桃花嫩，青還玉宇寬。", "獨遊吾有意，終日凭欄干。"]'),
('1ccc5405-b3c7-43f5-b96a-bd3baa72e75d','定慧別業次韻陳子中','釋紹嵩','宋','宋诗','song-poetry','','[]','地勝千山會，孤懷行轉幽。',48,'全唐诗/poet.song.213000.json','["地勝千山會，孤懷行轉幽。", "歸雲带層巘，遠岸送輕舟。", "綠樹鶯邊合，清泉檻外流。", "雨餘情更逸，端爲故人留。"]'),
('d3995382-5f60-42ee-95c5-3638079d7409','遣懷  其一','釋紹嵩','宋','宋诗','song-poetry','','[]','抱瘵便秋晚，無言祗自知。',48,'全唐诗/poet.song.213000.json','["抱瘵便秋晚，無言祗自知。", "是身多落寞，半世足飄離。", "靜閲王維畫，閑圍李遠棋。", "慨然歎時命，轉覺命堪疑。"]'),
('1d7e4d98-584c-42cf-8cff-40567fc17959','遣懷  其二','釋紹嵩','宋','宋诗','song-poetry','','[]','落拓無生計，放懷便所便。',48,'全唐诗/poet.song.213000.json','["落拓無生計，放懷便所便。", "託心時散帙，即事偶成篇。", "此道欣逢泰，平生祗信緣。", "慇懃伴幽獨，松亞小窗前。"]'),
('20909458-d31d-4fd5-95dc-230ecfae8ad1','遣懷  其三','釋紹嵩','宋','宋诗','song-poetry','','[]','學懶真成懶，龍鍾志未酬。',48,'全唐诗/poet.song.213000.json','["學懶真成懶，龍鍾志未酬。", "此生多轗軻，何處不遲留。", "勳業頻看鏡，寒盟得問鷗。", "羈愁難盡遣，愁盡自無愁。"]'),
('114f1f77-22c6-41ad-b39b-74c04279d29c','遣懷  其四','釋紹嵩','宋','宋诗','song-poetry','','[]','淹泊寧吾願，年光送老來。',48,'全唐诗/poet.song.213000.json','["淹泊寧吾願，年光送老來。", "只知閑說話，但覺旅懷開。", "此路方知己，唯天合是媒。", "冥搜無好語，也辱片雲催。"]'),
('29e29b95-ff5b-470e-b92c-645072abf302','與保寧西堂同客三塔因有感而作','釋紹嵩','宋','宋诗','song-poetry','','[]','漫浪真堪老，君應與我同。',48,'全唐诗/poet.song.213000.json','["漫浪真堪老，君應與我同。", "旅懷斜日後，閑步淡煙中。", "有分長爲客，無勞問轉蓬。", "不妨留滯好，悟取本來空。"]'),
('c7a3dea1-6d26-41e4-bae7-53b9db6c8c19','寫懷寄湛上人  其一','釋紹嵩','宋','宋诗','song-poetry','','[]','吾事只如此，奔忙自作癡。',48,'全唐诗/poet.song.213000.json','["吾事只如此，奔忙自作癡。", "買山猶未得，吊古却成悲。", "老去慵趨世，愁來獨賦詩。", "浮生同是客，誰復問棲遲。"]'),
('5033d234-15fa-497a-a23e-72be20c20e63','寫懷寄湛上人  其二','釋紹嵩','宋','宋诗','song-poetry','','[]','寂寂相思際，遥焚一炷香。',48,'全唐诗/poet.song.213000.json','["寂寂相思際，遥焚一炷香。", "鴈飛雲杳杳，笛引淚浪浪。", "明代誰招隠，窮遊我自忙。", "他時解顔笑，寧免鬢毛蒼。"]'),
('887d7526-2f65-4639-ab62-120c4d7770ff','寄元藏主','釋紹嵩','宋','宋诗','song-poetry','','[]','度歲不相見，別來春又春。',48,'全唐诗/poet.song.213000.json','["度歲不相見，別來春又春。", "縱橫皆失計，談笑亦何因。", "鄉思盈愁望，形衰恨道貧。", "掩扉當太白，願卜子爲隣。"]'),
('cb68f3c4-6bd2-41bf-81ba-a2f1ee5d44f8','送別一西堂','釋紹嵩','宋','宋诗','song-poetry','','[]','一老說淡話，志懷絕險艱。',48,'全唐诗/poet.song.213000.json','["一老說淡話，志懷絕險艱。", "別離從闕下，游戲且人間。", "落羽羞言命，臨岐强破顔。", "住山須鈯斧，此句急追還。"]'),
('dce01322-6b7a-4590-a30f-3c0bd07c8e53','次韻朋上人東湖精舍即事','釋紹嵩','宋','宋诗','song-poetry','','[]','開徑東湖上，千巖鏡裏看。',48,'全唐诗/poet.song.213000.json','["開徑東湖上，千巖鏡裏看。", "與君頻邂逅，此地久盤桓。", "柳影含雲幕，桃花生暮寒。", "婆娑弄翰墨，清興寄毫端。"]'),
('3adae242-fb60-42fb-8c11-7f2c94634753','登樓次朋上人韻','釋紹嵩','宋','宋诗','song-poetry','','[]','落日生春色，桃花笑不休。',48,'全唐诗/poet.song.213000.json','["落日生春色，桃花笑不休。", "鶴飛湖草迥，風止客帆收。", "樹遠天疑盡，江平水却流。", "愁來無處去，爲子上高樓。"]'),
('c9706f43-6960-416c-94fd-2dfbf272beab','小憩東嶽行宮戲題','釋紹嵩','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','樹色遥藏店，春風入皷鼙。',48,'全唐诗/poet.song.213000.json','["樹色遥藏店，春風入皷鼙。", "行宮花漠漠，孤嶼草萋萋。", "白鳥飛還立，黄鶯歇又啼。", "詩成那用好，到處好詩題。"]'),
('1e6f8336-6ab3-429a-a668-61a25d305f16','送客歸戲書','釋紹嵩','宋','宋诗','song-poetry','','[]','險盡途方坦，溪鳴錦幄傍。',48,'全唐诗/poet.song.213000.json','["險盡途方坦，溪鳴錦幄傍。", "暝煙沉古道，幽草戀殘陽。", "寂寂春將晚，迢迢日自長。", "東門因送客，行得汗如漿。"]'),
('5ef58af5-0910-40b3-8599-7d9f94fc019c','答一老','釋紹嵩','宋','宋诗','song-poetry','','[]','散拙亦自遂，誰能淚墮巾。',48,'全唐诗/poet.song.213000.json','["散拙亦自遂，誰能淚墮巾。", "詩成聊疥壁，道在不嫌貧。", "老矣曾榮望，頹然只任真。", "拂衣從此去，四海作閑人。"]'),
('160a3ff6-f076-49ef-9ee2-3f79203e4470','有感','釋紹嵩','宋','宋诗','song-poetry','','[]','志業不得力，寂寥常掩關。',48,'全唐诗/poet.song.213000.json','["志業不得力，寂寥常掩關。", "交疎貧病裏，老疾去留間。", "涉世心猶壯，經秋鬢自斑。", "平生懷古意，欲語淚先潸。"]'),
('f45d4d4b-a234-48ad-ab00-a8a949cf3303','送別永上人','釋紹嵩','宋','宋诗','song-poetry','','[]','四海無拘繫，飄然不可留。',48,'全唐诗/poet.song.213000.json','["四海無拘繫，飄然不可留。", "洩雲分疊巘，落日滿行舟。", "舉世謀三窟，餘生老一丘。", "對床清約在，後會必經秋。"]'),
('a910e5c5-c8ac-4638-bea4-675eb52015fa','翠蘿亭書事','釋紹嵩','宋','宋诗','song-poetry','','[]','萬壑初收雨，鴉聲唁客勞。',48,'全唐诗/poet.song.213000.json','["萬壑初收雨，鴉聲唁客勞。", "溪寒魚隊散，秋靜鳥行高。", "碧嶂前兼後，青猿斷更號。", "捲簾雙眼遠，繞舍綠周遭。"]'),
('d314d8f8-720a-40f1-92ef-0dbe691d29ad','登樓','釋紹嵩','宋','宋诗','song-poetry','','[]','二月春方好，登樓望欲迷。',48,'全唐诗/poet.song.213000.json','["二月春方好，登樓望欲迷。", "關情山簇簇，餘思草萋萋。", "小浦依林曲，長天向水低。", "鄉心正無限，恰恰一鶯啼。"]'),
('c5a7d6b8-d840-4815-a2af-2d86b88a6026','至錢君瑞壺天因題云','釋紹嵩','宋','宋诗','song-poetry','','[]','林下中餐後，登臨思渺然。',48,'全唐诗/poet.song.213000.json','["林下中餐後，登臨思渺然。", "捫蘿循鳥道，著屐到壺天。", "要地無閑日，新晴有亂蟬。", "主人貪貴達，燈火照青編。"]'),
('6470518f-ceeb-4fc2-9084-137af766b60a','贈別顯上人','釋紹嵩','宋','宋诗','song-poetry','','[]','兩浙尋山徧，依俙三十秋。',48,'全唐诗/poet.song.213000.json','["兩浙尋山徧，依俙三十秋。", "征塵添老色，藜杖賦歸休。", "落葉隨杯渡，殘虹带夕收。", "不知從此去，能寄短書不。"]'),
('655bdbb4-bdb6-46d6-8ae1-737b75166609','道中自遣','釋紹嵩','宋','宋诗','song-poetry','','[]','綠暗連村柳，江平不見灘。',48,'全唐诗/poet.song.213000.json','["綠暗連村柳，江平不見灘。", "日烘花氣暖，岸曲水流寒。", "世路今逾窄，客心須自寬。", "悠悠片雲質，溪上更蹣跚。"]'),
('c21a1f55-5cd2-47b5-b5a2-760c8e2a1652','走筆酬黎德夫','釋紹嵩','宋','宋诗','song-poetry','','[]','索寞門長掩，圖書是舊貧。',48,'全唐诗/poet.song.213000.json','["索寞門長掩，圖書是舊貧。", "無因從發藥，有命懶謀身。", "寥落悲前事，英雄歎後塵。", "裁詩託幽思，幽思忽相親。"]'),
('1b0c9c17-9498-481c-9f25-40f0ab255c58','哭黄少府','釋紹嵩','宋','宋诗','song-poetry','','[]','大節群公倡，儒科慕冉顔。',48,'全唐诗/poet.song.213000.json','["大節群公倡，儒科慕冉顔。", "遠分天子命，長覺吏徒閑。", "秋入篇章裏，川行翰墨間。", "壑舟今已矣，老淚爲渠潸。"]'),
('072b4adc-19e7-4364-ac3d-a5a391e7a13a','酬顔聖聞監稅','釋紹嵩','宋','宋诗','song-poetry','','[]','地僻春來靜，孤山夕照餘。',48,'全唐诗/poet.song.213000.json','["地僻春來靜，孤山夕照餘。", "深慚長者轍，新欠故人書。", "有酒招元亮，無人誦子虛。", "相從又相別，意緒各何如。"]'),
('046e93a2-b485-45c8-b0f1-37650c3e826b','贈劉信之','釋紹嵩','宋','宋诗','song-poetry','','[]','四海劉居士，詩書論議深。',48,'全唐诗/poet.song.213000.json','["四海劉居士，詩書論議深。", "苦吟天與性，醉卧月空沉。", "囊有壺公藥，身無戚里心。", "高懷不我棄，他日重來尋。"]'),
('ad9d85bd-fa42-4144-a312-3459945f5e3a','偶興','釋紹嵩','宋','宋诗','song-poetry','','[]','暖日薰楊柳，溪風爲肅然。',48,'全唐诗/poet.song.213000.json','["暖日薰楊柳，溪風爲肅然。", "浣衣逢野水，擁錫上瀧船。", "元是滄浪客，閑尋空谷泉。", "病來詩久廢，喜此得終篇。"]'),
('6c80b5af-eb74-4ce2-b085-0f15f646136d','贈黄元吉','釋紹嵩','宋','宋诗','song-poetry','','[]','此客非常客，搜詩病入神。',48,'全唐诗/poet.song.213000.json','["此客非常客，搜詩病入神。", "錦囊稱具眼，文學老於身。", "機息知名誤，家因守道貧。", "仍聞猿與鶴，與爾轉相親。"]'),
('b08061ff-626c-4d74-bc3e-a134f226b79f','江上對月','釋紹嵩','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','北渚牽吟興，何妨語夜闌。',48,'全唐诗/poet.song.213000.json','["北渚牽吟興，何妨語夜闌。", "天寬雲出谷，春至草生灘。", "練練長江靜，駸駸半臂寒。", "老翁扶杖立，空對爛銀盤。"]'),
('01736c2a-abbe-407a-9311-b1ecf9b5e09d','鳳口寺','釋紹嵩','宋','宋诗','song-poetry','','[]','古柏間松篁，山光接水光。',48,'全唐诗/poet.song.213000.json','["古柏間松篁，山光接水光。", "園林春婉娩，雲水日相佯。", "苒苒花明岸，稍稍竹過牆。", "冥搜得詩窟，臺館曉蒼蒼。"]'),
('58f5b81a-a067-48d2-b9df-66a5407ddee5','遊清老別業','釋紹嵩','宋','宋诗','song-poetry','','[]','別業青山郭，人煙遠更微。',48,'全唐诗/poet.song.213000.json','["別業青山郭，人煙遠更微。", "濕花隨水汎，長瀑倚空飛。", "開篋收詩卷，凭軒對竹扉。", "淹留更一醉，應在醉中歸。"]'),
('43d037a3-23da-499e-bb9c-617b5ade127c','遣懷','釋紹嵩','宋','宋诗','song-poetry','','[]','巡禮諸方徧，無心問世緣。',48,'全唐诗/poet.song.213000.json','["巡禮諸方徧，無心問世緣。", "東西南北路，一十二三年。", "夜色臨城月，猿聲隔樹煙。", "坐來幽興在，對景覓詩聯。"]'),
('67cbc74d-d5ca-411b-9363-3a2b58a62647','遊光嚴精舍','釋紹嵩','宋','宋诗','song-poetry','','[]','酷愛山兼水，山重水又回。',48,'全唐诗/poet.song.213000.json','["酷愛山兼水，山重水又回。", "樹圍平野合，花逼艷陽開。", "習習和風至，冥冥細雨來。", "將行誰請住，留步小庭隈。"]'),
('5d3d2cb8-0d78-49b9-8ef1-bee0cf2599a0','憩江亭','釋紹嵩','宋','宋诗','song-poetry','','[]','花露濕晴春，坐無車馬塵。',48,'全唐诗/poet.song.213000.json','["花露濕晴春，坐無車馬塵。", "江流青草岸，波閃白龍鱗。", "往事如今日，知心似古人。", "慇懃聽漁唱，閑趣自相親。"]'),
('3fbe7769-5c2a-4338-95ef-bb76d038f930','小院','釋紹嵩','宋','宋诗','song-poetry','','[]','小院無人夜，樓高月迥明。',48,'全唐诗/poet.song.213000.json','["小院無人夜，樓高月迥明。", "偈吟諸祖意，茶試老僧鐺。", "門掩園林僻，窗虛筆硯輕。", "慇懃供一笑，一笑可憐生。"]'),
('a4e01cac-2163-49e7-bfe6-b44004022e72','客中戲書  其一','釋紹嵩','宋','宋诗','song-poetry','','[]','杖屨千崖表，江山故作妍。',48,'全唐诗/poet.song.213000.json','["杖屨千崖表，江山故作妍。", "捫蘿懷鳥道，踏石過溪泉。", "野濕禾中露，秋明樹外天。", "白頭何所恨，隨處一欣然。"]'),
('900abeb5-60de-48b5-acac-f13b19385069','客中戲書  其二','釋紹嵩','宋','宋诗','song-poetry','','[]','遠笛招幽響，無人竹掃墀。',48,'全唐诗/poet.song.213000.json','["遠笛招幽響，無人竹掃墀。", "馬嘶遊寺客，鴉護落巢兒。", "日轉槐陰暮，天高秋氣悲。", "還應重風景，時作一篇詩。"]'),
('043d6bd4-1e89-41c8-9278-a5a3f79f422a','寶溪道中','釋紹嵩','宋','宋诗','song-poetry','','[]','徑直夫何細，雲山知幾重。',48,'全唐诗/poet.song.213000.json','["徑直夫何細，雲山知幾重。", "朱門均白屋，紅葉間青松。", "野火燒岡草，殘陽下遠峰。", "傷心繞村落，倦客獨携筇。"]'),
('ec4c3333-6391-4da1-8119-da24514790cd','寓山寺戲成','釋紹嵩','宋','宋诗','song-poetry','','[]','寺在猿啼外，都無俗到來。',48,'全唐诗/poet.song.213000.json','["寺在猿啼外，都無俗到來。", "岸花開且落，水鳥去仍迴。", "果落方知熟，詩成未費才。", "逍遥此中意，老子興悠哉。"]'),
('32938ba8-a7cc-4fdc-b5d8-804ef9e4adb6','感惻','釋紹嵩','宋','宋诗','song-poetry','','[]','路入南雲下，江回隔近村。',48,'全唐诗/poet.song.213000.json','["路入南雲下，江回隔近村。", "水深風浩浩，山遠霧昏昏。", "仰首羨飛鳥，流年只斷魂。", "客心兼暮色，感惻復何言。"]'),
('60770aaf-442c-499a-8b38-49a5416da20c','和崇上人','釋紹嵩','宋','宋诗','song-poetry','','[]','松下中峰路，疎陰偃蓋清。',48,'全唐诗/poet.song.213000.json','["松下中峰路，疎陰偃蓋清。", "遠雲收海雨，數鴈過秋城。", "撫事心猶壯，卑棲氣未平。", "近來唯此樂，高韻寄閑情。"]'),
('6aa513a4-0b1d-4e84-9fb4-d453e61e55b3','贈別性老','釋紹嵩','宋','宋诗','song-poetry','','[]','此老殊清健，情忘發興奇。',48,'全唐诗/poet.song.213000.json','["此老殊清健，情忘發興奇。", "異方驚會面，孤嶼共題詩。", "聚散千江月，參差萬里期。", "相看作離別，特地淚雙垂。"]'),
('b33285f9-8e7f-41c2-b79a-37de9a7467d6','秋夜憶親庭有感','釋紹嵩','宋','宋诗','song-poetry','','[]','碧澗寒侵屋，高林露氣清。',48,'全唐诗/poet.song.213000.json','["碧澗寒侵屋，高林露氣清。", "空窗閑月色，密竹動秋聲。", "宴坐遊三昧，隣談喧五更。", "兩親今正老，此別不勝情。"]'),
('e6eddca7-f608-46a4-8602-586da0340dc8','有懷','釋紹嵩','宋','宋诗','song-poetry','','[]','月淡猶明樹，巖幽鍾磬微。',48,'全唐诗/poet.song.213000.json','["月淡猶明樹，巖幽鍾磬微。", "露滋三徑草，寒入五更衣。", "棲托情何限，崢嶸歲且歸。", "漱流今已矣，無限故山薇。"]'),
('e02beaf4-0231-4aa4-b47a-e6279991ab65','至禪居','釋紹嵩','宋','宋诗','song-poetry','','[]','得路到深寺，溪流鏡樣清。',48,'全唐诗/poet.song.213000.json','["得路到深寺，溪流鏡樣清。", "微芳緣岸落，荒竹過牆生。", "烘日淺深色，寒鴉斷續聲。", "我來無舊識，素抱與誰傾。"]'),
('ad97508a-2973-4b88-b368-5b466786dd6a','口占','釋紹嵩','宋','宋诗','song-poetry','','[]','江上有微徑，漁人四五家。',48,'全唐诗/poet.song.213000.json','["江上有微徑，漁人四五家。", "野船明細火，宿鴈起圓沙。", "峽口聞猿夜，秋星見客槎。", "徘徊幽興盡，更覺在天涯。"]'),
('f5af5e58-1902-4cdd-bec0-5fba7214ff9b','即筆','釋紹嵩','宋','宋诗','song-poetry','','[]','小閣稱幽隠，群峰競秀尖。',48,'全唐诗/poet.song.213000.json','["小閣稱幽隠，群峰競秀尖。", "村舂雨外急，秋色望中添。", "世事已黄髮，忘情付黑甜。", "從渠造物巧，未怪老夫潜。"]'),
('8da6d075-55d1-403a-9b06-9496394a395f','獨步','釋紹嵩','宋','宋诗','song-poetry','','[]','獨步時凝望，幽襟失所從。',48,'全唐诗/poet.song.213000.json','["獨步時凝望，幽襟失所從。", "煙霞橫眼界，天地醉心胸。", "澤國秋容老，人家水影重。", "行窮十里嶺，回首興何慵。"]'),
('26dde78e-62a7-4edb-a125-363e697645ab','振策','釋紹嵩','宋','宋诗','song-poetry','','[]','振策出遊眺，清吟竹影東。',48,'全唐诗/poet.song.213000.json','["振策出遊眺，清吟竹影東。", "石門千仞斷，秀水一篙通。", "郡閣煙光裏，人家秋色中。", "烏衣多勝槩，老子柰途窮。"]'),
('a10b3c6e-8994-4df3-898e-b3925fb02c55','遊雙徑','釋紹嵩','宋','宋诗','song-poetry','','[]','寶剎觸南箕，登臨獨立時。',48,'全唐诗/poet.song.213000.json','["寶剎觸南箕，登臨獨立時。", "江山如有味，花柳更無私。", "已病身猶健，言歸心尚遲。", "片雲頭上黑，真箇解催詩。"]'),
('d3d73db3-c7a5-4383-930b-0213c43a889b','戲筆','釋紹嵩','宋','宋诗','song-poetry','','[]','地僻人稀到，東郊自養蒙。',48,'全唐诗/poet.song.213000.json','["地僻人稀到，東郊自養蒙。", "山遥天接樹，夜靜竹藏風。", "岸柳含煙翠，江花脫晚紅。", "詩應是遊戲，吟嘯不須工。"]'),
('f4507399-e7a9-489f-9463-eeb02ef93d23','雨罷','釋紹嵩','宋','宋诗','song-poetry','','[]','雨罷春光潤，雲隨落日移。',48,'全唐诗/poet.song.213000.json','["雨罷春光潤，雲隨落日移。", "鶯花愁不覺，世路老方知。", "苔徧安禪石，根侵洗硯池。", "晚來風月好，倚杖獨題詩。"]'),
('0fbd9021-9c5c-4338-bdab-d08e4dda3d89','溪上','釋紹嵩','宋','宋诗','song-poetry','','[]','弄水春溪上，溪寒晚日紅。',48,'全唐诗/poet.song.213000.json','["弄水春溪上，溪寒晚日紅。", "舟行明鑑裏，鳥度醉吟中。", "遠岫千重聳，輕艘萬派通。", "桃源在何處，笑語隔幽叢。"]'),
('be309002-809e-4f1c-aa4b-7b1c84cd1e32','次韻林仲山','釋紹嵩','宋','宋诗','song-poetry','','[]','午夢蠻花濕，吟看不忍休。',48,'全唐诗/poet.song.213000.json','["午夢蠻花濕，吟看不忍休。", "白翻蕎處雪，紅壓驛邊樓。", "砌冷蟲喧座，江澄水浴秋。", "看君有知己，鈴閣想遲留。"]'),
('6ee8666c-75a3-40db-977c-b04ba40975c8','贈別法儀','釋紹嵩','宋','宋诗','song-poetry','','[]','四海欲行徧，心猿日漸馴。',48,'全唐诗/poet.song.213000.json','["四海欲行徧，心猿日漸馴。", "貧高一生行，衣故十年塵。", "如我如君者，無名無利身。", "慇懃訝此別，忍淚已霑巾。"]'),
('a129b181-01b7-49a1-a4cb-812fcef55333','山居即事  其一','釋紹嵩','宋','宋诗','song-poetry','','[]','何處成吾道，深居絕送迎。',48,'全唐诗/poet.song.213000.json','["何處成吾道，深居絕送迎。", "竹扉常晝掩，野徑得閑行。", "萬壑樹聲滿，千巖暑氣清。", "相看兩不厭，天際一山橫。"]'),
('eb52e6b8-eb5f-4f41-9497-0205bb602177','山居即事  其二','釋紹嵩','宋','宋诗','song-poetry','','[]','山色堆藍重，風煙野外嘉。',48,'全唐诗/poet.song.213000.json','["山色堆藍重，風煙野外嘉。", "與閑爲活計，祗者是生涯。", "雖有明時約，端無外物華。", "人生貴知足，此興未應賒。"]'),
('cf24ed2f-26da-444c-90e8-b4867a0b023c','山居即事  其三','釋紹嵩','宋','宋诗','song-poetry','','[]','氣味閑中好，居疑與世分。',48,'全唐诗/poet.song.213000.json','["氣味閑中好，居疑與世分。", "銷愁何用酒，娛意莫如文。", "穴暝雲初上，山高日易曛。", "近來心更靜，清絕洗妖氛。"]'),
('4cef756b-9966-495c-a034-d9c3e2d7bad0','山居即事  其四','釋紹嵩','宋','宋诗','song-poetry','','[]','獨坐空山裏，閑尋物理幽。',48,'全唐诗/poet.song.213000.json','["獨坐空山裏，閑尋物理幽。", "人情正苦暑，詩興得高秋。", "衰謝多扶病，功名安足謀。", "自嗟疎野性，肯伴白雲休。"]'),
('e9a49af2-4806-47fa-b046-59de6c2a61fd','山居即事  其五','釋紹嵩','宋','宋诗','song-poetry','','[]','老去慵仍甚，幽歡良自如。',48,'全唐诗/poet.song.213000.json','["老去慵仍甚，幽歡良自如。", "性將時共背，身與世俱疎。", "水色含群動，秋容淡夕虛。", "愜心皆樂事，真作野人居。"]'),
('773451f6-3ee7-4748-a03e-3b3f5f1e6223','山居即事  其六','釋紹嵩','宋','宋诗','song-poetry','','[]','拂石翫林壑，凜然天欲秋。',48,'全唐诗/poet.song.213000.json','["拂石翫林壑，凜然天欲秋。", "竹風連野色，舍影漾江流。", "碧嶂雲初合，遥峰雨半收。", "山居自清絕，不夢世間遊。"]'),
('073fee0c-1c8a-4f0b-916b-76b4680ac28c','山居即事  其七','釋紹嵩','宋','宋诗','song-poetry','','[]','掩戶閑欹枕，身心俱寂然。',48,'全唐诗/poet.song.213000.json','["掩戶閑欹枕，身心俱寂然。", "蹉跎已甘分，游息或談玄。", "獨得萬古意，何勞百響煎。", "功名與世事，欲問即攀緣。"]'),
('9ac68ec1-2d42-43d6-a5dd-d22b5256ea0c','山居即事  其八','釋紹嵩','宋','宋诗','song-poetry','','[]','徑轉危峰逼，徧令兩眼明。',48,'全唐诗/poet.song.213000.json','["徑轉危峰逼，徧令兩眼明。", "凉風吹詠思，幽竹送寒聲。", "砧響家家急，溪陰寸寸生。", "含情不得語，拂石記閑名。"]'),
('9c475b4e-919b-49c2-a4fa-78236e4672bf','山居即事  其九','釋紹嵩','宋','宋诗','song-poetry','','[]','病目書淫歇，熏爐炷麝煤。',48,'全唐诗/poet.song.213000.json','["病目書淫歇，熏爐炷麝煤。", "山將落日去，風带舊寒來。", "微霰疎還密，虛堂閉復開。", "無人語心事，永日坐徘徊。"]'),
('a644b410-628d-4a14-bfec-6400a110711e','山居即事  其一○','釋紹嵩','宋','宋诗','song-poetry','','[]','老罷休無頼，吟詩報答閑。',54,'全唐诗/poet.song.213000.json','["老罷休無頼，吟詩報答閑。", "圓扉長寂寂，騰口任{口顔}{口顔}。", "護塔雲偏重，棲林鳥自還。", "榮枯不經意，何用密防姦。"]'),
('056694cf-3dc4-4539-bcc3-bedf7e7ef30c','山居即事  其一一','釋紹嵩','宋','宋诗','song-poetry','','[]','獨立柴荆外，孤吟四望頻。',48,'全唐诗/poet.song.213000.json','["獨立柴荆外，孤吟四望頻。", "晴山雲罨畫，深谷鳥聲春。", "老覺文章退，閑知氣味真。", "窮居那敢恨，虛白自爲隣。"]'),
('75846b52-0418-4f14-8759-21fe2f58f79e','山居即事  其一二','釋紹嵩','宋','宋诗','song-poetry','','[]','永日翛然坐，春風苦喚行。',48,'全唐诗/poet.song.213000.json','["永日翛然坐，春風苦喚行。", "笋輿穿樹色，竹塢度鍾聲。", "雨惡天光淡，山窮地勢傾。", "苔磯清境裏，花濕轉分明。"]'),
('8fb2b7f4-3870-42c3-9016-f6c0a8b3fb72','山居即事  其一三','釋紹嵩','宋','宋诗','song-poetry','','[]','此地真奇絕，何須屋萬間。',48,'全唐诗/poet.song.213000.json','["此地真奇絕，何須屋萬間。", "穿林隣虎穴，隔水是塵寰。", "保甲元無籍，訛邪自不關。", "安閑有深味，未敢負雲山。"]'),
('ac686a18-4908-405c-a47e-5c043b61f113','山居即事  其一四','釋紹嵩','宋','宋诗','song-poetry','','[]','早晚無塵事，清心白日長。',48,'全唐诗/poet.song.213000.json','["早晚無塵事，清心白日長。", "水煙通徑草，冰玉入詩腸。", "遠嶠收殘雨，空林挂夕陽。", "此時何限興，幽鳥語如簧。"]'),
('dce3f19d-2169-4734-9a06-36122e006a33','山居即事  其一五','釋紹嵩','宋','宋诗','song-poetry','','[]','碧樹高巖底，柴門引徑斜。',48,'全唐诗/poet.song.213000.json','["碧樹高巖底，柴門引徑斜。", "采茶尋遠澗，護藥插新笆。", "澄水含斜漢，寒空散晚霞。", "寂寥無與晤，聊欲玩煙花。"]'),
('86e11362-4045-4ac5-9e4e-d2e44bd1e3d0','山居即事  其一六','釋紹嵩','宋','宋诗','song-poetry','','[]','物色催年老，誰令眼界幽。',48,'全唐诗/poet.song.213000.json','["物色催年老，誰令眼界幽。", "不憂緣不動，無意亦無求。", "寂寞了閑事，迂疎却自由。", "功名今晚矣，萍梗任飄流。"]'),
('a8c11027-538f-4c8b-bd98-0c0ad7157bb8','山居即事  其一七','釋紹嵩','宋','宋诗','song-poetry','','[]','靜境絕過從，晝門開更慵。',48,'全唐诗/poet.song.213000.json','["靜境絕過從，晝門開更慵。", "荒林失輕霧，寒日下危峰。", "曳履尋花圃，搜詩到暮鍾。", "誰言淹泊意，無酒爲澆胸。"]'),
('3af0058b-5985-496a-a939-b171380b5f73','山居即事  其一八','釋紹嵩','宋','宋诗','song-poetry','','[]','古屋茆茨小，寒林春自芳。',48,'全唐诗/poet.song.213000.json','["古屋茆茨小，寒林春自芳。", "塢深人不到，花落樹猶香。", "事去青山在，閑知白日長。", "禪心真已靜，笑失昔時狂。"]'),
('bf447989-9ce2-4e63-bc30-428a43be10db','山居即事  其一九','釋紹嵩','宋','宋诗','song-poetry','','[]','雨後江山綠，蟬聲若喚人。',48,'全唐诗/poet.song.213000.json','["雨後江山綠，蟬聲若喚人。", "巖花隨處發，官柳著行新。", "風月充三益，林泉是四鄰。", "杖藜林下去，且作自由身。"]'),
('0bc07a2e-616a-40b1-b9a4-808e78283ca6','山居即事  其二○','釋紹嵩','宋','宋诗','song-poetry','','[]','衰落暗成病，如何不白頭。',48,'全唐诗/poet.song.213000.json','["衰落暗成病，如何不白頭。", "百年長擾擾，萬事祇悠悠。", "耕鑿資餘力，行藏獨倚樓。", "却因虛淡極，忽覺此生浮。"]'),
('06805d00-7f29-40f6-93ac-742108f79c63','列岫亭書事','釋紹嵩','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','極浦遥山合翠微，週迴秀色自清機。',64,'全唐诗/poet.song.213000.json','["極浦遥山合翠微，週迴秀色自清機。", "長江淡淡吞天去，白鳥翩翩接翅飛。", "屐齒苔痕猶故跡，露沙霜樹映斜暉。", "牧童何處吹羌笛，嚇得巢禽不敢歸。"]'),
('ec9e7e0d-b89b-4db7-8e60-5587e01c2fd0','臨川道中悵然有感因作遣情','釋紹嵩','宋','宋诗','song-poetry','','[]','路傍官河一带長，風帆沙鳥認微茫。',64,'全唐诗/poet.song.213000.json','["路傍官河一带長，風帆沙鳥認微茫。", "人生行樂知能幾，世事多虞只自傷。", "破衲卷雲秋漠漠，淡煙斜日晚荒荒。", "不堪吟罷東回首，底處青山是故鄉。"]'),
('cbd79550-696e-4af9-bfd5-08a3fbf156ac','疎山途次','釋紹嵩','宋','宋诗','song-poetry','','[]','路曲山隈一徑通，天開地闢幻金宮。',64,'全唐诗/poet.song.213000.json','["路曲山隈一徑通，天開地闢幻金宮。", "溪橋裊裊穿黄落，鴈字聯聯寫碧空。", "喚客不須嫌酒惡，昔賢何必哭途窮。", "生涯淡淡隨緣過，休把行藏問化工。"]'),
('c4db82f8-6f41-433d-b5f0-73f1961435e7','遊信州僊巖','釋紹嵩','宋','宋诗','song-poetry','','[]','仙境閑尋採藥翁，笋輿乘興得蒿蓬。',64,'全唐诗/poet.song.213000.json','["仙境閑尋採藥翁，笋輿乘興得蒿蓬。", "山鍾夜度空江水，窗戶凉生薜荔風。", "斷臂青猿啼玉笥，斜行白鳥入遥空。", "舍南有竹堪書字，借筆題詩却未工。"]'),
('ced6ee90-37da-4e37-8699-4135380a982c','贈李先輩','釋紹嵩','宋','宋诗','song-poetry','','[]','饑食松花渴飲泉，寂寥芳草茂芊芊。',67,'全唐诗/poet.song.213000.json','["饑食松花渴飲泉，寂寥芳草茂芊芊。", "巖邊石室低臨水，窟裏陰雲不上天。", "難與英雄論教化，等將身世付罤{罒全}。", "無由住得吟相伴，目送歸鴻籬下眠。"]'),
('2ddd776c-f3c5-4b5e-839b-bf8b28fefc51','走筆代顔西叔次途中即事之什','釋紹嵩','宋','宋诗','song-poetry','','[]','邐迤前岡壓後岡，鳥鳴山館客思鄉。',64,'全唐诗/poet.song.213000.json','["邐迤前岡壓後岡，鳥鳴山館客思鄉。", "孤村樹色昏殘雨，滿耳蛙聲正夕陽。", "對酒已成千里客，懷人空結九回腸。", "平生憂患諳償徧，迴避紅塵是所長。"]'),
('c1e38e3e-0250-4e42-b0bb-a9b0f9b72a3e','再代和通字韻','釋紹嵩','宋','宋诗','song-poetry','','[]','驛路穿林斷復通，客程蛇繞亂山中。',64,'全唐诗/poet.song.213000.json','["驛路穿林斷復通，客程蛇繞亂山中。", "三杯軟飽千林暝，萬事從來一笑空。", "珍重故人相問意，自憐覊客尚飄蓬。", "江湖易有淹留興，已許滄浪伴釣翁。"]'),
('bd2dc111-1dfb-4fc5-bb2b-11322b93e982','贈張炳','釋紹嵩','宋','宋诗','song-poetry','','[]','怪服先生衆駭聞，賣刀買犢便耕耘。',64,'全唐诗/poet.song.213000.json','["怪服先生衆駭聞，賣刀買犢便耕耘。", "棋功過却楊玄寶，賦詠思齊鄭廣文。", "直爲篇章非動衆，忽携書劍遠辭群。", "行行快趁風煙闊，得句不妨時策勳。"]'),
('54edbfbf-b0f8-49fc-a284-35082758c229','題德夫劉公江亭','釋紹嵩','宋','宋诗','song-poetry','','[]','兄弟將知大自强，南山霧裏晦文章。',64,'全唐诗/poet.song.213000.json','["兄弟將知大自强，南山霧裏晦文章。", "睡輕可忍風敲竹，語妙何妨石作腸。", "碧瓦朱甍占肅爽，紫蘭紅藥共凄凉。", "漁舟去後天將夕，月入波心碎夜光。"]'),
('9615465c-9e37-4af6-abbb-e86e38f7e857','代和韻','釋紹嵩','宋','宋诗','song-poetry','','[]','石路無塵竹徑開，幽園尋勝獨登臺。',64,'全唐诗/poet.song.213000.json','["石路無塵竹徑開，幽園尋勝獨登臺。", "橋邊野水通漁路，城上秋山入酒盃。", "紫闥青雲俱未遂，紅顔白髮遞相催。", "悠悠蘭渚動歸思，歸思臨高不易裁。"]'),
('b168c5ee-b79b-471c-995e-9b3278d6c43b','偶成','釋紹嵩','宋','宋诗','song-poetry','','[]','誰復知予懶是真，平生自信解甘貧。',64,'全唐诗/poet.song.213000.json','["誰復知予懶是真，平生自信解甘貧。", "苦無名位高今世，爲有煙霞伴此身。", "長掩柴荆避寒暑，猶將談笑對風塵。", "只今那得王摩詰，狀取江湖太古民。"]'),
('2cc8d487-6fd0-44a7-8281-b952377aae68','南山書懷','釋紹嵩','宋','宋诗','song-poetry','','[]','日色今朝分外明，湖光浩氣共澄清。',64,'全唐诗/poet.song.213000.json','["日色今朝分外明，湖光浩氣共澄清。", "鳥啼綠樹穿花影，水泛青山入古城。", "眼下見榮還見辱，病中嫌雨又嫌晴。", "衰遲自喜添詩學，三十年來掉臂行。"]'),
('27aea93b-65e6-415c-b310-b2719baf42ab','西湖晚步偶成呈曾君舉司戶','釋紹嵩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','山引千巖翠作堆，鍾鳴樓閣晚雲開。',64,'全唐诗/poet.song.213000.json','["山引千巖翠作堆，鍾鳴樓閣晚雲開。", "魚吹鑑面暈痕蹙，人過橋心倒影來。", "要聽劇談飛木屑，便期携手上春臺。", "世間剛有東流水，一洗從前猿鶴哀。"]'),
('dd2ae945-cf44-4fc5-af6e-4a4b0b619526','贈郎德父','釋紹嵩','宋','宋诗','song-poetry','','[]','衣弊履穿不諱窮，籬門和竹夾西東。',64,'全唐诗/poet.song.213000.json','["衣弊履穿不諱窮，籬門和竹夾西東。", "閑棲已合稱高士，發興真成繼庾公。", "人世鶴歸雙鬢上，丹霄路在五言中。", "却須袖取經綸手，深入蘆花作釣翁。"]'),
('b3134d0e-1aaf-4f2f-a6e8-97ba692a0c86','酬胡聖聞','釋紹嵩','宋','宋诗','song-poetry','','[]','別後滄波路幾迷，竹風松雨共凄凄。',64,'全唐诗/poet.song.213000.json','["別後滄波路幾迷，竹風松雨共凄凄。", "十年依舊雙瞳碧，四海仍傳一角犀。", "池上溶溶浮日暖，山中物物是詩題。", "先生莫道心如鐵，可忍紅英半著泥。"]'),
('50b827dc-d528-4e4f-a08f-808c3582e1e9','紹興即事','釋紹嵩','宋','宋诗','song-poetry','','[]','柳色葱葱官渡平，梨花吹雪度清明。',64,'全唐诗/poet.song.213000.json','["柳色葱葱官渡平，梨花吹雪度清明。", "山從海岸裝吟景，寺倚雲峰更晚晴。", "潮水忽生添野水，春城何忍作空城。", "黄鶯久住渾相識，故作林間求友聲。"]'),
('2b463fe1-abc8-43cd-884c-4fc77c978bf6','蘭亭書事','釋紹嵩','宋','宋诗','song-poetry','','[]','蒼岸古木靄煙蘿，風俗猶聞晉永和。',64,'全唐诗/poet.song.213000.json','["蒼岸古木靄煙蘿，風俗猶聞晉永和。", "綠樹碧簷相掩映，青鞋黄帽飽經過。", "還緣世遇兵戈閙，頗覺閑消日月多。", "盤礴幽窗覓詩處，月明天色白連河。"]'),
('af5b85cf-990f-43cd-aab8-b8a2e7c277df','代次登城之什','釋紹嵩','宋','宋诗','song-poetry','','[]','上得孤城向晚春，其如衰病只傷神。',64,'全唐诗/poet.song.213000.json','["上得孤城向晚春，其如衰病只傷神。", "鼠肝蟲臂窺前輩，虹旆星車委後塵。", "兩鬢已霜難諱老，一機何處定非真。", "愁來只有賢從事，千里相逢如故人。"]'),
('c49ccc0a-19b0-498f-a36f-807eca6ac1ee','慶元道中','釋紹嵩','宋','宋诗','song-poetry','','[]','臨溪柳带正依依，落絮因風特地飛。',64,'全唐诗/poet.song.213000.json','["臨溪柳带正依依，落絮因風特地飛。", "島上斷雲垂極浦，城頭初角送殘暉。", "閑過綺陌尋高寺，謾遶清流欲浣衣。", "重到張公泊船處，家家扶得醉人歸。"]'),
('73939a83-cfcf-4fb6-9269-00a4541ecd0e','留題江亭','釋紹嵩','宋','宋诗','song-poetry','','[]','晚凉閑步向江亭，山色偏於晚有情。',64,'全唐诗/poet.song.213000.json','["晚凉閑步向江亭，山色偏於晚有情。", "綵索平時牆婉娩，飛花滿眼句縱橫。", "五峰遥拱千巖秀，四水縈紆十里程。", "鵲噪鴉啼俱喜色，望中渾恐是蓬瀛。"]'),
('12dc1f2a-59d4-4d83-a3aa-cf6a1fb8137e','答仲寬','釋紹嵩','宋','宋诗','song-poetry','','[]','强半年光屬苦辛，生涯如在舊山貧。',64,'全唐诗/poet.song.213000.json','["强半年光屬苦辛，生涯如在舊山貧。", "江南江北閑爲客，人去人來恨轉新。", "節裏且追千載事，胸中別作一家春。", "明年此會知誰健，不問蒼生問鬼神。"]'),
('67dbfd2f-25dd-4f06-af1c-496ebb05f9af','和蔣自然','釋紹嵩','宋','宋诗','song-poetry','','[]','歲月悠悠一夢中，榮枯消得幾何功。',64,'全唐诗/poet.song.213000.json','["歲月悠悠一夢中，榮枯消得幾何功。", "寧爲宇宙閑吟客，豈是江湖把釣翁。", "山口斷雲憐舊路，沙邊微雨濕孤蓬。", "飯餘鼓腹聊行樂，立盡疎簾落絮風。"]'),
('493099e0-e931-44c0-b256-6a0e90f3265a','重經故人舊居','釋紹嵩','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','五字研成舉世傳，醉吟朝夕在樊川。',64,'全唐诗/poet.song.213000.json','["五字研成舉世傳，醉吟朝夕在樊川。", "江南海北三千里，雨散雲飛二十年。", "壁上塵黏蒲葉扇，鏡中人入洞庭煙。", "倦遊客子心無際，遐想星軺思惘然。"]');
